-- Poems batch 10
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('7874e72a-34c7-4fb4-9564-0005c67bb596','塞下曲 一','李益','唐','唐诗','tang','','["\u9ec4\u6cb3", "\u5c06\u58eb", "\u751f\u6d3b", "\u5199\u666f", "\u8fb9\u585e"]','蕃州部落能結束，朝暮馳獵黃河曲。',32,'全唐诗/poet.tang.15000.json','["蕃州部落能結束，朝暮馳獵黃河曲。", "燕歌未斷塞鴻飛，牧馬羣嘶邊草綠。"]'),
('29fbdce1-7be4-40c6-8653-8dbe6009ce49','塞下曲 二','李益','唐','唐诗','tang','','[]','秦築長城城已摧，漢武北上單于臺。',32,'全唐诗/poet.tang.15000.json','["秦築長城城已摧，漢武北上單于臺。", "古來征戰虜不盡，今日還復天兵來。"]'),
('b7c28260-45f1-466e-b5fb-901240b9bee5','塞下曲 三','李益','唐','唐诗','tang','','["\u9ec4\u6cb3"]','黃河東流流九折，沙場埋恨何時絕。',32,'全唐诗/poet.tang.15000.json','["黃河東流流九折，沙場埋恨何時絕。", "蔡琰沒去造胡笳，蘇武歸來持漢節。"]'),
('04b1e32a-44da-4530-b953-2db87e4c9d5e','塞下曲 四','李益','唐','唐诗','tang','','[]','爲報如今都護雄，匈奴且莫下雲中。',32,'全唐诗/poet.tang.15000.json','["爲報如今都護雄，匈奴且莫下雲中。", "請書塞北陰山石，願比燕然車騎功。"]'),
('6a1a1f44-9ea2-45a8-876a-57a374479897','夜上西城聽梁州曲二首 一','李益','唐','唐诗','tang','','[]','行人夜上西城宿，聽唱梁州雙筦逐。',32,'全唐诗/poet.tang.15000.json','["行人夜上西城宿，聽唱梁州雙筦逐。", "此時秋月滿關山，何處關山無此曲。"]'),
('1c4586db-d898-4587-96fa-3a41883587b3','夜上西城聽梁州曲二首 二','李益','唐','唐诗','tang','','[]','鴻雁新從北地來，聞聲一半却飛回。',32,'全唐诗/poet.tang.15000.json','["鴻雁新從北地來，聞聲一半却飛回。", "金河戍客腸應斷，更在秋風百尺臺。"]'),
('7315d4f1-4a61-43f8-ad46-6477d8dd50e1','暖川','李益','唐','唐诗','tang','','[]','胡風凍合鸊鵜泉，牧馬千羣逐暖川。',32,'全唐诗/poet.tang.15000.json','["胡風凍合鸊鵜泉，牧馬千羣逐暖川。", "塞外征行無盡日，年年移帳雪中天。"]'),
('9444dea4-3ec6-4ba6-b571-d569e203670e','過馬嵬','李益','唐','唐诗','tang','','[]','漢將如雲不直言，寇來翻罪綺羅恩。',32,'全唐诗/poet.tang.15000.json','["漢將如雲不直言，寇來翻罪綺羅恩。", "託君休洗蓮花血，留記千年妾淚痕。"]'),
('299a6ee7-7b3b-4ae4-9ea7-bdd82d956c9e','答許五端公馬上口號','李益','唐','唐诗','tang','','[]','晚逐旌旗俱白首，少遊京洛共緇塵。',32,'全唐诗/poet.tang.15000.json','["晚逐旌旗俱白首，少遊京洛共緇塵。", "不堪身外悲前事，強向杯中覓舊春。"]'),
('a62bde81-05f7-447b-b605-de65e96056e6','牡丹','李益','唐','唐诗','tang','','[]','紫蕊叢開未到家，却教遊客賞繁華。',32,'全唐诗/poet.tang.15000.json','["紫蕊叢開未到家，却教遊客賞繁華。", "始知年少求名處，滿眼空中別有花。"]'),
('64d63850-8805-4c14-8f2a-843fc441ec0a','邊思','李益','唐','唐诗','tang','','["\u8fb9\u585e"]','腰懸錦帶佩吳鉤，走馬曾防玉塞秋。',32,'全唐诗/poet.tang.15000.json','["腰懸錦帶佩吳鉤，走馬曾防玉塞秋。", "莫笑關西將家子，秪將詩思入涼州。"]'),
('663ad068-30f8-4b38-816c-eecead23bc7e','奉和武相公春曉聞鶯','李益','唐','唐诗','tang','','[]','蜀道山川心易驚，緣窗殘夢曉聞鶯。',32,'全唐诗/poet.tang.15000.json','["蜀道山川心易驚，緣窗殘夢曉聞鶯。", "分明似寫文君恨，萬怨千愁弦上聲。"]'),
('c5f09de1-23c6-4900-8cfc-c9086e07ae5f','送客還幽州','李益','唐','唐诗','tang','','[]','惆悵秦城送獨歸，薊門雲樹遠依依。',32,'全唐诗/poet.tang.15000.json','["惆悵秦城送獨歸，薊門雲樹遠依依。", "秋來莫射南飛雁，從遣乘春更北飛。"]'),
('f07da970-0a2f-4b34-a09f-ff47b6830769','柳楊送客','李益','唐','唐诗','tang','','[]','青楓江畔白蘋洲，楚客傷離不待秋。',32,'全唐诗/poet.tang.15000.json','["青楓江畔白蘋洲，楚客傷離不待秋。", "君見隋朝更何事，柳楊南渡水悠悠。"]'),
('bd1d28af-6231-4446-9d6a-fb76840dde90','從軍北征','李益','唐','唐诗','tang','','["\u6218\u4e89", "\u601d\u4e61", "\u8fb9\u585e", "\u65e0\u5948", "\u60b2\u51c9"]','天山雪後海風寒，橫笛偏吹行路難。',32,'全唐诗/poet.tang.15000.json','["天山雪後海風寒，橫笛偏吹行路難。", "磧裏征人三十萬，一時回向月明看。"]'),
('426eea46-266e-472d-8fe4-a558b28d18f9','聽曉角','李益','唐','唐诗','tang','','["\u5199\u666f", "\u51c4\u51c9", "\u8427\u745f", "\u79cb\u5929", "\u8fb9\u585e"]','邊霜昨夜墮關榆，吹角當城漢月孤。',32,'全唐诗/poet.tang.15000.json','["邊霜昨夜墮關榆，吹角當城漢月孤。", "無限塞鴻飛不度，秋風卷入小單于。"]'),
('3ba7240c-f2c7-47b2-aab4-df61036655ca','宮怨','李益','唐','唐诗','tang','','["\u95fa\u6028"]','露溼晴花春殿香，月明歌吹在昭陽。',32,'全唐诗/poet.tang.15000.json','["露溼晴花春殿香，月明歌吹在昭陽。", "似將海水添宮漏，共滴長門一夜長。"]'),
('9d52cf95-a86a-4041-831f-3c16d568ccde','暮過回樂烽','李益','唐','唐诗','tang','','[]','烽火高飛百尺臺，黃昏遙自磧西來。',32,'全唐诗/poet.tang.15000.json','["烽火高飛百尺臺，黃昏遙自磧西來。", "昔時征戰回應樂，今日從軍樂未回。"]'),
('ef71c49c-0e5f-421e-b8da-f2a64606930e','奉和武相公郊居寓目','李益','唐','唐诗','tang','','[]','黃扉晚下禁垣鐘，歸坐南闈山萬重。',32,'全唐诗/poet.tang.15000.json','["黃扉晚下禁垣鐘，歸坐南闈山萬重。", "獨有月中高興盡，雪峯明處見寒松。"]'),
('9a26bdee-c60a-47d7-8a6d-1d9d51783899','詣紅樓院尋廣宣不遇留題','李益','唐','唐诗','tang','','[]','柿葉翻紅霜景秋，碧天如水倚紅樓。',32,'全唐诗/poet.tang.15000.json','["柿葉翻紅霜景秋，碧天如水倚紅樓。", "隔窗愛竹無人問，遣向鄰房覓戶鉤。"]'),
('a841cfca-0ac2-4271-9ff0-34f87e837bbe','回軍行','李益','唐','唐诗','tang','','[]','關城榆葉早疎黃，日暮沙雲古戰場。',32,'全唐诗/poet.tang.15000.json','["關城榆葉早疎黃，日暮沙雲古戰場。", "表請回軍掩塵骨，莫教士卒哭龍荒。"]'),
('3a692edc-d3bd-4be8-8142-42e9d058030c','邠寧春日','李益','唐','唐诗','tang','','[]','桃李年年上國新，風沙日日塞垣人。',32,'全唐诗/poet.tang.15000.json','["桃李年年上國新，風沙日日塞垣人。", "傷心更見庭前柳，忽有千條欲占春。"]'),
('699800d5-6ce3-4f34-8f68-78b6c32f7202','古瑟怨','李益','唐','唐诗','tang','','[]','破瑟悲秋已減弦，湘靈沈怨不知年。',32,'全唐诗/poet.tang.15000.json','["破瑟悲秋已減弦，湘靈沈怨不知年。", "感君拂拭遺音在，更奏新聲明月天。"]'),
('f68fbbd0-6729-40b1-8707-b8349dd44177','夜宴觀石將軍舞','李益','唐','唐诗','tang','','[]','微月東南上戍樓，琵琶起舞錦纏頭。',32,'全唐诗/poet.tang.15000.json','["微月東南上戍樓，琵琶起舞錦纏頭。", "更聞橫笛關山遠，白草胡沙西塞秋。"]'),
('590153bb-2f4d-419d-84ac-c4b9cb785a48','春夜聞笛','李益','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','寒山吹笛喚春歸，遷客相看淚滿衣。',32,'全唐诗/poet.tang.15000.json','["寒山吹笛喚春歸，遷客相看淚滿衣。", "洞庭一夜無窮雁，不待天明盡北飛。"]'),
('6795f7bd-7a8b-452c-9c2a-ccf693710c85','揚州送客','李益','唐','唐诗','tang','','[]','南行直入鷓鴣羣，萬歲橋邊一送君。',32,'全唐诗/poet.tang.15000.json','["南行直入鷓鴣羣，萬歲橋邊一送君。", "聞道望鄉聞不得，梅花暗落嶺頭雲。"]'),
('772f7f55-f920-4217-9024-4b5232e96d57','統漢峰下','李益','唐','唐诗','tang','','["\u9ec4\u6cb3"]','統漢峰西降戶營，黃河戰骨擁長城。',32,'全唐诗/poet.tang.15000.json','["統漢峰西降戶營，黃河戰骨擁長城。", "只今已勒燕然石，北地無人空月明。"]'),
('d83981b3-b9e0-4b94-9e63-a6392929acd6','避暑女冠','李益','唐','唐诗','tang','','[]','霧袖煙裾雲母冠，碧琉璃簟井冰寒。',32,'全唐诗/poet.tang.15000.json','["霧袖煙裾雲母冠，碧琉璃簟井冰寒。", "焚香欲使三清鳥，靜拂桐陰上玉壇。"]'),
('fa3c1357-9b8c-4d13-aa5e-067758de57d0','行舟','李益','唐','唐诗','tang','','[]','柳花飛入正行舟，臥引菱花信碧流。',32,'全唐诗/poet.tang.15000.json','["柳花飛入正行舟，臥引菱花信碧流。", "聞道風光滿揚子，天晴共上望鄉樓。"]'),
('cfc5525c-1c63-4f1f-ac67-6aed44885d6e','隋宮燕','李益','唐','唐诗','tang','','["\u540a\u53e4\u4f24\u4eca", "\u5199\u9e1f", "\u9e1f"]','燕語如傷舊國春，宮花一落已成塵。',32,'全唐诗/poet.tang.15000.json','["燕語如傷舊國春，宮花一落已成塵。", "自從一閉風光後，幾度飛來不見人。"]'),
('48684889-1cbd-4b19-9768-be3c6b22d97e','送人歸岳陽','李益','唐','唐诗','tang','','[]','煙草連天楓樹齊，岳陽歸路子規啼。',32,'全唐诗/poet.tang.15000.json','["煙草連天楓樹齊，岳陽歸路子規啼。", "春江萬里巴陵戍，落日看沈碧水西。"]'),
('73b9a9a6-8fcf-47bf-a8f2-f4aaf3a1419a','上汝州郡樓','李益','唐','唐诗','tang','','[]','黃昏鼓角似邊州，三十年前上此樓。',32,'全唐诗/poet.tang.15000.json','["黃昏鼓角似邊州，三十年前上此樓。", "今日山城對垂淚，傷心不獨爲悲秋。"]'),
('8806295e-05bb-40d8-9776-e4eaeee89d1a','臨滹沱見蕃使列名','李益','唐','唐诗','tang','','[]','漠南春色到滹沱，碧柳青青塞馬多。',32,'全唐诗/poet.tang.15000.json','["漠南春色到滹沱，碧柳青青塞馬多。", "萬里關山今不閉，漢家頻許郅支和。"]'),
('1cb66aa8-e665-40b5-af59-253d8592f137','寫情','李益','唐','唐诗','tang','','["\u5931\u604b", "\u7231\u60c5"]','水紋珍簟思悠悠，千里佳期一夕休。',32,'全唐诗/poet.tang.15000.json','["水紋珍簟思悠悠，千里佳期一夕休。", "從此無心愛良夜，任他明月下西樓。"]'),
('992df222-c445-4925-a656-0caa4447d5bb','夜上受降城聞笛','李益','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u601d\u5ff5", "\u6218\u4e89", "\u51ac\u5929", "\u8fb9\u585e", "\u4e03\u8a00\u7edd\u53e5"]','回樂峰前沙似雪，受降城下月如霜。',32,'全唐诗/poet.tang.15000.json','["回樂峰前沙似雪，受降城下月如霜。", "不知何處吹蘆管，一夜征人盡望鄉。"]'),
('f0b13311-ab59-4dc6-86e7-d201003dd201','赴渭北宿石泉驛南望黃堆烽','李益','唐','唐诗','tang','','[]','邊城已在虜城中，烽火南飛入漢宮。',32,'全唐诗/poet.tang.15000.json','["邊城已在虜城中，烽火南飛入漢宮。", "漢庭議事先黃老，麟閣何人定戰功。"]'),
('ed7f860f-572b-468f-a70a-d6b233f0cbc6','逢歸信偶寄','李益','唐','唐诗','tang','','[]','無事將心寄柳條，等閑書字滿芭蕉。',32,'全唐诗/poet.tang.15000.json','["無事將心寄柳條，等閑書字滿芭蕉。", "鄉關若有東流信，遣送揚州近驛橋。"]'),
('ace9546f-5d4e-42ac-8f07-d4707030f7a4','贈毛仙翁','李益','唐','唐诗','tang','','[]','玉樹溶溶仙氣深，含光混俗似無心。',32,'全唐诗/poet.tang.15000.json','["玉樹溶溶仙氣深，含光混俗似無心。", "長愁忽作鶴飛去，一片孤雲何處尋。"]'),
('7ce1049a-e49a-4c44-8092-8147c5b8efb3','長干行','李益','唐','唐诗','tang','','[]','憶妾深閨裏，煙塵不曾識。',144,'全唐诗/poet.tang.15000.json','["憶妾深閨裏，煙塵不曾識。", "嫁與長干人，沙頭候風色。", "五月南風興，思君下巴陵。", "八月西風起，想君發揚子。", "去來悲如何，見少離別多。", "湘潭幾日到，妾夢越風波。", "昨夜狂風度，吹折江頭樹。", "渺渺暗無邊，行人在何處。", "好乘浮雲驄，佳期蘭渚東。", "鴛鴦綠浦上，翡翠錦屏中。", "自憐十五餘，顏色桃花紅。", "那作商人婦，愁水復愁風。"]'),
('44376f7d-a0d4-415d-a846-ec6da52ba651','和丘員外題湛長史舊居','李益','唐','唐诗','tang','','[]','昔降英王顧。',72,'全唐诗/poet.tang.15000.json','["昔降英王顧。", "屏身幽巖曲，靈波結繁笳。", "爽籟赴鳴玉，運轉春華至。", "歲來山草綠，青松掩落暉。", "白雲竟空谷，伊人撫遺歎。", "惻惻芳又縟，云誰斅美香。", "分毫寄明牧。"]'),
('2e0cd4ce-4297-420f-a4bf-92e48b38e5d2','送客歸振武','李益','唐','唐诗','tang','','[]','駿馬事輕車，軍行萬里沙。',48,'全唐诗/poet.tang.15000.json','["駿馬事輕車，軍行萬里沙。", "胡山通嗢落，漢節繞渾邪。", "桂滿天西月，蘆吹塞北笳。", "別離俱報主，路極不爲賒。"]'),
('7456cfc7-afe2-4f55-a95a-b6868ab10533','府試古鏡','李益','唐','唐诗','tang','','[]','舊是秦時鏡，今藏古匣中。',72,'全唐诗/poet.tang.15000.json','["舊是秦時鏡，今藏古匣中。", "龍盤初挂月，鳳舞欲生風。", "石黛曾留殿，朱光適在宮。", "應祥知道泰，鑑物覺神通。", "肝膽誠難隱，妍媸信易窮。", "幸居君子室，長願免塵蒙。"]'),
('5a937bf2-db04-4f01-8af7-4d0ea02c9657','贈宣大師','李益','唐','唐诗','tang','','[]','一國沙彌獨解詩，人人道勝惠林師。',64,'全唐诗/poet.tang.15000.json','["一國沙彌獨解詩，人人道勝惠林師。", "先皇詔下徵還日，今上龍飛入內時。", "看月憶來松寺宿，尋花思作杏溪期。", "因論佛地求心地，秪說常吟是住持。"]'),
('03aceab2-1bbe-4c0f-850b-b98d3760e35a','漢宮詞','李益','唐','唐诗','tang','','[]','漢室長陵小市東，珠簾繡戶對春風。',32,'全唐诗/poet.tang.15000.json','["漢室長陵小市東，珠簾繡戶對春風。", "君王昨日移仙仗，玉輦將迎入漢中。"]'),
('3b28eace-a2e8-4627-a7ef-02e3b901be8f','江南曲','李益','唐','唐诗','tang','','[]','長樂花枝雨點銷，江城日暮好相邀。',32,'全唐诗/poet.tang.15000.json','["長樂花枝雨點銷，江城日暮好相邀。", "春樓不閉葳蕤鎖，綠水回連宛轉橋。"]'),
('5d171072-47a3-4daf-ba8f-202d4c47ce49','宿石邑山中','李益','唐','唐诗','tang','','["\u5199\u5c71", "\u5199\u666f", "\u63cf\u5199\u5c71"]','浮雲不共此山齊，山靄蒼蒼望轉迷。',32,'全唐诗/poet.tang.15000.json','["浮雲不共此山齊，山靄蒼蒼望轉迷。", "曉月暫飛高樹裏，秋河隔在數峯西。"]'),
('cc1bf6ee-a6d6-4018-a194-1d6e084d36ab','寄贈衡州楊使君','李益','唐','唐诗','tang','','[]','湘竹斑斑湘水春，衡陽太守虎符新。',32,'全唐诗/poet.tang.15000.json','["湘竹斑斑湘水春，衡陽太守虎符新。", "朝來笑向歸鴻道，早晚南飛見主人。"]'),
('e8d49e76-fc92-40cb-81cb-458828cdaf8d','途中寄李二','李益','唐','唐诗','tang','','[]','楊柳含煙灞岸春，年年攀折爲行人。',32,'全唐诗/poet.tang.15000.json','["楊柳含煙灞岸春，年年攀折爲行人。", "好風若借低枝便，莫遣青絲掃路塵。"]'),
('b12f0f8a-a36e-446d-9607-e30772d52730','寄許鍊師','李益','唐','唐诗','tang','','[]','掃石焚香禮碧空，露華偏溼蕊珠宮。',32,'全唐诗/poet.tang.15000.json','["掃石焚香禮碧空，露華偏溼蕊珠宮。", "如何說得天壇上，萬里無雲月在中。"]'),
('a3f3a8b5-83d2-4e36-a1c1-20d6d1a0d465','失題','李益','唐','唐诗','tang','','[]','世故相逢各未閑，百年多在別離間。',32,'全唐诗/poet.tang.15000.json','["世故相逢各未閑，百年多在別離間。", "昨夜秋風今夜雨，不知何處入空山。"]'),
('60adfcbb-87e0-4a68-851c-bb92ccc2f05a','塞下曲','李益','唐','唐诗','tang','','["\u5199\u4eba", "\u8fb9\u585e", "\u58ee\u5fd7"]','伏波惟願裹尸還，定遠何須生入關。',32,'全唐诗/poet.tang.15000.json','["伏波惟願裹尸還，定遠何須生入關。", "莫遣隻輪歸海窟，仍留一箭射天山。"]'),
('c3a17902-eb44-4244-9cd8-d60a4ac55f82','上黃堆烽','李益','唐','唐诗','tang','','[]','心期紫閣山中月，身過黃堆烽上雲。',32,'全唐诗/poet.tang.15000.json','["心期紫閣山中月，身過黃堆烽上雲。", "年髮已從書劒老，戎衣更逐霍將軍。"]'),
('37ab7b24-b25e-4492-88de-16a5eb4c2008','句','李益','唐','唐诗','tang','','[]','閑庭草色能留馬，當路楊花不避人。',16,'全唐诗/poet.tang.15000.json','["閑庭草色能留馬，當路楊花不避人。"]'),
('ff6d2d68-17c4-4204-8d54-0203177c730b','古別離二首 一','李端','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','水國葉黃時，洞庭霜落夜。',96,'全唐诗/poet.tang.15000.json','["水國葉黃時，洞庭霜落夜。", "行舟聞商估，宿在楓林下。", "此地送君還，茫茫似夢間。", "後期知幾日，前路轉多山。", "巫峽通湘浦，迢迢隔雲雨。", "天晴見海檣，月落聞津鼓。", "人老自多愁，水深難急流。", "清宵歌一曲，白首對汀洲。"]'),
('3c3ab4a7-a3d1-46bc-a942-1bb035d0e86b','古別離二首 二','李端','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','與君桂陽別，令君岳陽待。',131,'全唐诗/poet.tang.15000.json','["與君桂陽別，令君岳陽待。", "後事忽差池，前期日空在。", "木落雁嗷嗷，洞庭波浪高。", "遠山雲似蓋，極浦樹如毫。", "朝發能幾里，暮來風又起。", "如何兩處愁，皆在孤舟裏。", "昨夜天月明，長川寒且清。", "菊花開欲盡，薺菜泊來生。", "下江帆勢速，五兩遙相逐。", "欲問去時人，知投何處宿。", "空令猿嘯時泣對湘簟竹。"]'),
('61194804-f2d2-41bc-a43e-a774f80f26dd','折楊柳','李端','唐','唐诗','tang','','[]','東城攀柳葉，柳葉低着草。',120,'全唐诗/poet.tang.15000.json','["東城攀柳葉，柳葉低着草。", "少壯莫輕年，輕年有衰老。", "柳發遍川岡，登高堪斷腸。", "雨煙輕漠漠，何樹近君鄉。", "贈君折楊柳，顏色豈能久。", "上客莫沾巾，佳人正回首。", "新柳送君行，古柳傷君情。", "突兀臨荒渡，婆娑出舊營。", "隋家兩岸盡，陶宅五株榮。", "日暮偏愁望，春山有鳥聲。"]'),
('d528ff85-134d-4d1d-86ba-e6053487bd8a','留別柳中庸','李端','唐','唐诗','tang','','[]','惆悵流水時，蕭條背城路。',36,'全唐诗/poet.tang.15000.json','["惆悵流水時，蕭條背城路。", "離人出古亭，嘶馬入寒樹。", "江海正風波，相逢在何處。"]'),
('553ab62d-c697-480c-96a3-c9f93da53fc1','野亭三韻送錢員外','李端','唐','唐诗','tang','','[]','野菊開欲稀，寒泉流漸淺。',36,'全唐诗/poet.tang.15000.json','["野菊開欲稀，寒泉流漸淺。", "幽人步林後，歎此年華晚。", "倚杖送行雲，尋思故山遠。"]'),
('96851a23-f8c1-49ea-8e6b-1d7063b8d0ad','歸山招王逵','李端','唐','唐诗','tang','','[]','日長原野靜，杖策步幽巘。',48,'全唐诗/poet.tang.15000.json','["日長原野靜，杖策步幽巘。", "雉雊麥苗陰，蝶飛溪草晚。", "我生好閒放，此去殊未返。", "自是君不來，非關故山遠。"]'),
('9fa9dfb2-4e4a-4c51-bd1f-bb28049777d9','過谷口元贊善所居','李端','唐','唐诗','tang','','[]','入谷訪君來，秋泉已堪涉。',48,'全唐诗/poet.tang.15000.json','["入谷訪君來，秋泉已堪涉。", "林間人獨坐，月下山相接。", "重露濕蒼苔，明燈照黃葉。", "故交一不見，素髮何稠疊。"]'),
('0b829019-582f-4b44-8e25-f6ef247fcb6b','旅次岐山得山友書却寄鳳翔張尹','李端','唐','唐诗','tang','','[]','本與戴徵君，同師竹上坐。',36,'全唐诗/poet.tang.15000.json','["本與戴徵君，同師竹上坐。", "偶爲名利引，久廢論真果。", "昨日山信迴，寄書來責我。"]'),
('169db1f4-0f3e-49d4-b6a7-ac3d6ddea9ed','九日贈司空文明','李端','唐','唐诗','tang','','[]','我有惆悵詞，待君醉時說。',36,'全唐诗/poet.tang.15000.json','["我有惆悵詞，待君醉時說。", "長來逢九日，難與菊花別。", "摘却正開花，暫言花未發。"]'),
('1187b7da-e4e4-4d63-800b-3e6e9d99d57e','蕪城','李端','唐','唐诗','tang','','[]','昔人登此地，丘隴已前悲。',48,'全唐诗/poet.tang.15000.json','["昔人登此地，丘隴已前悲。", "今日又非昔，春風能幾時。", "風吹城上樹，草沒城邊路。", "城裏月明時，精靈自來去。"]'),
('dde00080-96a2-45aa-a780-f19ced0019c5','送吉中孚拜官歸楚州','李端','唐','唐诗','tang','','[]','才子神骨清，虛竦眉眼明。',228,'全唐诗/poet.tang.15000.json','["才子神骨清，虛竦眉眼明。", "貌應同衞玠，鬢且異潘生。", "初戴莓苔幘，來過丞相宅。", "滿堂歸道師，衆口宗詩伯。", "須臾里巷傳，天子亦知賢。", "出詔升高士，馳聲在少年。", "自爲才哲愛，日與侯王會。", "匡主一言中，榮親千里外。", "更聞仙士友，往往東回首。", "驅石不成羊，指丹空斃狗。", "孤帆淮上歸，商估夜相依。", "海霧寒將盡，天星曉欲稀。", "潮頭來始歇，浦口喧爭發。", "鄉樹尚和雲，鄰船猶帶月。", "到洞必傷情，巡房見舊名。", "醮疎壇路澀，汲少井欄傾。", "別我長安道，前期共須老。", "方隨水向山，肯惜花辭島。", "悵望執君衣，今朝風景好。"]'),
('26a9c152-dc44-4c44-a610-c84ca4d1d2e3','荆州泊','李端','唐','唐诗','tang','','[]','南樓西下時，月裏聞來棹。',48,'全唐诗/poet.tang.15000.json','["南樓西下時，月裏聞來棹。", "桂水舳艫迴，荆州津濟鬧。", "移帷望星漢，引帶思容貌。", "今夜一江人，唯應妾身覺。"]'),
('2859c7f7-5ebd-4ed0-8b4a-2d8212dbcc14','春遊樂','李端','唐','唐诗','tang','','[]','遊童蘇合彈，倡女蒲葵扇。',48,'全唐诗/poet.tang.15000.json','["遊童蘇合彈，倡女蒲葵扇。", "初日映城時，相思忽相見。", "褰裳蹋路草，理鬢回花面。", "薄暮不同歸，留情此芳甸。"]'),
('de1797c7-0c10-4d76-aac3-68dbfbf82b77','千里思','李端','唐','唐诗','tang','','[]','涼州風月美，遙望居延路。',48,'全唐诗/poet.tang.15000.json','["涼州風月美，遙望居延路。", "汎汎下天雲，青青緣塞樹。", "燕山蘇武上，海島田橫住。", "更是草生時，行人出門去。"]'),
('5b2a69d8-3a60-4fea-b23b-eb83f81622f6','白鷺詠','李端','唐','唐诗','tang','','[]','迥起來應近，高飛去自遙。',36,'全唐诗/poet.tang.15000.json','["迥起來應近，高飛去自遙。", "映林同落雪，拂水狀飜潮。", "猶有幽人興，相逢到碧霄。"]'),
('19a7e803-e3b8-4ebe-9dc1-2869c23122e9','冬夜與故友聚送吉校書','李端','唐','唐诗','tang','','[]','途窮別則怨，何必天涯去。',84,'全唐诗/poet.tang.15000.json','["途窮別則怨，何必天涯去。", "共作出門人，不見歸鄉路。", "殷勤執杯酒，悵望送親故。", "月色入閒軒，風聲落高樹。", "雲霄望且遠，齒髮行應暮。", "九日泣黃花，三秋悲白露。", "君行過洛陽，莫向青山度。"]'),
('314d0c08-7c56-47a8-bc40-f48ef0742396','與苗員外山行','李端','唐','唐诗','tang','','[]','古人留路去，今日共君行。',36,'全唐诗/poet.tang.15000.json','["古人留路去，今日共君行。", "若待青山盡，應逢白髮生。", "誰知到蘭若，流落一書名。"]'),
('5e8854d8-650e-4e80-b95a-6a40679681cd','早春同庾侍郎題青龍上方院','李端','唐','唐诗','tang','','[]','相見惜餘輝，齊行登古寺。',36,'全唐诗/poet.tang.15000.json','["相見惜餘輝，齊行登古寺。", "風煙結遠恨，山水含芳意。", "車馬莫前歸，留看巢鶴至。"]'),
('c98956e6-9415-4374-bfca-925ca2b91243','送從叔赴洪州','李端','唐','唐诗','tang','','[]','榮家兼佐幕，叔父似還鄉。',48,'全唐诗/poet.tang.15000.json','["榮家兼佐幕，叔父似還鄉。", "王粲名雖重，郄超髯未長。", "鳴橈過夏口，斂笏見潯陽。", "後夜相思處，中庭月一方。"]'),
('da45d665-c7b9-4403-b2f8-e2c30bfbd188','送路司諫侍從叔赴洪州','李端','唐','唐诗','tang','','[]','郄超本絕倫，得意在芳春。',168,'全唐诗/poet.tang.15000.json','["郄超本絕倫，得意在芳春。", "勳業耿家盛，風流荀氏均。", "聲名金作賦，白皙玉爲身。", "斂笏辭天子，乘龜從丈人。", "度關行且獵，鞍馬何躞蹀。", "猿嘯暮應愁，湖流春好涉。", "潯陽水分送，于越山相接。", "梅雨細如絲，蒲帆輕似葉。", "逢風燕不定，值石波先疊。", "樓見遠公廬，船經徐穉業。", "邑人多秉筆，州吏亦負笈。", "村女解收魚，津童能用檝。", "唯我有荆扉，無成未得歸。", "見君兄弟出，今日自霑衣。"]'),
('64ab14be-6565-4ac9-aa39-4a9e40d92023','病後遊青龍寺','李端','唐','唐诗','tang','','[]','病來形貌穢，齋沫入東林。',36,'全唐诗/poet.tang.15000.json','["病來形貌穢，齋沫入東林。", "境靜聞神遠，身羸向道深。", "芭蕉高自折，荷葉大先沈。"]'),
('e802bf07-532a-4c10-a92a-baf6eaa25c29','夜尋司空文明逢深上人因寄晉侍御','李端','唐','唐诗','tang','','[]','鶴裘筇竹杖，語笑過林中。',36,'全唐诗/poet.tang.15000.json','["鶴裘筇竹杖，語笑過林中。", "正是月明夜，陶家見遠公。", "自嫌山客務，不與漢官同。"]'),
('cc66b4b1-8c6f-4b27-8abb-27028bd76e2a','長安書事寄薛戴','李端','唐','唐诗','tang','','[]','朔雁去成行，哀蟬響如昨。',156,'全唐诗/poet.tang.15000.json','["朔雁去成行，哀蟬響如昨。", "時芳一憔悴，暮序何蕭索。", "笑語且無聊，逢迎多約略。", "三山不可見，百歲空揮霍。", "故事盡爲愁，新知無復樂。", "夫君又離別，而我加寂寞。", "惠遠縱相尋，陶潛祗獨酌。", "主人恩則厚，客子才自薄。", "委曲見提攜，因循成蹇剝。", "論邊書未上，招隱詩還作。", "貴者已朝餐，豈能敦宿諾。", "飛禽雖失樹，流水長思壑。", "千里寄瓊枝，夢寐青山郭。"]'),
('7ac0a7d0-2347-4647-8165-9dca1bef2530','鮮于少府宅看花','李端','唐','唐诗','tang','','[]','謝家能植藥，萬簇相縈倚。',168,'全唐诗/poet.tang.15000.json','["謝家能植藥，萬簇相縈倚。", "爛熳綠苔前，嬋娟青草裏。", "垂欄復照戶，映竹仍臨水。", "驟雨發芳香，迴風舒錦綺。", "孤光雜新故，衆色更重累。", "散碧出疎莖，分黃成細蘂。", "遊蜂高更下，驚蝶坐還起。", "玉貌對應慙，霞標方不似。", "春陰憐弱蔓，夏日同短晷。", "迴落報榮衰，交關鬬紅紫。", "花時苟未賞，老至誰能止。", "上客屢移牀，幽僧勞憑几。", "初合雖薄劣，却得陪君子。", "敢問賢主人，何如種桃李。"]'),
('667d65f5-9f24-4abd-b635-214ba34533bb','慈恩寺懷舊','李端','唐','唐诗','tang','','[]','去者不可憶，舊遊相見時。',264,'全唐诗/poet.tang.15000.json','["去者不可憶，舊遊相見時。", "凌霄徒更發，非是看花期。", "倚玉交文友，登龍年月久。", "東閣許聯牀，西郊亦攜手。", "彼蒼何暖昧，薄劣翻居後。", "重入遠師谿，誰嘗陶令酒。", "伊昔會禪宮，容輝在眼中。", "籃輿來問道，玉柄解談空。", "孔席亡顏子，僧堂失謝公。", "遺文一書壁，新竹再移叢。", "始聚終成散，朝歡暮不同。", "春霞方照日，夜燭忽迎風。", "蟻鬬聲猶在，鴞災道已窮。", "問天應默默，歸宅太匆匆。", "淒其履還路，莽蒼雲林暮。", "九陌似無人，五陵空有霧。", "緬懷山陽笛，永恨平原賦。", "錯莫過門欄，分明識行路。", "上智本全真，郄公況重臣。", "唯應撫靈運，暫是憶嘉賓。", "存信松猶小，緘哀草尚新。", "鯉庭埋玉樹，那忍見門人。"]'),
('1e5d503c-12ee-4e2c-a645-80e5e892316b','贈薛戴','李端','唐','唐诗','tang','','[]','曉霧忽爲霜，寒蟬還罷響。',156,'全唐诗/poet.tang.15000.json','["曉霧忽爲霜，寒蟬還罷響。", "行人在長道，日暮多歸想。", "射策本何功，名登絳帳中。", "遂矜丘室重，不料阮途窮。", "交結慙時輩，龍鍾似老翁。", "機非鄙夫正，懶是平生性。", "欹枕鴻雁高，閉關花藥盛。", "廚煙當雨絕，階竹連窗暝。", "欲賦苦饑行，無如消渴病。", "舊業歷胡塵，荒原少四鄰。", "田園空有處，兄弟未成人。", "毛義心長苦，袁安家轉貧。", "今呈胸臆事，當爲淚沾巾。"]'),
('3cd9a856-d137-4760-8431-47fd482be3d3','東門送客','李端','唐','唐诗','tang','','[]','綠楊新草路，白髮故鄉人。',36,'全唐诗/poet.tang.15000.json','["綠楊新草路，白髮故鄉人。", "既壯還應老，遊梁復滯秦。", "逢花莫漫折，能有幾多春。"]'),
('d3df845a-eee5-4b84-beb4-0bdeb09cf264','送韓紳卿','李端','唐','唐诗','tang','','[]','春雨昨開花，秋霜忽霑草。',36,'全唐诗/poet.tang.15000.json','["春雨昨開花，秋霜忽霑草。", "榮枯催日夕，去住皆須老。", "君望漢家原，高墳漸成道。"]'),
('77076b15-6e9b-4d55-81c8-89f66b33a428','襄陽曲','李端','唐','唐诗','tang','','[]','襄陽堤路長，草碧柳枝黃。',76,'全唐诗/poet.tang.15000.json','["襄陽堤路長，草碧柳枝黃。", "誰家女兒臨夜妝，紅羅帳裏有燈光。", "雀釵翠羽動明璫，欲出不出脂粉香。", "同居女伴正衣裳，中庭寒月白如霜。", "賈生十八稱才子，空得門前一斷腸。"]'),
('f2a2bee8-b67a-47b5-a061-3e571e8371c9','胡騰兒','李端','唐','唐诗','tang','','[]','胡騰身是涼州兒，肌膚如玉鼻如錐。',144,'全唐诗/poet.tang.15000.json','["胡騰身是涼州兒，肌膚如玉鼻如錐。", "桐布輕衫前後卷，葡萄長帶一邊垂。", "帳前跪作本音語，拾襟攪袖爲君舞。", "安西舊牧收淚看，洛下詞人抄曲與。", "揚眉動目踏花氈，紅汗交流珠帽偏。", "醉却東傾又西倒，雙靴柔弱滿燈前。", "環行急蹴皆應節，反手叉腰如却月。", "絲桐忽奏一曲終，嗚嗚畫角城頭發。", "胡騰兒，胡騰兒，故鄉路斷知不知。"]'),
('86909f2e-2ccb-40d2-8773-8bdec8006cce','贈康洽','李端','唐','唐诗','tang','','[]','黃鬚康兄酒泉客，平生出入王侯宅。',208,'全唐诗/poet.tang.15000.json','["黃鬚康兄酒泉客，平生出入王侯宅。", "今朝醉臥又明朝，忽憶故鄉頭已白。", "流年恍惚瞻西日，陳事蒼茫指南陌。", "聲名恆壓鮑參軍，班位不過揚執戟。", "邇來七十遂無機，空是咸陽一布衣。", "後輩輕肥賤衰朽，五侯門館許因依。", "自言萬物有移改，始信桑田變成海。", "同時獻賦人皆盡，共壁題詩君獨在。", "步出東城風景和，青山滿眼少年多。", "漢家尚壯今則老，髮短心長知奈何。", "華堂舉杯白日晚，龍鍾相見誰能免。", "君今已反我正來，朱顏宜笑能幾回。", "借問朦朧花樹下，誰家畚插築高臺。"]'),
('5785bfff-5e2a-46bf-95ef-6737f20a6993','瘦馬行','李端','唐','唐诗','tang','','[]','城傍牧馬驅未過，一馬徘徊起還臥。',144,'全唐诗/poet.tang.15000.json','["城傍牧馬驅未過，一馬徘徊起還臥。", "眼中有淚皮有瘡，骨毛焦瘦令人傷。", "朝朝放在兒童手，誰覺舉頭看故鄉。", "往時漢地相馳逐，如雨如風過平陸。", "豈意今朝驅不前，蚊蚋滿身泥上腹。", "路人識是名馬兒，疇昔三軍不得騎。", "玉勒金鞍既已遠，追奔獲獸有誰知。", "終身櫪上食君草，遂與駑駘一時老。", "儻借長鳴隴上風，猶期一戰安西道。"]'),
('0c98ec8b-0757-420a-8171-fd439d8c150f','雜歌呈鄭錫司空文明','李端','唐','唐诗','tang','','[]','昨宵夢到亡何鄉，忽見一人山之陽。',160,'全唐诗/poet.tang.15000.json','["昨宵夢到亡何鄉，忽見一人山之陽。", "高冠長劍立石堂，鬢眉颯爽瞳子方。", "胡麻作飯瓊作漿，素書一帙在柏牀。", "啖我還丹拍我背，令我延年在人代。", "乃書數字與我持，小兒歸去須讀之。", "覺來知是虛無事，山中雪平雲覆地。", "東嶺啼猿三四聲，卷簾一望心堪碎。", "蓬萊有梯不可躡，向海回頭淚盈睫。", "且聞童子是蒼蠅，誰謂莊生異蝴蝶。", "學仙去來辭故人，長安道路多風塵。"]'),
('4bd7acac-92da-4afa-b14d-010bb5e9da52','雜歌','李端','唐','唐诗','tang','','[]','漢水至清泥則濁，松枝至堅蘿則弱。',224,'全唐诗/poet.tang.15000.json','["漢水至清泥則濁，松枝至堅蘿則弱。", "十三女兒事他家，顏色如花終索寞。", "蘭生當門燕巢幙，蘭芽未吐燕泥落。", "爲姑偏忌諸嫂良，作婦翻嫌壻家惡。", "人生照鏡須自知，無鹽何用妬西施。", "秦庭野鹿忽爲馬，巧僞亂真君試思。", "伯奇掇蜂賢父逐，曾參殺人慈母疑。", "酒沽千日人不醉，琴弄一弦心已悲。", "常聞善交無爾汝，讒口甚甘良藥苦。", "山雞錦翼豈鳳凰，隴鳥人言止鸚鵡。", "向栩非才徒隱竈，田文有命那關戶。", "犀燭江行見鬼神，木人登席呈歌舞。", "樂生東去終居趙，陽虎北轅飜適楚。", "世間反覆不易陳，緘此貽君淚如雨。"]'),
('29349510-7c20-4105-b50d-258ce53a8523','烏栖曲','李端','唐','唐诗','tang','','[]','白馬逐朱車，黃昏入狹斜。',44,'全唐诗/poet.tang.15000.json','["白馬逐朱車，黃昏入狹斜。", "狹斜柳樹烏爭宿，爭枝未得飛上屋。", "東房少婦壻從軍，每聽烏啼知夜分。"]'),
('12cdd629-7c39-4d78-bfcc-246cffbb7127','送客東歸','李端','唐','唐诗','tang','','[]','昨夜東風吹盡雪，兩京路上梅花發。',48,'全唐诗/poet.tang.15000.json','["昨夜東風吹盡雪，兩京路上梅花發。", "行人相見便東西，日暮溪頭飲馬別。", "把君衫袖望垂楊，兩行淚下思故鄉。"]'),
('b0394c9f-7d5a-4880-a96a-b9211aecc6db','王敬伯歌','李端','唐','唐诗','tang','','[]','妾本舟中女，聞君江上琴。',108,'全唐诗/poet.tang.15000.json','["妾本舟中女，聞君江上琴。", "君初感妾意，妾亦感君心。", "遂出合歡被，同爲交頸禽。", "傳杯唯畏淺，接膝猶嫌遠。", "侍婢奏箜篌，女郎歌宛轉。", "宛轉怨如何，中庭霜漸多。", "霜多葉可惜，昨日非今夕。", "徒結萬重歡，終成一宵客。", "王敬伯，綠水青山從此隔。"]'),
('e321d83c-6578-4f48-a774-aa4abc5d4f9d','救生寺望春寄暢當','李端','唐','唐诗','tang','','[]','東西南北望，望遠悲潛蓄。',40,'全唐诗/poet.tang.15000.json','["東西南北望，望遠悲潛蓄。", "紅黃綠紫花，花開看不足。", "今年與子少相隨，他年與子老相逐。"]'),
('1acf8579-cac4-4305-82f6-de716ca26a76','荆門歌送兄赴夔州','李端','唐','唐诗','tang','','[]','余兄佐郡經西楚，餞行因賦荆門雨。',192,'全唐诗/poet.tang.15000.json','["余兄佐郡經西楚，餞行因賦荆門雨。", "𩆵𩆵燮燮聲漸繁，浦裏人家收市喧。", "重陰大點過欲盡，碎浪柔文相與飜。", "雲間悵望荆衡路，萬里青山一時暮。", "琵琶寺裏響空廊，熨斗陂前濕荒戍。", "沙尾長檣發漸稀，竹竿草屩涉流歸。", "夷陵已遠半成燒，漢上游倡始濯衣。", "船門相對多商估，葛服龍鍾篷下語。", "自是湘州石燕飛，那關齊地商羊舞。", "曾爲江客念江行，腸斷秋荷雨打聲。", "摩天古木不可見，住岳高僧空得名。", "今朝拜首臨欲別，遙憶荆門雨中發。"]'),
('31db4b05-1ecc-4068-82e7-3c4681f2dcd7','妾薄命','李端','唐','唐诗','tang','','["\u95fa\u6028"]','憶妾初嫁君，花鬟如綠雲。',100,'全唐诗/poet.tang.15000.json','["憶妾初嫁君，花鬟如綠雲。", "迴燈入綺帳，轉面脫羅裙。", "折步教人學，偷香與客熏。", "容顏南國重，名字北方聞。", "一從失恩意，轉覺身顦顇。", "對鏡不梳頭，倚窗空落淚。", "新人莫恃新，秋至會無春。", "從來閉在長門者，必是宮中第一人。"]'),
('15a4577a-a56a-4576-bea0-d6f64aea1199','關山月','李端','唐','唐诗','tang','','[]','露濕月蒼蒼，關頭榆葉黃。',48,'全唐诗/poet.tang.15000.json','["露濕月蒼蒼，關頭榆葉黃。", "迴輪照海遠，分彩上樓長。", "水凍頻移幕，兵疲數望鄉。", "只應城影外，萬里共胡霜。"]'),
('a83f524c-ef82-4bb8-a14b-f3360e7b5d2a','度關山','李端','唐','唐诗','tang','','[]','雁塞日初晴，狐關雪復平。',48,'全唐诗/poet.tang.15000.json','["雁塞日初晴，狐關雪復平。", "危樓緣廣漠，古竇傍長城。", "拂劍金星出，彎弧玉羽鳴。", "誰知係虜者，賈誼是書生。"]'),
('dd8200fc-61b8-4d38-8c30-15b54428be42','巫山高','李端','唐','唐诗','tang','','[]','巫山十二峯，皆在碧虛中。',48,'全唐诗/poet.tang.15000.json','["巫山十二峯，皆在碧虛中。", "迴合雲藏月，霏微雨帶風。", "猿聲寒過澗，樹色暮連空。", "愁向高唐望，清秋見楚宮。"]'),
('318bbfaf-054e-4d21-b82b-eb5a62c1fccf','雨雪曲','李端','唐','唐诗','tang','','[]','天山一丈雪，雜雨夜霏霏。',48,'全唐诗/poet.tang.15000.json','["天山一丈雪，雜雨夜霏霏。", "濕馬胡歌亂，經烽漢火微。", "丁零蘇武別，疎勒范羌歸。", "若看關頭下，長榆葉定稀。"]'),
('01fb9d75-9711-4b11-b58d-6d767575044b','春遊樂','李端','唐','唐诗','tang','','[]','柘彈連錢馬，銀鉤妥墮鬟。',48,'全唐诗/poet.tang.15000.json','["柘彈連錢馬，銀鉤妥墮鬟。", "摘桑春陌上，踏草夕陽間。", "意合辭先露，心誠貌却閒。", "明朝若相憶，雲雨出巫山。"]'),
('d8e54bab-695d-4ce2-89a8-908d28feea5d','山下泉','李端','唐','唐诗','tang','','[]','碧水暎丹霞，濺濺度淺沙。',48,'全唐诗/poet.tang.15000.json','["碧水暎丹霞，濺濺度淺沙。", "暗通山下草，流出洞中花。", "淨色和雲落，喧聲遶石斜。", "明朝更尋去，應到阮郎家。"]'),
('24ca4298-5f1f-4a0e-93b1-4e72caafbaee','送客赴洪州','李端','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56", "\u9001\u522b"]','草色隨驄馬，悠悠共出秦。',48,'全唐诗/poet.tang.15000.json','["草色隨驄馬，悠悠共出秦。", "水傳雲夢曉，山接洞庭春。", "帆影連三峽，猿聲在四鄰。", "青門一分手，難見杜陵人。"]'),
('37f4077e-4ef3-4815-bcf9-e8d0e177799d','與鄭錫遊春','李端','唐','唐诗','tang','','[]','東門垂柳長，迴首獨心傷。',48,'全唐诗/poet.tang.15000.json','["東門垂柳長，迴首獨心傷。", "日煖臨芳草，天晴憶故鄉。", "暎花鸎上下，過水蝶飛揚。", "借問同行客，今朝淚幾行。"]'),
('9ad223b0-9c4e-4889-9285-c32465441457','送友人','李端','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','聞說湘川路，年年古木多。',48,'全唐诗/poet.tang.15000.json','["聞說湘川路，年年古木多。", "猿啼巫峽夜，月照洞庭波。", "窮海人還去，孤城雁與過。", "青山不同賞，來往自蹉跎。"]'),
('31f756f8-7fbd-47f7-852b-5d15bccede9a','題從叔沆林園','李端','唐','唐诗','tang','','[]','阮宅閒園暮，窗中見樹陰。',48,'全唐诗/poet.tang.15000.json','["阮宅閒園暮，窗中見樹陰。", "樵歌依遠草，僧語過長林。", "鳥哢花間曲，人彈竹裏琴。", "自嫌身未老，已有住山心。"]'),
('dc1cc95e-2380-4997-9a98-779a7c22b737','送少微上人入蜀','李端','唐','唐诗','tang','','[]','削髮本求道，何方不是歸。',48,'全唐诗/poet.tang.15000.json','["削髮本求道，何方不是歸。", "松風開法席，江月濯禪衣。", "飛閣蟬鳴早，漫天客過稀。", "戴顒常執筆，不覺此身非。"]'),
('07596669-74eb-4543-adf4-0562ec1cdba4','雨後遊輞川','李端','唐','唐诗','tang','','[]','驟雨歸山盡，頹陽入輞川。',48,'全唐诗/poet.tang.15000.json','["驟雨歸山盡，頹陽入輞川。", "看虹登晚墅，踏石過春泉。", "紫葛藏仙井，黃花出野田。", "自知無路去，迴步就人煙。"]'),
('68c41266-d7f8-442e-bd0e-d25192e47ea3','同皇甫侍御題惟一上人房','李端','唐','唐诗','tang','','[]','焚香居一室，盡日見空林。',48,'全唐诗/poet.tang.15000.json','["焚香居一室，盡日見空林。", "得道輕年暮，安禪愛夜深。", "東西皆是夢，存沒豈關心。", "唯羨諸童子，持經在竹陰。"]'),
('a5c02d9d-0d51-4e6a-8533-26f1ffafc4fd','同苗員外宿薦福寺僧舍','李端','唐','唐诗','tang','','[]','潘安秋興動，涼夜宿僧房。',48,'全唐诗/poet.tang.15000.json','["潘安秋興動，涼夜宿僧房。", "倚杖雲離月，垂簾竹有霜。", "迴風生遠逕，落葉颯長廊。", "一與交親會，空貽別後傷。"]'),
('c04af040-9b5f-4954-8080-fc0e5a7feb80','送客往湘江','李端','唐','唐诗','tang','','[]','識君年已老，孤棹向瀟湘。',48,'全唐诗/poet.tang.15000.json','["識君年已老，孤棹向瀟湘。", "素髮臨高鏡，清晨入遠鄉。", "三山分夏口，五兩映涔陽。", "更逐巴東客，南行淚幾行。"]'),
('480b2291-d1d9-4bd7-9851-93f4cf8192e2','送友人遊蜀','李端','唐','唐诗','tang','','[]','嘉陵天氣好，百里見雙流。',48,'全唐诗/poet.tang.15000.json','["嘉陵天氣好，百里見雙流。", "帆影緣巴字，鐘聲出漢州。", "綠原春草晚，青木暮猿愁。", "本是風流地，遊人易白頭。"]'),
('ce356bec-ac61-4adb-ab69-fcf465118812','送友人遊江東','李端','唐','唐诗','tang','','[]','江上花開盡，南行見杪春。',48,'全唐诗/poet.tang.15000.json','["江上花開盡，南行見杪春。", "鳥聲悲古木，雲影入通津。", "返景斜連草，迴潮暗動蘋。", "謝公今在郡，應喜得詩人。"]'),
('a0748bf1-95fb-4c94-882d-f60af170e41c','送樂平苗明府得家字','李端','唐','唐诗','tang','','[]','本自求彭澤，誰云道里賒。',48,'全唐诗/poet.tang.15000.json','["本自求彭澤，誰云道里賒。", "山從石壁斷，江向弋陽斜。", "暮色隨楓樹，陰雲暗荻花。", "諸侯舊調鼎，應重宰臣家。"]'),
('6381e1ed-6c1f-4b0a-b4aa-26fd2370c2c4','過宋州','李端','唐','唐诗','tang','','[]','睢陽陷虜日，外絕救兵來。',48,'全唐诗/poet.tang.15000.json','["睢陽陷虜日，外絕救兵來。", "世亂忠臣死，時清明主哀。", "荒郊春草徧，故壘野花開。", "欲爲將軍哭，東流水不迴。"]'),
('6805e578-f4a7-4cf3-9010-6aa77700dd2c','茂陵山行陪韋金部','李端','唐','唐诗','tang','','[]','宿雨朝來歇，空山秋氣清。',48,'全唐诗/poet.tang.15000.json','["宿雨朝來歇，空山秋氣清。", "盤雲雙鶴下，隔水一蟬鳴。", "古道黃花落，平蕪赤燒生。", "茂陵雖有病，猶得伴君行。"]'),
('5e2d8a26-816a-42a0-a793-43cb68b807be','江上逢司空曙','李端','唐','唐诗','tang','','[]','共爾髫年故，相逢萬里餘。',48,'全唐诗/poet.tang.15000.json','["共爾髫年故，相逢萬里餘。", "新春兩行淚，故國一封書。", "夏口帆初落，涔陽雁正疎。", "唯當執杯酒，暫食漢江魚。"]'),
('0a3c8ec7-42d7-48b9-90df-b961b50d2a28','逢王泌自東京至','李端','唐','唐诗','tang','','[]','逢君自鄉至，雪涕問田園。',48,'全唐诗/poet.tang.15000.json','["逢君自鄉至，雪涕問田園。", "幾處生喬木，誰家在舊村。", "山峰橫二室，水色映千門。", "愁見游從處，如今花正繁。"]'),
('2f5fd8d9-88ef-4407-baa9-cb359cfb0668','山中期吉中孚','李端','唐','唐诗','tang','','[]','行人路不同，花落到山中。',48,'全唐诗/poet.tang.15000.json','["行人路不同，花落到山中。", "水暗蒹葭霧，月明楊柳風。", "年華驚已擲，志業颯然空。", "何必龍鍾後，方期事遠公。"]'),
('07f81b2b-dc25-4246-b886-3374c8e4d564','酬前大理寺評事張芬','李端','唐','唐诗','tang','','[]','君家舊林壑，寄在亂峰西。',48,'全唐诗/poet.tang.15000.json','["君家舊林壑，寄在亂峰西。", "近日春雲滿，相思路亦迷。", "聞鐘投野寺，待月過前溪。", "悵望成幽夢，依依識故蹊。"]'),
('4e36c646-625d-40db-8060-1433058bb551','賦得山泉送房造','李端','唐','唐诗','tang','','[]','泉水山邊去，高人月下看。',48,'全唐诗/poet.tang.15000.json','["泉水山邊去，高人月下看。", "潤松秋色淨，落澗夜聲寒。", "委曲穿深竹，潺湲過遠灘。", "聖朝無隱者，早晚罷漁竿。"]'),
('37843026-d9d5-407b-81b3-74dbfada971d','宿興善寺後堂池','李端','唐','唐诗','tang','','[]','草堂高樹下，月向後池生。',48,'全唐诗/poet.tang.15000.json','["草堂高樹下，月向後池生。", "野客如僧靜，新荷共水平。", "錦鱗沉不食，繡羽亂相鳴。", "即事思江海，誰能萬里行。"]'),
('a5ba3afd-a08c-49e8-a13e-9c90d1d88428','憶皎然上人','李端','唐','唐诗','tang','','[]','未得從師去，人間萬事勞。',48,'全唐诗/poet.tang.15000.json','["未得從師去，人間萬事勞。", "雲門不可見，山木已應高。", "向日開柴戶，驚秋問敝袍。", "何由宿峰頂，窗裏望波濤。"]'),
('09e8939a-ce9c-42d6-b6d5-1d0ae752a3c6','贈衡岳隱禪師','李端','唐','唐诗','tang','','[]','舊住衡州寺，隨緣偶北來。',48,'全唐诗/poet.tang.15000.json','["舊住衡州寺，隨緣偶北來。", "夜禪山雪下，朝汲竹門開。", "半偈傳初盡，羣生意未迴。", "唯當與樵者，杖錫入天台。"]'),
('be3a6223-111c-4452-81ee-7483c9462f52','雲陽觀寄袁稠','李端','唐','唐诗','tang','','[]','花洞晚陰陰，仙壇隔杏林。',48,'全唐诗/poet.tang.15000.json','["花洞晚陰陰，仙壇隔杏林。", "漱泉春谷冷，擣藥夜窗深。", "石上開仙酌，松間對玉琴。", "戴家溪北住，雪後去相尋。"]'),
('7ea7f9d1-64cc-4496-b27a-930f2f52f905','晚遊東田寄司空曙','李端','唐','唐诗','tang','','[]','暮來思遠客，獨立在東田。',48,'全唐诗/poet.tang.15000.json','["暮來思遠客，獨立在東田。", "片雨無妨景，殘虹不映天。", "別愁逢夏果，歸興入秋蟬。", "莫作隳官意，陶潛未必賢。"]'),
('68d9ed9c-3785-4e67-9f3c-6e214f9a15a5','題崔端公園林','李端','唐','唐诗','tang','','[]','上士愛清輝，開門向翠微。',48,'全唐诗/poet.tang.15000.json','["上士愛清輝，開門向翠微。", "抱琴看鶴去，枕石待雲歸。", "野坐苔生席，高眠竹挂衣。", "舊山東望遠，惆悵暮花飛。"]'),
('f99c8509-6d10-44bc-aa49-90dc515dd4ce','早春雪夜寄盧綸兼呈秘書元丞','李端','唐','唐诗','tang','','[]','聞君隨謝朓，春夜宿前川。',48,'全唐诗/poet.tang.15000.json','["聞君隨謝朓，春夜宿前川。", "看竹雲垂地，尋僧月滿田。", "熊寒方入樹，魚樂稍離船。", "獨夜羇愁客，惟知惜故年。"]'),
('48463e26-4422-448c-b3fa-d1245915026d','早春夜集耿拾遺宅','李端','唐','唐诗','tang','','[]','如何逋客會，忽在侍臣家。',48,'全唐诗/poet.tang.15000.json','["如何逋客會，忽在侍臣家。", "新草猶停雪，寒梅未放花。", "銜杯雞欲唱，逗月雁應斜。", "年齒俱憔悴，誰堪故國賒。"]'),
('28dab00e-5163-4f57-921e-1da2b551712e','元丞宅送胡濬及第東歸覲省','李端','唐','唐诗','tang','','[]','登龍兼折桂，歸去當高車。',48,'全唐诗/poet.tang.15000.json','["登龍兼折桂，歸去當高車。", "舊楚楓猶在，前隋柳已疎。", "月中逢海客，浪裏得鄉書。", "見說江邊住，知君不厭魚。"]'),
('3cff4d95-87c2-48bc-81d8-721f843f9a39','送魏廣下第歸揚州寧親','李端','唐','唐诗','tang','','[]','遊宦今空返，浮淮一雁秋。',48,'全唐诗/poet.tang.15000.json','["遊宦今空返，浮淮一雁秋。", "白雲陰澤國，青草遶揚州。", "調膳過花下，張筵到水頭。", "昆山仍有玉，歲晏莫淹留。"]'),
('2baf65cc-4604-4ccf-ac0a-94994e18e15e','歸山與酒徒別','李端','唐','唐诗','tang','','[]','野客本無事，此來非有求。',48,'全唐诗/poet.tang.15000.json','["野客本無事，此來非有求。", "煩君徵樂餞，未免憶山愁。", "紅燭侵明月，青娥促白頭。", "童心久已盡，豈爲豔歌留。"]'),
('c340def5-21ad-4179-bfac-3007ebe37f5d','冬夜寄韓弇','李端','唐','唐诗','tang','','[]','獨坐知霜下，開門見木衰。',48,'全唐诗/poet.tang.15000.json','["獨坐知霜下，開門見木衰。", "壯應隨日去，老豈與人期。", "廢井蟲鳴早，陰階菊發遲。", "興來空憶戴，不似剡溪時。"]'),
('6e839873-f7fa-477e-bbae-ba1add31be7e','聞吉道士還俗因而有贈','李端','唐','唐诗','tang','','[]','聞有華陽客，儒裳謁紫微。',48,'全唐诗/poet.tang.15000.json','["聞有華陽客，儒裳謁紫微。", "舊山連藥賣，孤鶴帶雲歸。", "柳市名猶在，桃源夢已稀。", "還鄉見鷗鳥，應愧背船飛。"]'),
('2e235fe0-7c45-444b-b33d-a317f79b6ec5','韋員外東齋看花','李端','唐','唐诗','tang','','[]','入花凡幾步，此樹獨相留。',48,'全唐诗/poet.tang.15000.json','["入花凡幾步，此樹獨相留。", "發豔紅枝合，垂煙綠水幽。", "倂開偏覺好，未落已成愁。", "一到芳菲下，空招兩鬢秋。"]'),
('aa5b58b9-029a-4cc0-856b-a2dd09cb4a74','邊頭作','李端','唐','唐诗','tang','','[]','邠郊泉脉動，落日上城樓。',48,'全唐诗/poet.tang.15000.json','["邠郊泉脉動，落日上城樓。", "羊馬水草足，羌胡帳幕稠。", "射鵰過海岸，傳箭怯邊州。", "何事歸朝將，今年又拜侯。"]'),
('ac707a09-78f2-4230-a223-17d9173ef41a','宿深上人院聽遠泉','李端','唐','唐诗','tang','','[]','泉聲宜遠聽，入夜對支公。',48,'全唐诗/poet.tang.15000.json','["泉聲宜遠聽，入夜對支公。", "斷續來方盡，潺湲咽又通。", "何年出石下，幾里在山中。", "君問窮源處，禪心與此同。"]'),
('c3c25268-b08b-4126-8e77-141cf5bbeaad','茂陵村行贈何兆','李端','唐','唐诗','tang','','[]','春天黃鳥囀，野逕白雲閒。',48,'全唐诗/poet.tang.15000.json','["春天黃鳥囀，野逕白雲閒。", "解帶依芳草，支頤想故山。", "人行九州路，樹老五陵間。", "誰道臨邛遠，相如自憶還。"]'),
('0e58b1d3-ae22-41da-9995-93c3d985e01c','送友人還洛','李端','唐','唐诗','tang','','[]','去國渡關河，蟬鳴古樹多。',48,'全唐诗/poet.tang.15000.json','["去國渡關河，蟬鳴古樹多。", "平原正超忽，行子復蹉跎。", "去事不可想，舊遊難再過。", "何當嵩岳下，相見在煙蘿。"]'),
('3adb71b6-f985-49f8-8c0d-cda8ddd64891','送戴徵士還山','李端','唐','唐诗','tang','','[]','柔桑錦臆雉，相送到煙霞。',48,'全唐诗/poet.tang.15000.json','["柔桑錦臆雉，相送到煙霞。", "獨隱空山裏，閒門幾樹花。", "草生楊柳岸，鳥囀竹林家。", "不是謀生拙，無爲末路賒。"]'),
('4d79a7f2-2e3c-496a-b9bd-9f778aee26ee','秋日旅舍別司空文明','李端','唐','唐诗','tang','','[]','涼風颯窮巷，秋思滿高雲。',48,'全唐诗/poet.tang.15000.json','["涼風颯窮巷，秋思滿高雲。", "吏隱俱不就，此心仍別君。", "素懷宗淡泊，羈旅念功勳。", "轉憶西林寺，江聲月下聞。"]'),
('5fbdbf12-a0c7-4e46-bca8-8d09a3dfdaa8','旅舍對雪贈考功王員外','李端','唐','唐诗','tang','','[]','楊花驚滿路，麵市忽狂風。',48,'全唐诗/poet.tang.15000.json','["楊花驚滿路，麵市忽狂風。", "驟下搖蘭葉，輕飛集竹叢。", "欲將瓊樹比，不共玉人同。", "獨望徽之棹，青山在雪中。"]'),
('aba0b6ed-1b47-4c35-bd39-17a4a4a069b5','送丁少府往唐上','李端','唐','唐诗','tang','','[]','因君灞陵別，故國一迴看。',48,'全唐诗/poet.tang.15000.json','["因君灞陵別，故國一迴看。", "共食田文飯，先之梅福官。", "江風轉日暮，山月滿潮寒。", "不得同舟望，淹留歲月闌。"]'),
('28af459d-8908-4c13-ae29-d6d768ad54d4','贈李龜年','李端','唐','唐诗','tang','','[]','青春事漢主，白首入秦城。',48,'全唐诗/poet.tang.15000.json','["青春事漢主，白首入秦城。", "遍識才人字，多知舊曲名。", "風流隨故事，語笑合新聲。", "獨有垂楊樹，偏傷日暮情。"]'),
('99edd908-d72c-419a-b92f-61939a21ad4a','送郭補闕歸江陽','李端','唐','唐诗','tang','','[]','東門春尚淺，楊柳未成陰。',48,'全唐诗/poet.tang.15000.json','["東門春尚淺，楊柳未成陰。", "雁影愁斜日，鸎聲怨故林。", "隋宮江上遠，梁苑雪中深。", "獨有懷歸客，難爲欲別心。"]'),
('c119d5d1-3bd8-40af-ae71-a9f5a990ce14','早春會王逵主人得蓬字','李端','唐','唐诗','tang','','[]','今年華鬢色，半在故人中。',48,'全唐诗/poet.tang.15000.json','["今年華鬢色，半在故人中。", "欲寫無窮恨，先期一醉同。", "綠叢猶覆雪，紅萼已凋風。", "莫負歸山契，君看陌上蓬。"]'),
('517af7f0-4487-4764-9ade-e6838c8b445f','宿山寺思歸','李端','唐','唐诗','tang','','[]','僧房秋雨歇，愁臥夜更深。',48,'全唐诗/poet.tang.15000.json','["僧房秋雨歇，愁臥夜更深。", "欹枕聞鴻雁，迴燈見竹林。", "歸螢入草盡，落月映窗沉。", "拭淚無人覺，長謠向壁陰。"]'),
('7e4f268d-88bd-4640-9992-d20c160a1d3d','送客赴江陵寄郢州郎士元','李端','唐','唐诗','tang','','[]','露下晚蟬愁，詩人舊怨秋。',48,'全唐诗/poet.tang.15000.json','["露下晚蟬愁，詩人舊怨秋。", "沅湘莫留滯，宛洛好遨遊。", "飲馬逢黃菊，離家值白頭。", "竟陵明月夜，爲上庾公樓。"]'),
('06a0a6ef-06f6-45dc-b9be-c94b65e8c7e5','送客賦得巴江夜猿','李端','唐','唐诗','tang','','[]','巴水天邊路，啼猿傷客情。',48,'全唐诗/poet.tang.15000.json','["巴水天邊路，啼猿傷客情。", "遲遲雲外盡，杳杳樹中生。", "殘月暗將落，空霜寒欲明。", "楚人皆掩淚，聞到第三聲。"]'),
('624cc745-9bec-4afc-9032-52042f103c9e','秋日憶暕上人','李端','唐','唐诗','tang','','[]','一從持鉢別，更未到人間。',48,'全唐诗/poet.tang.15000.json','["一從持鉢別，更未到人間。", "好靜居貧寺，遺名棄近山。", "雨前縫百衲，葉下閉重關。", "若便潯陽去，須將舊客還。"]'),
('04fb8049-647f-44a5-b729-20ba3af1399a','寄上舍人叔','李端','唐','唐诗','tang','','[]','車馬朝初下，看山憶獨尋。',48,'全唐诗/poet.tang.15000.json','["車馬朝初下，看山憶獨尋。", "會知逢水盡，且愛入雲深。", "殘雨開斜日，新蟬發迥林。", "阮咸雖別巷，遙識此時心。"]'),
('e9013cb0-39cc-4b2a-9f1d-6b466b6a2389','送古之奇赴安西幕','李端','唐','唐诗','tang','','[]','疇昔十年兄，相逢五校營。',48,'全唐诗/poet.tang.15000.json','["疇昔十年兄，相逢五校營。", "今宵舉杯酒，隴月見軍城。", "堠火經陰絕，邊人接曉行。", "殷勤送書記，強虜幾時平。"]'),
('f61b4916-5970-4772-8090-8faab5cb0acf','送張芬歸江東兼寄柳中庸','李端','唐','唐诗','tang','','[]','久是天涯客，偏傷落木時。',48,'全唐诗/poet.tang.15000.json','["久是天涯客，偏傷落木時。", "如何故國見，更欲異鄉期。", "鳥暮東西急，波寒上下遲。", "空將滿眼淚，千里怨相思。"]'),
('8204939c-ce4f-42e9-8a0c-042d847893f3','送丘丹歸江東','李端','唐','唐诗','tang','','[]','故山霜落久，才子憶荆扉。',48,'全唐诗/poet.tang.15000.json','["故山霜落久，才子憶荆扉。", "旅舍尋人別，秋風逐雁歸。", "夢愁楓葉盡，醉惜菊花稀。", "肯學求名者，經年未拂衣。"]'),
('12676785-e9e4-4d9b-83de-ff031e56f520','臥病寄苗員外','李端','唐','唐诗','tang','','[]','故人初未貴，相見得淹留。',48,'全唐诗/poet.tang.15000.json','["故人初未貴，相見得淹留。", "一自朝天去，因成計日遊。", "月明應獨醉，葉下肯同愁。", "因恨劉楨病，空園臥見秋。"]'),
('4bf27b1f-061f-4463-8180-61927064aac2','送楊臯擢第歸江東','李端','唐','唐诗','tang','','[]','隋堤望楚國，江上一歸人。',48,'全唐诗/poet.tang.15000.json','["隋堤望楚國，江上一歸人。", "綠氣千檣暮，青風萬里春。", "試才初得桂，泊渚肯傷蘋。", "拜手終悽愴，恭承中外親。"]'),
('c326aa75-69df-42ec-b918-aacbb8d10860','題鄭少府林園','李端','唐','唐诗','tang','','[]','謝家今日晚，詞客願抽毫。',48,'全唐诗/poet.tang.15000.json','["謝家今日晚，詞客願抽毫。", "櫪馬方迴影，池鵝正理毛。", "竹筒傳水遠，麈尾坐僧高。", "獨有宗雷賤，過君著敝袍。"]'),
('ee3750cc-563c-4bc1-be08-92cbe45ba0d1','送吉中孚拜官歸業','李端','唐','唐诗','tang','','[]','南入華陽洞，無人古樹寒。',48,'全唐诗/poet.tang.15000.json','["南入華陽洞，無人古樹寒。", "吟詩開舊帙，帶綬上荒壇。", "因病求歸易，霑恩更隱難。", "孟宗應獻鮓，家近守漁官。"]'),
('477e1b28-8c69-4536-9442-41681596f0eb','送楊少府赴陽翟','李端','唐','唐诗','tang','','[]','冠帶仁兄後，光輝壽母前。',48,'全唐诗/poet.tang.15000.json','["冠帶仁兄後，光輝壽母前。", "陸雲還入洛，潘岳更張筵。", "井邑嵩山對，園林潁水連。", "東人欲相送，旅舍已潸然。"]'),
('5cbacdef-c801-4b10-b17e-05adda87211a','慈恩寺暕上人房招耿拾遺','李端','唐','唐诗','tang','','[]','悠然對惠遠，共結故山期。',48,'全唐诗/poet.tang.15000.json','["悠然對惠遠，共結故山期。", "汲井樹陰下，閉門亭午時。", "地閒花落厚，石淺水流遲。", "願與神仙客，同來事本師。"]'),
('10343b4e-a3ad-48f1-8bed-e0d7e4905971','宿山寺雪夜寄吉中孚','李端','唐','唐诗','tang','','[]','獨愛僧房竹，春來長到池。',48,'全唐诗/poet.tang.15000.json','["獨愛僧房竹，春來長到池。", "雲遮皆晃朗，雪壓半低垂。", "不見侵山葉，空聞拂地枝。", "鄙夫今夜興，唯有子猷知。"]'),
('62178074-6682-491e-8e6f-13258a757d32','贈趙神童','李端','唐','唐诗','tang','','[]','聖朝殊漢令，才子少登科。',48,'全唐诗/poet.tang.15000.json','["聖朝殊漢令，才子少登科。", "每見先鳴早，常驚後進多。", "獨居方寂寞，相對覺蹉跎。", "不是通家舊，頻勞文舉過。"]'),
('c90872e4-378a-48f6-b5dd-3ddf44f4af01','宿雲際寺贈深上人','李端','唐','唐诗','tang','','[]','暫別青藍寺，今來髮欲斑。',48,'全唐诗/poet.tang.15000.json','["暫別青藍寺，今來髮欲斑。", "獨眠孤燭下，風雨在前山。", "壞宅終須去，空門不易還。", "支公有方便，一願啓玄關。"]'),
('b15981cd-41a4-484b-be49-c8c92bddf5e5','送從兄赴洪州別駕兄善琴','李端','唐','唐诗','tang','','[]','援琴兼愛竹，遙夜在湘沅。',48,'全唐诗/poet.tang.15000.json','["援琴兼愛竹，遙夜在湘沅。", "鶴舞月將下，烏啼霜正繁。", "亂流喧橘岸，飛雪暗荆門。", "佐郡無辭屈，其如相府恩。"]'),
('9991691b-23a6-463b-9eef-0f36027d8a9b','山中期張芬不至','李端','唐','唐诗','tang','','[]','石堤春草碧，雙燕向西飛。',48,'全唐诗/poet.tang.15000.json','["石堤春草碧，雙燕向西飛。", "悵望雲天暮，佳人何處歸。", "藥欄蟲網遍，苔井水痕稀。", "誰道嵇康嬾，山中自掩扉。"]'),
('51169d5f-1218-48cf-873a-c2851aa0c9b7','寄暢當','李端','唐','唐诗','tang','','[]','麥秀草芊芊，幽人好晝眠。',48,'全唐诗/poet.tang.15000.json','["麥秀草芊芊，幽人好晝眠。", "雲霞生嶺上，猿鳥下牀前。", "顏子方敦行，支郎久住禪。", "中林輕暫別，約略已經年。"]'),
('4f0445db-513b-4949-ab33-5412bcd8c074','送義興元少府','李端','唐','唐诗','tang','','[]','逢君惠連第，初命[便]光輝。',50,'全唐诗/poet.tang.15000.json','["逢君惠連第，初命[便]光輝。", "已得羣公祖，終妨太傅譏。", "路長人反顧，草斷燕迴飛。", "本是江南客，還同衣錦歸。"]'),
('d166bb61-1756-49af-8967-29ae96ddf592','臥病別鄭錫','李端','唐','唐诗','tang','','[]','病來喜無事，多臥竹林間。',50,'全唐诗/poet.tang.15000.json','["病來喜無事，多臥竹林間。", "此日一相見，明朝還掩關。", "幽人愛芳草，志士惜頹顏。", "歲[晏]不我棄，期君在故山。"]'),
('f81acf44-ba49-457e-9735-26292f63ec3b','書志贈暢當','李端','唐','唐诗','tang','','[]','少喜神仙術，未去已蹉跎。',48,'全唐诗/poet.tang.15000.json','["少喜神仙術，未去已蹉跎。", "壯志一爲累，浮生事漸多。", "衰顏不相識，歲暮定相過。", "請問宗居士，君其奈老何。"]'),
('90000504-3c60-4a56-8955-0760535a6d42','送諸曁裴少府','李端','唐','唐诗','tang','','[]','山公訪嵇紹，趙武見韓侯。',48,'全唐诗/poet.tang.15000.json','["山公訪嵇紹，趙武見韓侯。", "事去恩猶在，名成淚却流。", "一官同北去，千里赴南州。", "才子清風後，無貽相府憂。"]'),
('ec92b206-bff8-43a6-ae6b-977430e21bd8','送鄭宥入蜀迎覲','李端','唐','唐诗','tang','','[]','寧親西陟險，君去異王陽。',48,'全唐诗/poet.tang.15000.json','["寧親西陟險，君去異王陽。", "在世誰非客，還家即是鄉。", "劍門千轉盡，巴水一支長。", "請語愁猿道，無煩促淚行。"]'),
('664aff60-36cb-4907-8842-e6717be10cce','送耿拾遺湋使江南括圖書','李端','唐','唐诗','tang','','[]','驅傳草連天，回風滿樹蟬。',48,'全唐诗/poet.tang.15000.json','["驅傳草連天，回風滿樹蟬。", "將過夫子宅，前問孝廉船。", "漢使收三篋，周詩採百篇。", "別來將有淚，不是怨流年。"]'),
('2a24e107-6995-4aba-8051-bd14bd55e78f','送王少府遊河南','李端','唐','唐诗','tang','','[]','馬卿方失意，東去謁諸侯。',48,'全唐诗/poet.tang.15000.json','["馬卿方失意，東去謁諸侯。", "過宋人應少，遊梁客獨愁。", "鳥翻千室暮，蟬急兩河秋。", "僕本無媒者，因君淚亦流。"]'),
('0f2f5bed-450c-40f4-b45c-4838badedf18','送別駕赴晉陵即舍人叔之兄','李端','唐','唐诗','tang','','[]','諸宗稱叔父，從子亦光輝。',48,'全唐诗/poet.tang.15000.json','["諸宗稱叔父，從子亦光輝。", "謝脁中書直，王祥別乘歸。", "江帆衝雨上，海樹隔潮微。", "南阮貧無酒，唯將淚濕衣。"]'),
('b4f9fafa-98fa-4d1a-b7a7-893371caaf1b','臥病寄閻寀','李端','唐','唐诗','tang','','[]','病中貪好景，強步出幽居。',48,'全唐诗/poet.tang.15000.json','["病中貪好景，強步出幽居。", "紫葛垂山徑，黃花遶野渠。", "荒林飛老鶴，敗堰過遊魚。", "縱憶同年友，無人可寄書。"]'),
('12235098-ffc0-49a5-bca0-0730abcbc337','晚夏聞蟬寄廣文','李端','唐','唐诗','tang','','[]','昨日鶯囀聲，今朝蟬忽鳴。',48,'全唐诗/poet.tang.15000.json','["昨日鶯囀聲，今朝蟬忽鳴。", "朱顏向華髮，定是幾年程。", "故國白雲遠，閒居青草生。", "因垂數行淚，書報十年兄。"]'),
('616d4775-8f78-4128-ada7-4722ae705698','歸山居寄錢起','李端','唐','唐诗','tang','','[]','悵望青山下，回頭淚滿巾。',48,'全唐诗/poet.tang.15000.json','["悵望青山下，回頭淚滿巾。", "故鄉多古樹，落日少行人。", "髮鬢將回色，簪纓未到身。", "誰知武陵路，亦有漢家臣。"]'),
('f3019c14-dd48-4626-8fe8-a31151f8456e','曉發瓜州','李端','唐','唐诗','tang','','[]','曉發悲行客，停橈獨未前。',48,'全唐诗/poet.tang.15000.json','["曉發悲行客，停橈獨未前。", "寒江半有月，野戍漸無煙。", "棹唱臨高岸，鴻嘶發遠田。", "誰知避徒御，對酒一潸然。"]'),
('dde43147-3d4b-4c3b-b9f8-5e45db51e046','江上喜逢司空文明','李端','唐','唐诗','tang','','[]','秦人江上見，握手淚沾巾。',48,'全唐诗/poet.tang.15000.json','["秦人江上見，握手淚沾巾。", "落日見秋草，暮年逢故人。", "非夫長作客，多病淺謀身。", "臺閣舊親友，誰曾見苦辛。"]'),
('29b0a3bb-27ae-462d-a793-f632108d3a58','同苗發慈恩寺避暑','李端','唐','唐诗','tang','','[]','追涼尋寶剎，畏日望璇題。',48,'全唐诗/poet.tang.15000.json','["追涼尋寶剎，畏日望璇題。", "臥草同鴛侶，臨池似虎溪。", "樹閒人跡外，山晚鳥行西。", "若問無心法，蓮花隔淤泥。"]'),
('c427bc24-14a9-4fdb-8801-ead203ab9fa2','送潘述宏詞下第歸江外','李端','唐','唐诗','tang','','["\u957f\u6c5f"]','唱高人不和，此去淚難收。',48,'全唐诗/poet.tang.15000.json','["唱高人不和，此去淚難收。", "上國經年住，長江滿目流。", "弈棊知勝偶，射策請焚舟。", "應是田囗囗，玄成許爾遊。"]'),
('d455202e-0577-4455-bf2b-0e7040ed9bf4','送張少府赴夏縣','李端','唐','唐诗','tang','','["\u9ec4\u6cb3"]','雖爲州縣職，還欲抱琴過。',48,'全唐诗/poet.tang.15000.json','["雖爲州縣職，還欲抱琴過。", "樹古聞風早，山枯見雪多。", "雞聲連絳市，馬色傍黃河。", "太守新臨郡，還逢五袴歌。"]'),
('80c7cd27-c454-481e-b3d5-5845b4bc3627','酬秘書元丞郊園臥疾見寄','李端','唐','唐诗','tang','','[]','聞說漳濱臥，題詩怨歲華。',48,'全唐诗/poet.tang.15000.json','["聞說漳濱臥，題詩怨歲華。", "求醫主高手，報疾到貧家。", "撒枕銷行蟻，移杯失畫蛇。", "明朝九衢上，應見玉人車。"]'),
('fd046c72-5c26-4565-b0cc-044e954feda6','送成都韋丞還蜀','李端','唐','唐诗','tang','','[]','蜀門雲樹合，高棧有猿愁。',48,'全唐诗/poet.tang.15000.json','["蜀門雲樹合，高棧有猿愁。", "驅傳加新命，之官向舊遊。", "晨裝逢酒雨，夜夢見刀州。", "遠別長相憶，當年莫滯留。"]'),
('a2ade3e4-2e64-4fb2-9b4c-0b07bcad2ffb','晚秋旅舍寄苗員外','李端','唐','唐诗','tang','','[]','爭途苦不前，貧病遂連牽。',48,'全唐诗/poet.tang.15000.json','["爭途苦不前，貧病遂連牽。", "向暮同行客，當秋獨長年。", "晚花唯有菊，寒葉已無蟬。", "吏部逢今日，還應甕下眠。"]'),
('c9d73415-8fff-4c3a-8857-f49b49e3fdf1','送惟良上人歸潤州','李端','唐','唐诗','tang','','[]','擬詩偏不類，又送上人歸。',48,'全唐诗/poet.tang.15000.json','["擬詩偏不類，又送上人歸。", "寄世同高鶴，尋仙稱壞衣。", "雨行江草短，露坐海帆稀。", "正被空門縛，臨岐乞解圍。"]'),
('c0c804f0-03cb-4610-a809-f413608ac25e','送何兆下第還蜀','李端','唐','唐诗','tang','','[]','重江不可涉，孤客莫晨裝。',48,'全唐诗/poet.tang.15000.json','["重江不可涉，孤客莫晨裝。", "高木莎城小，殘星棧道長。", "褭猿楓子落，過雨荔枝香。", "勸爾成都住，文翁有草堂。"]'),
('010728ad-02ef-48b6-a80b-1602b392a698','送友人宰湘陰','李端','唐','唐诗','tang','','[]','從宦舟行遠，浮湘又入閩。',48,'全唐诗/poet.tang.15000.json','["從宦舟行遠，浮湘又入閩。", "蒹葭無朔雁，檉栝有蠻神。", "傳吏閒調象，山精暗訟人。", "唯須千樹橘，暫救李衡貧。"]'),
('7378a7d0-6a90-4ab6-852b-74b8b98f09e6','送元晟歸江東舊居','李端','唐','唐诗','tang','','[]','澤國舟車接，關門雨雪乖。',48,'全唐诗/poet.tang.15000.json','["澤國舟車接，關門雨雪乖。", "春天行故楚，夜月下清淮。", "講易居山寺，論詩到郡齋。", "蔣家人暫別，三路草連堦。"]'),
('8670e43a-7cff-4436-81ab-157afb81eac3','送黎少府赴陽翟','李端','唐','唐诗','tang','','[]','詩禮稱才子，神仙是丈人。',48,'全唐诗/poet.tang.15000.json','["詩禮稱才子，神仙是丈人。", "玉山那惜醉，金谷已無春。", "白馬如風疾，青袍奪草新。", "不嫌鳴吠客，願用百年身。"]'),
('2fb33cc4-43fb-42b9-8e7e-2790d9a01d6b','送夏侯審遊蜀','李端','唐','唐诗','tang','','[]','西望煙綿樹，愁君上蜀時。',48,'全唐诗/poet.tang.15000.json','["西望煙綿樹，愁君上蜀時。", "同林息商客，隔棧見罛師。", "石滑羊腸險，山空杜宇悲。", "琴心正幽怨，莫奏鳳凰詩。"]'),
('dbe3db07-8b1c-4edf-8a8d-eefb22db972e','單推官廳前雙桐詠','李端','唐','唐诗','tang','','[]','封植因高興，孤貞契素期。',48,'全唐诗/poet.tang.15000.json','["封植因高興，孤貞契素期。", "由來得地早，何事結花遲。", "葉重凝煙後，條寒過雨時。", "還同李家樹，爭賦角弓詩。"]'),
('ed458409-9298-486a-b549-65f60c967a8b','送宋校書赴宣州幕','李端','唐','唐诗','tang','','[]','浮舟壓芳草，容裔逐江春。',48,'全唐诗/poet.tang.15000.json','["浮舟壓芳草，容裔逐江春。", "遠避看書吏，行當入幕賓。", "夜潮衝老樹，曉雨破輕蘋。", "鴛鷺多傷別，欒家德在人。"]'),
('313f41fa-0152-4b99-81d2-ee96ff20a074','送趙給事姪尉丹陽','李端','唐','唐诗','tang','','[]','太傅憐羣從，門人亦賤回。',48,'全唐诗/poet.tang.15000.json','["太傅憐羣從，門人亦賤回。", "入官先愛子，賜酒許同杯。", "淮海春多雨，蒹葭夜有雷。", "遙知拜慶後，梅尉稱仙才。"]'),
('2213a457-daa0-4b8c-8576-928ab743e4cd','宿瓜洲寄柳中庸','李端','唐','唐诗','tang','','[]','懷人同不寐，清夜起論文。',48,'全唐诗/poet.tang.15000.json','["懷人同不寐，清夜起論文。", "月魄正出海，雁行斜上雲。", "寒潮來灩灩，秋葉下紛紛。", "便送江東去，徘徊祗待君。"]'),
('2c1885e2-fc93-4291-82ab-c2c92055a909','夜宴虢縣張明府宅逢宇文評事','李端','唐','唐诗','tang','','[]','虢田留古宅，入夜足秋風。',48,'全唐诗/poet.tang.15000.json','["虢田留古宅，入夜足秋風。", "月影來窗裏，燈光落水中。", "徵詩逢謝客，飲酒得陶公。", "更愛疎籬下，繁霜濕菊叢。"]'),
('8b0f0da9-2461-4e36-9044-1b49a44efbe7','冬夜集張尹後閣','李端','唐','唐诗','tang','','[]','乘龜兼戴豸，白面映朱衣。',48,'全唐诗/poet.tang.15000.json','["乘龜兼戴豸，白面映朱衣。", "安石還須起，泉明不得歸。", "譍門常吏在，登席舊寮稀。", "遠客長先醉，那知亞相威。"]'),
('05bce030-82e2-495c-a8a3-20ae16cc7564','將之澤潞留別王郎中','李端','唐','唐诗','tang','','[]','弱年知己少，前路主人稀。',48,'全唐诗/poet.tang.15000.json','["弱年知己少，前路主人稀。", "貧病期相惜，艱難又憶歸。", "事成應未卜，身賤又無機。", "幸到龍門下，須因羽翼飛。"]'),
('5bf914dc-5c7f-4d9f-abe7-b5b2e1b10186','晚次巴陵','李端','唐','唐诗','tang','','[]','雪後柳條新，巴陵城下人。',48,'全唐诗/poet.tang.15000.json','["雪後柳條新，巴陵城下人。", "烹魚邀水客，載酒奠山神。", "雲去低斑竹，波迴動白蘋。", "不堪逢楚老，日暮正江春。"]'),
('de08789e-f931-4c88-aece-d70d5c5aa197','送荀道士歸廬山','李端','唐','唐诗','tang','','["\u5e90\u5c71"]','先生歸有處，欲別笑無言。',48,'全唐诗/poet.tang.15000.json','["先生歸有處，欲別笑無言。", "綠水到山口，青林連洞門。", "月明尋石路，雲霽望花源。", "早晚還乘鶴，悲歌向故園。"]'),
('eb5774b6-2822-479b-92ab-c4028ec564bd','送張淑歸覲叔父','李端','唐','唐诗','tang','','[]','日慘長亭暮，天高大澤閒。',48,'全唐诗/poet.tang.15000.json','["日慘長亭暮，天高大澤閒。", "風中聞草木，雪裏見江山。", "馬向塞雲去，人隨古道還。", "阮家今夜樂，應在竹林間。"]'),
('5b59eecb-8e64-4f62-8642-9d154a869838','送郭參軍赴絳州','李端','唐','唐诗','tang','','[]','登車君莫望，故絳柳條春。',48,'全唐诗/poet.tang.15000.json','["登車君莫望，故絳柳條春。", "蒲澤逢胡雁，桃源見晉人。", "佐軍髯尚短，擲地思還新。", "小謝常攜手，因之醉路塵。"]'),
('da1f200e-5c0e-47f3-a256-793110d7b716','送袁稠游江南','李端','唐','唐诗','tang','','[]','江南衰草遍，十里見長亭。',48,'全唐诗/poet.tang.15000.json','["江南衰草遍，十里見長亭。", "客去逢搖落，鴻飛入杳冥。", "空城寒雨細，深院曉燈青。", "欲去行人起，徘徊恨酒醒。"]'),
('5c365aaf-f2df-4a07-adf6-dd460903675d','送夏中丞赴寧國任','李端','唐','唐诗','tang','','["\u957f\u6c5f"]','楚縣入青楓，長江一派通。',48,'全唐诗/poet.tang.15000.json','["楚縣入青楓，長江一派通。", "板橋尋謝客，古邑事陶公。", "片雨收山外，連雲上漢東。", "陸機猶滯洛，念子望南鴻。"]'),
('f8abbcf9-6e8c-474c-a9e0-cdf19686d015','送衞雄下第歸同州','李端','唐','唐诗','tang','','[]','不才先上第，詞客却空還。',48,'全唐诗/poet.tang.15000.json','["不才先上第，詞客却空還。", "邊地行人少，平蕪盡日閒。", "一蟬陂樹裏，衆火隴雲間。", "羨汝歸茅屋，書窗見遠山。"]'),
('a64c0e34-2b67-4ae9-95a3-6603562da624','送單少府赴扶風','李端','唐','唐诗','tang','','[]','少年趨盛府，顏色比花枝。',48,'全唐诗/poet.tang.15000.json','["少年趨盛府，顏色比花枝。", "范匄非童子，楊修豈小兒。", "叨陪丈人行，常恐阿戎欺。", "此去雲霄近，看君逸足馳。"]'),
('95d54531-dd2a-4f05-8064-c28224919dfc','題山中別業','李端','唐','唐诗','tang','','[]','舊宅在山中，閒門與寺通。',48,'全唐诗/poet.tang.15000.json','["舊宅在山中，閒門與寺通。", "往來黃葉路，交結白頭翁。", "晚笋難成竹，秋花不滿叢。", "生涯祗麤糲，吾豈諱言窮。"]'),
('6bf8b3b5-c0a1-4b65-945a-1f8cbcc10770','送司空文明歸江上舊居','李端','唐','唐诗','tang','','[]','野菊有黃花，送君千里還。',48,'全唐诗/poet.tang.15000.json','["野菊有黃花，送君千里還。", "鴻來燕又去，離別惜容顏。", "流水通歸夢，行雲失故關。", "江風正搖落，宋玉莫登山。"]'),
('b065477a-bb08-4ce1-b740-c736fd542d1c','送新城戴叔倫明府','李端','唐','唐诗','tang','','[]','遙想隋堤路，春天楚國情。',48,'全唐诗/poet.tang.15000.json','["遙想隋堤路，春天楚國情。", "白雲當海斷，青草隔淮生。", "雁起斜還直，潮回遠復平。", "萊蕪不可到，一醉送君行。"]'),
('b476bd50-8790-464f-9141-8c9d88097745','送雍丘任少府','李端','唐','唐诗','tang','','[]','叢車餞才子，路走許東偏。',48,'全唐诗/poet.tang.15000.json','["叢車餞才子，路走許東偏。", "遠水同春色，繁花勝雪天。", "鳥行侵楚邑，樹影向殷田。", "莫學生鄉思，梅真正少年。"]'),
('61b2b15c-601a-479b-a00a-f4dcd6f88b13','送雍郢州','李端','唐','唐诗','tang','','[]','厭郎思出守，遂領漢東軍。',48,'全唐诗/poet.tang.15000.json','["厭郎思出守，遂領漢東軍。", "望月逢殷浩，緣江送范雲。", "城閒煙草遍，浦逈雪林分。", "誰伴樓中宿，吟詩估客聞。"]'),
('cfa9216e-b1c0-459d-94c9-972427733c96','寄王密卿','李端','唐','唐诗','tang','','[]','酒樂今年少，僧期近日頻。',48,'全唐诗/poet.tang.15000.json','["酒樂今年少，僧期近日頻。", "買山多爲竹，卜宅不緣貧。", "志業歸初地，文章寄此身。", "嵇康雖有病，猶得見情人。"]'),
('4af45c65-e023-4d75-9d16-11c31976c68d','與蕭遠上人游少華山寄皇甫侍御','李端','唐','唐诗','tang','','[]','尋危兼採藥，渡水又登山。',48,'全唐诗/poet.tang.15000.json','["尋危兼採藥，渡水又登山。", "獨與高僧去，逍遙落日間。", "漸看閭里遠，自覺性情閒。", "廻首知音在，因令悵望還。"]'),
('e8711802-5f93-4354-8422-a634ba2213e4','代村中老人答','李端','唐','唐诗','tang','','[]','京洛風塵後，村鄉煙火稀。',48,'全唐诗/poet.tang.15000.json','["京洛風塵後，村鄉煙火稀。", "少年曾失所，衰暮欲何依。", "夜靜臨江哭，天寒踏雪歸。", "時清應不見，言罷淚盈衣。"]'),
('1c37df28-5999-4773-bc0a-5927ec7a278f','贈故將軍','李端','唐','唐诗','tang','','[]','平生在邊日，鞍馬若星流。',48,'全唐诗/poet.tang.15000.json','["平生在邊日，鞍馬若星流。", "獨出間千里，相知滿九州。", "恃功凌主將，作氣見王侯。", "誰道廉頗老，猶能報遠讐。"]'),
('49676c14-b0aa-4ff9-b221-0479c049aa25','送陸郎中歸田司空幕','李端','唐','唐诗','tang','','[]','漢家分列宿，東土佐諸侯。',48,'全唐诗/poet.tang.15000.json','["漢家分列宿，東土佐諸侯。", "結束還軍府，光輝過御溝。", "農桑連紫陌，分野入青州。", "覆被恩難報，西看成白頭。"]'),
('7b4af0a9-b307-4092-bb74-859934b5e429','酬晉侍御見寄','李端','唐','唐诗','tang','','[]','野客蒙詩贈，殊恩欲報難。',48,'全唐诗/poet.tang.15000.json','["野客蒙詩贈，殊恩欲報難。", "本求文舉識，不在子真官。", "細雨雙林暮，重陽九日寒。", "貧齋一叢菊，願與上賓看。"]'),
('ae54e684-8316-4298-b04d-1ad47322262b','送銅澤王歸城','李端','唐','唐诗','tang','','[]','昔聞公族出，其從亦高車。',48,'全唐诗/poet.tang.15000.json','["昔聞公族出，其從亦高車。", "爲善唯求樂，分貧必及疎。", "身承漢枝葉，手習魯詩書。", "尚說無功德，三年在石渠。"]'),
('0ce098bc-1f0b-4e01-95fb-d0eba63ef813','江上別柳中庸','李端','唐','唐诗','tang','','[]','秦人江上見，握手便霑衣。',48,'全唐诗/poet.tang.15000.json','["秦人江上見，握手便霑衣。", "近日相知少，往年親故稀。", "遠遊何處去，舊業幾時歸。", "更向巴陵宿，堪聞雁北飛。"]'),
('9345bb4c-1059-4af4-9c1e-c75839490a66','喜皇甫郎中拜諭德兼集賢學士','李端','唐','唐诗','tang','','[]','爲郎三載後，寵命一朝新。',48,'全唐诗/poet.tang.15000.json','["爲郎三載後，寵命一朝新。", "望苑遷詞客，儒林拜丈人。", "鶯飛綺閣曙，柳拂畫堂春。", "幾日調金鼎，諸君欲望塵。"]'),
('4e114210-7201-44d1-a969-2afc1146136c','送黎兵曹往陝府結婚','李端','唐','唐诗','tang','','[]','東方發車騎，君是上頭人。',48,'全唐诗/poet.tang.15000.json','["東方發車騎，君是上頭人。", "奠雁逢良日，行媒及仲春。", "時稱渡河婦，宜配坦牀賓。", "安得同門吏，揚鞭入後塵。"]'),
('e8b648ab-64a5-4200-9a19-f721ca120ffb','送竇兵曹','李端','唐','唐诗','tang','','[]','梨花開上苑，遊女著羅衣。',48,'全唐诗/poet.tang.15000.json','["梨花開上苑，遊女著羅衣。", "聞道情人怨，應須走馬歸。", "御橋遲日暖，官渡早鶯稀。", "莫遣佳期過，看看蝴蝶飛。"]'),
('f66715b5-7e80-4014-acb6-6bed68d6a4f4','留別故人','李端','唐','唐诗','tang','','[]','此別不可道，此心當語誰。',48,'全唐诗/poet.tang.15000.json','["此別不可道，此心當語誰。", "春風灞水上，飲馬桃花時。", "誤作好文士，祗應遊宦遲。", "留書下朝客，我有故山期。"]'),
('aa6ff7f8-433b-4dc6-b98f-d78991d0b06f','奉送宋中丞使河源','李端','唐','唐诗','tang','','[]','東周遣戍役，才子欲離羣。',48,'全唐诗/poet.tang.15000.json','["東周遣戍役，才子欲離羣。", "部領河源去，悠悠隴水分。", "笳聲悲塞草，馬首渡關雲。", "辛苦逢炎熱，何時及漢軍。"]'),
('89a5fd37-28dd-45c0-8b3f-b9165559b092','都亭驛送郭判官之幽州幕府','李端','唐','唐诗','tang','','[]','幕府參戎事，承明伏奏歸。',48,'全唐诗/poet.tang.15000.json','["幕府參戎事，承明伏奏歸。", "都亭使者出，杯酒故人違。", "細雨霑官騎，輕風拂客衣。", "還從大夫後，吾黨亦光輝。"]'),
('afe5ec61-08a5-47a6-8e03-dd06e917592b','送王羽林往秦州','李端','唐','唐诗','tang','','[]','秦州貴公子，漢日羽林郎。',48,'全唐诗/poet.tang.15000.json','["秦州貴公子，漢日羽林郎。", "事主來中禁，榮親上北堂。", "輶車花擁路，寶劒雪生光。", "直掃三邊靖，承恩向建章。"]'),
('afb2ce80-73ac-47b6-bc68-bbcb083c31a3','送友入關','李端','唐','唐诗','tang','','[]','聞君帝城去，西望一沾巾。',48,'全唐诗/poet.tang.15000.json','["聞君帝城去，西望一沾巾。", "落日見秋草，暮年逢故人。", "非才長作客，有命懶謀身。", "近更嬰衰疾，空思老漢濱。"]'),
('9b8d0786-3a7f-4231-8180-2e7706ef4fc8','代宗輓歌','李端','唐','唐诗','tang','','[]','祖庭三獻罷，嚴衞百靈朝。',48,'全唐诗/poet.tang.15000.json','["祖庭三獻罷，嚴衞百靈朝。", "警蹕移前殿，宮車上渭橋。", "寒霜凝羽葆，野吹咽笳簫。", "已向新京兆，誰云天路遙。"]'),
('58dc279b-eebd-40eb-8ab6-ff1401504150','張左丞輓歌二首 一','李端','唐','唐诗','tang','','[]','素斾低寒水，清笳出曉風。',48,'全唐诗/poet.tang.15000.json','["素斾低寒水，清笳出曉風。", "鳥來傷賈傅，馬立葬滕公。", "松柏青山上，城池白日中。", "一朝今古隔，唯有月明同。"]'),
('2eb64614-d5a4-43a5-a796-a485efaeaced','張左丞輓歌二首 二','李端','唐','唐诗','tang','','[]','禍集鉤方失，災生劒忽飛。',48,'全唐诗/poet.tang.15000.json','["禍集鉤方失，災生劒忽飛。", "無由就日拜，空憶自天歸。", "門吏看還葬，宮官識賜衣。", "東堂哀贈畢，從此故臣稀。"]'),
('fc44e3c3-935e-466d-9741-9fdffaaccba6','奉和王元二相避暑懷杜太尉','李端','唐','唐诗','tang','','[]','艱難嘗共理，海晏更相悲。',48,'全唐诗/poet.tang.15000.json','["艱難嘗共理，海晏更相悲。", "況復登堂處，分明避暑時。", "綠槐千穗綻，丹藥一番遲。", "蓬蓽今何幸，先朝大雅詩。"]'),
('f92902f3-cfd7-4e89-bfec-3d439a6bf9b8','青龍寺題故曇上人房','李端','唐','唐诗','tang','','[]','遠公留故院，一徑雪中微。',48,'全唐诗/poet.tang.15000.json','["遠公留故院，一徑雪中微。", "童子逢皆老，門人問亦稀。", "飜經徒有處，攜履遂無歸。", "空念尋巢鶴，時來傍影飛。"]'),
('85eadf60-2f98-41b2-88bf-b6337fa120e4','早春夜望','李端','唐','唐诗','tang','','[]','舊雪逐泥沙，新雷發草芽。',48,'全唐诗/poet.tang.15000.json','["舊雪逐泥沙，新雷發草芽。", "曉霜應傍鬢，夜雨莫催花。", "行矣前途晚，歸歟故國賒。", "不勞報春盡，從此惜年華。"]'),
('7c0ba3e7-f201-4fa9-8caa-ff18105e927a','宴伊東岸','李端','唐','唐诗','tang','','[]','晴洲無遠近，一樹一潭春。',48,'全唐诗/poet.tang.15000.json','["晴洲無遠近，一樹一潭春。", "芳草留歸騎，朱櫻擲舞人。", "空花對酒落，小翠隔林新。", "竟日皆攜手，何由遇此辰。"]'),
('e4c2627a-cb2c-427e-a74c-e753682fa41c','雲際中峰居喜見苗發','李端','唐','唐诗','tang','','[]','自得中峰住，深林亦閉關。',48,'全唐诗/poet.tang.15000.json','["自得中峰住，深林亦閉關。", "經秋無客到，入夜有僧還。", "暗澗泉聲小，荒村樹影閑。", "高窗不可望，星月滿空山。"]'),
('e81493d1-0362-481b-9249-42674555c65c','宿洞庭','李端','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','白水連天暮，洪波帶日流。',48,'全唐诗/poet.tang.15000.json','["白水連天暮，洪波帶日流。", "風高雲夢夕，月滿洞庭秋。", "沙上漁人火，煙中賈客舟。", "西園與南浦，萬里共悠悠。"]'),
('24d4eccc-5f8b-483a-81ff-f610464ab4ea','江上賽神','李端','唐','唐诗','tang','','["\u957f\u6c5f"]','疎鼓應繁絲，送神歸九疑。',48,'全唐诗/poet.tang.15000.json','["疎鼓應繁絲，送神歸九疑。", "蒼龍隨赤鳳，帝子上天時。", "驟雨歸山疾，長江下日遲。", "獨憐遊宦子，今夜泊天涯。"]'),
('39fdb908-0035-476f-b871-31447e4f7af1','奉和元丞侍從遊南城別業','李端','唐','唐诗','tang','','[]','垂朱領孫子，從宴在池塘。',48,'全唐诗/poet.tang.15000.json','["垂朱領孫子，從宴在池塘。", "獻壽回龜顧，和羹躍鯉香。", "高松先草晚，平石助泉涼。", "餘橘期相及，門生有陸郎。"]'),
('4b6f6d7f-30d6-4ca9-955c-d5afe32401bb','送從舅成都丞廣南歸蜀','李端','唐','唐诗','tang','','[]','巴字天邊水，秦人去是歸。',48,'全唐诗/poet.tang.15000.json','["巴字天邊水，秦人去是歸。", "棧長山雨響，溪亂火田稀。", "俗富行應樂，官雄祿豈微。", "魏舒終有淚，還濕甯家衣。"]'),
('d119e9a6-56b9-499a-a23a-3e76c0a12e99','贈郭駙馬 一','李端','唐','唐诗','tang','','[]','青春都尉最風流，二十功成便拜侯。',64,'全唐诗/poet.tang.15000.json','["青春都尉最風流，二十功成便拜侯。", "金距鬬雞過上苑，玉鞭騎馬出長楸。", "熏香荀令偏憐少，傅粉何郎不解愁。", "日暮吹簫楊柳陌，路人遙指鳳凰樓。"]'),
('19a1494a-7c0a-4513-a828-6443abe9db0a','贈郭駙馬 二','李端','唐','唐诗','tang','','[]','方塘似鏡草芊芊，初月如鉤未上弦。',64,'全唐诗/poet.tang.15000.json','["方塘似鏡草芊芊，初月如鉤未上弦。", "新開金埒看調馬，舊賜銅山許鑄錢。", "楊柳入樓吹玉笛，芙蓉出水妬花鈿。", "今朝都尉如相顧，願脫長裾學少年。"]'),
('e7b59ce3-5d91-4ee2-b8ef-32416721d445','宿淮浦憶司空文明','李端','唐','唐诗','tang','','[]','愁心一倍長離憂，夜思千重戀舊遊。',64,'全唐诗/poet.tang.15000.json','["愁心一倍長離憂，夜思千重戀舊遊。", "秦地故人成遠夢，楚天涼雨在孤舟。", "諸溪近海潮皆應，獨樹邊淮葉盡流。", "別恨轉深何處寫，前程唯有一登樓。"]'),
('898151bf-b3b7-4387-b41c-f56da1575e2e','送濮陽錄事赴忠州','李端','唐','唐诗','tang','','[]','成名不遂雙旌遠，主印還爲一郡雄。',64,'全唐诗/poet.tang.15000.json','["成名不遂雙旌遠，主印還爲一郡雄。", "赤葉黃花隨野岸，青山白水映江楓。", "巴人夜語孤舟裏，越鳥春啼萬壑中。", "聞說古書多未校，肯令才子久西東。"]'),
('a35d2a45-1ce1-4455-a251-7398f204aecd','送馬尊師','李端','唐','唐诗','tang','','[]','南入商山松路深，石牀溪水晝陰陰。',64,'全唐诗/poet.tang.15000.json','["南入商山松路深，石牀溪水晝陰陰。", "雲中採藥隨青節，洞裏耕田映綠林。", "直上煙霞空舉手，迴經丘壠自傷心。", "武陵花木應長在，願與漁人更一尋。"]'),
('72e511e9-1a49-4cf9-a2fe-c5456af41343','題元注林園','李端','唐','唐诗','tang','','[]','謝家門館似山林，碧石青苔滿樹陰。',64,'全唐诗/poet.tang.15000.json','["謝家門館似山林，碧石青苔滿樹陰。", "乳鵲眄巢花巷靜，鳴鳩鼓翼竹園深。", "桔槔轉水兼通藥，方丈留僧共聽琴。", "獨有野人箕踞慣，過君始得一長吟。"]'),
('39640e40-b5f6-4ca0-8106-235b98251880','野寺病居喜盧綸見訪','李端','唐','唐诗','tang','','[]','青青麥壠白雲陰，古寺無人新草深。',64,'全唐诗/poet.tang.15000.json','["青青麥壠白雲陰，古寺無人新草深。", "乳燕拾泥依古井，鳴鳩拂羽歷花林。", "千年駁蘚明山履，萬尺垂蘿入水心。", "一臥漳濱今欲老，誰知才子忽相尋。"]'),
('9b9e4720-2ced-46a8-8cd2-be4575f67658','送皎然上人歸山','李端','唐','唐诗','tang','','[]','適來世上豈緣名，適去人間豈爲情。',64,'全唐诗/poet.tang.15000.json','["適來世上豈緣名，適去人間豈爲情。", "古寺山中幾日到，高松月下一僧行。", "雲陰鳥道苔方合，雪映龍潭水更清。", "法主欲歸須有說，門人流淚厭浮生。"]'),
('97d8a9f6-e9da-443f-8e24-4003ee81123e','贈道士','李端','唐','唐诗','tang','','[]','姓氏不書高士傳，形神自得逸人風。',64,'全唐诗/poet.tang.15000.json','["姓氏不書高士傳，形神自得逸人風。", "已傳花洞將秦接，更指茅山與蜀通。", "嬾說歲年齊絳老，甘爲鄉曲號涪翁。", "終朝賣卜無人識，敝服徒行入市中。"]'),
('7943654f-0f18-46ff-a747-e667525eb8f2','題雲際寺準上人房','李端','唐','唐诗','tang','','[]','高僧居處似天台，錫杖銅瓶對綠苔。',64,'全唐诗/poet.tang.15000.json','["高僧居處似天台，錫杖銅瓶對綠苔。", "竹巷雨晴春鳥囀，山房日午老人來。", "園中鹿過椒枝動，潭底龍遊水沫開。", "獨夜焚香禮遺像，空林月出始應迴。"]'),
('e83897d9-af00-4337-bd76-3679065976e9','山中寄苗員外','李端','唐','唐诗','tang','','[]','鳥鳴花發空山裏，衡岳幽人藉草時。',64,'全唐诗/poet.tang.15000.json','["鳥鳴花發空山裏，衡岳幽人藉草時。", "既近淺流安筆硯，還因平石布蓍龜。", "千尋楚水橫琴望，萬里秦城帶酒思。", "聞說潘安方寓直，與君相見漸難期。"]'),
('855456e2-f8a8-4344-b207-b764395bda19','憶故山贈司空曙','李端','唐','唐诗','tang','','[]','漢主金門正召才，馬卿多病自遲迴。',64,'全唐诗/poet.tang.15000.json','["漢主金門正召才，馬卿多病自遲迴。", "舊山蹔別老將至，芳草欲闌歸去來。", "雲在高天風會起，年如流水日長催。", "知君素有棲禪意，歲晏蓬門遲爾開。"]'),
('eb090f98-6185-4fba-8fe0-6bb295821b61','閑園即事贈考功王員外','李端','唐','唐诗','tang','','[]','南陌晴雲稍變霞，東風動柳水紋斜。',64,'全唐诗/poet.tang.15000.json','["南陌晴雲稍變霞，東風動柳水紋斜。", "園林帶雪潛生草，桃李雖春未有花。", "幸接上賓登鄭驛，羞爲長女似黃家。", "今朝一望還成暮，欲別芳菲戀歲華。"]'),
('c23fcb9d-ed9e-4289-b0bb-c54e2b39ca6e','寄廬山真上人','李端','唐','唐诗','tang','','["\u5e90\u5c71"]','高僧無跡本難尋，更得禪行去轉深。',66,'全唐诗/poet.tang.15000.json','["高僧無跡本難尋，更得禪行去轉深。", "青草湖中看五老，白雲山上宿雙林。", "月明潭色澄空性，夜靜猨聲證道心。", "更[說謝]公南座好，煙蘿到地幾重陰。"]'),
('a5280a77-ac56-47b6-b489-76f03fc8fb5a','題覺公新蘭若','李端','唐','唐诗','tang','','[]','頭白禪師何處還，獨開蘭若樹林間。',64,'全唐诗/poet.tang.15000.json','["頭白禪師何處還，獨開蘭若樹林間。", "鬼因巫祝傳移社，神見天人請施山。", "猛虎聽經金磬動，獼猴獻蜜雪窗閒。", "新齋結誓如相許，願與雷宗永閉關。"]'),
('57de89d2-d4bc-4d67-b88a-2cea34883ed5','贈道者','李端','唐','唐诗','tang','','[]','窗中忽有鶴飛聲，方士因知道欲成。',48,'全唐诗/poet.tang.15000.json','["窗中忽有鶴飛聲，方士因知道欲成。", "來取圖書安枕裏，便驅雞犬向山行。", "花開深洞仙門小，路過懸橋羽節輕。"]'),
('a15caa6f-dbca-4eec-8445-a1ece443d115','代棄婦答賈客','李端','唐','唐诗','tang','','[]','玉壘城邊爭走馬，銅鞮市裏共乘舟。',64,'全唐诗/poet.tang.15000.json','["玉壘城邊爭走馬，銅鞮市裏共乘舟。", "鳴環動珮恩無盡，掩袖低巾淚不流。", "疇昔將歌邀客醉，如今欲舞對君羞。", "忍懷賤妾平生曲，獨上襄陽舊酒樓。"]'),
('668bda10-2fcd-45a3-9795-a8393e22ae00','和李舍人直中書對月見寄','李端','唐','唐诗','tang','','[]','名卿步月正淹留，上客裁詩怨別遊。',64,'全唐诗/poet.tang.15000.json','["名卿步月正淹留，上客裁詩怨別遊。", "素魄近成班女扇，清光遠似庾公樓。", "嬋娟更稱凭高望，皎潔能傳自古愁。", "盈手入懷皆不見，陽春曲麗轉難酬。"]'),
('62ecb6aa-2aeb-41c1-9b6c-78784005f52d','臥病聞吉中孚拜官寄元秘書昆季','李端','唐','唐诗','tang','','[]','漢家採使不求聲，自慰文章道欲行。',64,'全唐诗/poet.tang.15000.json','["漢家採使不求聲，自慰文章道欲行。", "毛遂登門雖異賞，韓非入傳濫齊名。", "雲歸暫愛青山出，客去還愁白髮生。", "年少奉親皆願達，敢將心事向玄成。"]'),
('967ac6e2-b5ec-4d6c-b3e3-51ed1e9711d6','江上逢柳中庸','李端','唐','唐诗','tang','','["\u8861\u5c71"]','舊住衡山曾夜歸，見君江客憶荆扉。',64,'全唐诗/poet.tang.15000.json','["舊住衡山曾夜歸，見君江客憶荆扉。", "星沉嶺上人行早，月過湖西鶴唳稀。", "弱竹萬株頻礙幘，新泉數步一褰衣。", "今來唯有禪心在，鄉路翻成向翠微。"]'),
('3fa3ea71-5f33-42c7-8b83-2b96734e20cd','戲贈韓判官紳卿','李端','唐','唐诗','tang','','[]','少尋道士居嵩嶺，晚事高僧住沃洲。',64,'全唐诗/poet.tang.15000.json','["少尋道士居嵩嶺，晚事高僧住沃洲。", "齒發未知何處老，身名且被外人愁。", "欲隨山水居茅洞，已有田園在虎丘。", "獨怪子猷緣掌馬，雪時不肯更乘舟。"]'),
('86e50e91-b337-47f9-bfee-4899b4ac4a84','送周長史','李端','唐','唐诗','tang','','[]','青楓樹裏宣城郡，獨佐諸侯上板橋。',64,'全唐诗/poet.tang.15000.json','["青楓樹裏宣城郡，獨佐諸侯上板橋。", "江客亦能傳好信，山僧多解說南朝。", "雲陰出浦看帆小，草色連天見雁遙。", "別有空園落桃杏，知將絲組繫蘭橈。"]'),
('fad6b3e0-61b6-4182-a4f5-2076f8cb940d','題故將軍莊','李端','唐','唐诗','tang','','[]','曾將數騎過桑乾，遙對單于飭馬鞍。',64,'全唐诗/poet.tang.15000.json','["曾將數騎過桑乾，遙對單于飭馬鞍。", "塞北征兒諳用劍，關西宿將許登壇。", "田園蕪沒歸耕晚，弓箭開離出獵難。", "唯有老身如刻畫，猶期聖主解衣看。"]'),
('b8b54726-0666-42fb-82ea-f60b2deff99c','夜投豐德寺謁海上人','李端','唐','唐诗','tang','','[]','半夜中峰有磬聲，偶尋樵者問山名。',64,'全唐诗/poet.tang.15000.json','["半夜中峰有磬聲，偶尋樵者問山名。", "上方月曉聞僧語，下界林疎見客行。", "野鶴巢邊松最老，毒龍潛處水偏清。", "願得遠山知姓字，焚香洗鉢過餘生。"]'),
('8d1f6a8f-dd04-4527-a631-86238208076f','塞上','李端','唐','唐诗','tang','','[]','二十在邊城，軍中得勇名。',72,'全唐诗/poet.tang.15000.json','["二十在邊城，軍中得勇名。", "卷旗收敗馬，占磧擁殘兵。", "覆陣烏鳶起，燒山草木明。", "塞閑思遠獵，師老厭分營。", "雪嶺無人跡，冰河足雁聲。", "李陵甘此沒，惆悵漢公卿。"]'),
('fbc48a2e-dbd3-4862-8c5d-8e979f418df7','送彭將軍雲中覲兄','李端','唐','唐诗','tang','','[]','聞說蒼鷹守，今朝欲下韛。',72,'全唐诗/poet.tang.15000.json','["聞說蒼鷹守，今朝欲下韛。", "因令白馬將，兼道覓封侯。", "略地關山冷，防河雨雪稠。", "飜弓騁猨臂，承箭惜貂裘。", "設伏軍謀密，坑降塞邑愁。", "報恩唯有死，莫使漢家羞。"]'),
('0229d4a7-2410-41e2-ab77-0022f9a70c38','奉贈苗員外','李端','唐','唐诗','tang','','[]','朱戶敞高扉，青槐礙落暉。',72,'全唐诗/poet.tang.15000.json','["朱戶敞高扉，青槐礙落暉。", "八龍承慶重，三虎遞朝歸。", "坐竹人聲絕，橫琴鳥語稀。", "花慙潘岳貌，年稱老萊衣。", "葉暗新櫻熟，絲長粉蝶飛。", "應憐魯儒賤，空與故山違。"]'),
('a76e84bc-e1e1-459a-90bb-e2185b4a4ba3','酬丘拱外甥覽余舊文見寄','李端','唐','唐诗','tang','','[]','丘遲本才子，始冠即周旋。',120,'全唐诗/poet.tang.15000.json','["丘遲本才子，始冠即周旋。", "舅乏郄鑒愛，君如衞玠賢。", "禮將金友等，情向玉人偏。", "鄙俗那勞似，龍鍾却要憐。", "投甎聊取笑，贈綺一何妍。", "野坐臨黃菊，溪行踏綠錢。", "巖高雲反下，洞黑水潛穿。", "僻嶺猿偷栗，枯池雁唼蓮。", "身居霞外寺，思發月明田。", "猶恨縈塵網，昏昏過幾年。"]'),
('d60bd6be-1b14-4468-8178-3c55883594d5','贈岐山姜明府','李端','唐','唐诗','tang','','[]','昨夜聞山雨，歸心便似遲。',132,'全唐诗/poet.tang.15000.json','["昨夜聞山雨，歸心便似遲。", "幾迴驚葉落，即到白頭時。", "雁影將魂去，蟲聲與淚期。", "馬卿兼病老，宋玉對秋悲。", "謝客纔爲別，陶公已見思。", "非關口腹累，自是雪霜姿。", "釀酒栽黃菊，炊粳折綠葵。", "山河方入望，風日正宜詩。", "牧豎寒騎馬，邊烽晚立旗。", "蘭凋猶有氣，柳脆不成絲。", "別後如相問，高僧知所之。"]'),
('a90c22c3-4ea6-4839-b4c1-f01f10e03d19','下第上薛侍郎','李端','唐','唐诗','tang','','[]','蓬蓽春風起，開簾却自悲。',96,'全唐诗/poet.tang.15000.json','["蓬蓽春風起，開簾却自悲。", "如何飄梗處，又到採蘭時。", "明鏡方重照，微城寄一辭。", "家貧求祿早，身賤報恩遲。", "幸得皮存矣，須勞翼長之。", "銘肌非厚荅，肉骨是前期。", "縱覺新人好，寧忘舊主疑。", "終慙太丘道，不爲小生私。"]'),
('03b478b1-bef3-4398-ab4d-02f480749554','奉和秘書元丞杪秋憶終南舊居','李端','唐','唐诗','tang','','[]','高門有才子，能履古人蹤。',96,'全唐诗/poet.tang.15000.json','["高門有才子，能履古人蹤。", "白社陶元亮，青雲阮仲容。", "田園忽歸去，車馬杳難逢。", "廢巷臨秋水，支頤向暮峰。", "行魚避楊柳，驚鴨觸芙蓉。", "石竇紅泉細，山橋紫菜重。", "鳳雛終食竹，鶴侶暫巢松。", "願接煙霞賞，羈離計不從。"]'),
('bd2ab416-81a4-4e12-a9b4-1dec6b86ac43','送歸中丞使新羅','李端','唐','唐诗','tang','','[]','東望扶桑日，何年是到時。',72,'全唐诗/poet.tang.15000.json','["東望扶桑日，何年是到時。", "片帆通雨露，積水隔華夷。", "浩淼風來遠，虛冥鳥去遲。", "長波靜雲月，孤島宿旌旗。", "別葉傳秋意，迴潮動客思。", "滄溟無舊路，何處問前期。"]'),
('b6283b73-915a-4959-8579-19cc7e057f69','暮春尋終南柳處士','李端','唐','唐诗','tang','','[]','龐眉一居士，鶉服隱堯時。',72,'全唐诗/poet.tang.15000.json','["龐眉一居士，鶉服隱堯時。", "種荳初成畝，還丹舊日師。", "入溪花徑遠，向嶺鳥行遲。", "紫葛垂苔壁，青菰映柳絲。", "偶來塵外事，暫與素心期。", "終恨遊春宮，同爲歲月悲。"]'),
('29913307-4c08-4df9-baa4-89954f13172a','雪夜尋太白道士','李端','唐','唐诗','tang','','[]','雪路夜朦朧，尋師杏樹東。',96,'全唐诗/poet.tang.15000.json','["雪路夜朦朧，尋師杏樹東。", "石壇連竹靜，醮火照山紅。", "再拜開金籙，焚香使玉童。", "篷瀛三島至，天地一壺通。", "別客曾留藥，逢舟或借風。", "出遊居鶴上，避禍入羊中。", "過洞偏迴首，登門未發蒙。", "桑田如可見，滄海幾時空。"]'),
('18970206-4b28-4c5e-974f-a9ef44cbc9a7','得山中道友書寄苗銭二員外','李端','唐','唐诗','tang','','[]','有謀皆轗軻，非病亦遲迴。',120,'全唐诗/poet.tang.15000.json','["有謀皆轗軻，非病亦遲迴。", "壯志年年減，馳暉日日催。", "還山不及伴，到闕又無媒。", "高臥成長策，微官稱下才。", "詩人識何謝，居士別宗雷。", "跡向塵中隱，書從谷口來。", "藥欄遭鹿踐，澗戶被猿開。", "野鶴巢雲竇，遊龜上水苔。", "新歡追易失，故思渺難裁。", "自有歸期在，勞君示劫灰。"]'),
('1912131c-ca0a-497b-86b8-c4ce48a644a0','酬前駕部員外郎苗發','李端','唐','唐诗','tang','','[]','馬融方直校，閱簡復持鉛。',120,'全唐诗/poet.tang.15000.json','["馬融方直校，閱簡復持鉛。", "素業高風繼，青春壯思全。", "論文多在夜，宿寺不虛年。", "自署區中職，同荒郭外田。", "山鄰三徑絕，野意八行傳。", "煮玉矜新法，留符識舊仙。", "涵苔溪溜淺，搖浪竹橋懸。", "複洞潛棲燕，疎楊半翳蟬。", "詠歌雖有和，雲錦獨成妍。", "應以馮唐老，相譏示此篇。"]'),
('4eadc463-caa7-4df0-ac58-a91ae885fe42','宿薦福寺東池有懷故園因寄元校書','李端','唐','唐诗','tang','','[]','暮雨風吹盡，東池一夜涼。',168,'全唐诗/poet.tang.15000.json','["暮雨風吹盡，東池一夜涼。", "伏流迴弱荇，明月入垂楊。", "石竹閒開碧，薔薇暗吐黃。", "倚琴看鶴舞，搖扇引桐香。", "舊筍方辭籜，新蓮未滿房。", "林幽花晚發，地遠草先長。", "撫枕愁華鬢，凭欄想故鄉。", "露餘清漢直，雲卷白榆行。", "驚鵲仍依樹，遊魚不過粱。", "繫舟偏憶戴，炊黍願期張。", "末路還思借，前恩詎敢忘。", "從來叔夜嬾，非是接輿狂。", "衆病嬰公幹，羣憂集孝璋。", "慙將多誤曲，今日獻周郎。"]'),
('d047c01e-d574-42f8-a69e-b246ecc3c20d','送王副使還幷州','李端','唐','唐诗','tang','','[]','幷州近胡地，此去事風沙。',72,'全唐诗/poet.tang.15000.json','["幷州近胡地，此去事風沙。", "鐵馬垂金絡，貂裘犯雪花。", "曾持兩郡印，多比五侯家。", "繼世新恩厚，從軍舊國賒。", "戍煙千里直，邊雁一行斜。", "想到清油幕，長謀出左軍。"]'),
('73ee65f1-307b-4978-bc2e-61918e3c6652','晚春过夏侯校書值其沉醉戲贈','李端','唐','唐诗','tang','','[]','欹冠枕如意，獨寢落花前。',168,'全唐诗/poet.tang.15000.json','["欹冠枕如意，獨寢落花前。", "姚馥清時醉，邊韶白日眠。", "曝褌還當屋，張幕便成天。", "謁客唯題鳳，偷兒欲覘氈。", "失杯猶離席，墜履反登筵。", "本是牆東隱，今爲甕下僊。", "臥龍髯乍磔，栖蝶腹何便。", "阮籍供琴韻，陶潛餘秫田。", "人逢轂陽望，春似永和年。", "願我非工飲，期君行見憐。", "嘗知渴羌好，亦覺醉胡賢。", "炙熟樽方竭，車回轄且全。", "噀風仍作雨，灑地即成泉。", "自鄙新豐過，遲迴惜十年。"]'),
('826e14b6-7575-46f7-86f5-444474771d12','哭張南史因寄南史姪叔宗','李端','唐','唐诗','tang','','[]','爭路忽摧車，沈鉤未得魚。',96,'全唐诗/poet.tang.15000.json','["爭路忽摧車，沈鉤未得魚。", "結交唯我少，喪舊自君初。", "諫草文難似，圍棊智不如。", "仲宣新有賦，叔夜近無書。", "地閉滕公宅，山荒謝客廬。", "殲良從此恨，福善竟成虛。", "釀酒多同醉，烹雞或取餘。", "阮咸雖永別，豈共仲容疎。"]'),
('13bedf8d-9714-4c81-99a6-4de25b2e9845','長安感事呈盧綸','李端','唐','唐诗','tang','','[]','十五事文翰，大兒輕孔融。',240,'全唐诗/poet.tang.15000.json','["十五事文翰，大兒輕孔融。", "長裾遊邸第，笑傲五侯中。", "諫獵一朝寢，論邊素未工。", "蹉跎潘鬢至，蹭蹬阮途窮。", "貸布憐寧興，無金命未通。", "王陵固似戇，郭最遂非雄。", "斂板辭羣彥，回車訪老農。", "詠詩懷洛下，送客憶山東。", "沈病魂神濁，清齋思慮空。", "羸將衞玠比，冷共鄴侯同。", "草舍纔遮雨，荆窗不礙風。", "梨教通子守，酒是遠師供。", "捫虱欣時泰，迎猫達歲豐。", "原門唯有席，井飲但加葱。", "少壯衿齊德，高年覺宋聾。", "寓書先論嬾，讀易反求蒙。", "昔慕能鳴雁，今憐半死桐。", "秉心猶似矢，搔首忽如蓬。", "赤葉翻藤架，黃花蓋菊叢。", "聊將呈匠伯，今已學愚公。"]'),
('a13d5995-b530-465b-84bc-b3c847dd1c44','遊終南山因寄蘇奉禮士尊師苗員外','李端','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','半嶺逢仙駕，清晨獨採芝。',108,'全唐诗/poet.tang.15000.json','["半嶺逢仙駕，清晨獨採芝。", "壺中開白日，霧裏捲朱旂。", "猨鳥知歸路，松蘿見會時。", "雞聲傳洞遠，鶴語報家遲。", "童子閑驅石，樵夫樂看棊。", "依稀醉後拜，恍惚夢中辭。", "海上終難接，人間益自疑。", "風塵甘獨老，山水但相思。", "願得燒丹訣，流沙永待師。"]'),
('017cc40c-e1e0-492e-9e35-f19cb643ad13','長安書事寄盧綸','李端','唐','唐诗','tang','','[]','弱冠家廬岳，從師歲月深。',120,'全唐诗/poet.tang.15000.json','["弱冠家廬岳，從師歲月深。", "翻同老夫見，殊寡少年心。", "及此時方晏，因之名亦沈。", "趨途非要路，避事樂空林。", "素業在山下，青泉當樹陰。", "交遊有凋喪，離別代追尋。", "向秀初聞笛，鍾期久罷琴。", "殘愁猶滿貌，餘淚可霑襟。", "勿以朱顏好，而忘白髮侵。", "終期入靈洞，相與鍊黃金。"]'),
('999dbf81-f5a8-4f71-87b3-54bd70dbeab0','送郭良輔下第東歸','李端','唐','唐诗','tang','','[]','獻策不得意，馳車東出秦。',24,'全唐诗/poet.tang.15000.json','["獻策不得意，馳車東出秦。", "暮年千里客，落日萬家春。"]'),
('9816ff60-fc81-4291-8d05-cad5e5541933','妾薄命','李端','唐','唐诗','tang','','[]','自從君棄妾，憔悴不羞人。',24,'全唐诗/poet.tang.15000.json','["自從君棄妾，憔悴不羞人。", "唯餘壞粉淚，未免映衫勻。"]'),
('d7ca2c1c-1daa-495e-9796-f1e31472bdb2','送暕上人遊春','李端','唐','唐诗','tang','','[]','獨將支遁去，欲往戴顒家。',24,'全唐诗/poet.tang.15000.json','["獨將支遁去，欲往戴顒家。", "晴野人臨水，春山樹發花。"]'),
('69fc549b-654d-4ce7-8de6-8b9b6d6bd895','晦日同苗員外遊曲江','李端','唐','唐诗','tang','','[]','晦日同攜手，臨流一望春。',24,'全唐诗/poet.tang.15000.json','["晦日同攜手，臨流一望春。", "可憐楊柳陌，愁殺故鄉人。"]'),
('2d822a7d-7393-42c5-9366-263c627b8403','溪行逢雨與柳中庸','李端','唐','唐诗','tang','','[]','日落衆山昏，蕭蕭暮雨繁。',24,'全唐诗/poet.tang.15000.json','["日落衆山昏，蕭蕭暮雨繁。", "那堪兩處宿，共聽一聲猨。"]'),
('8aa36cc8-fec9-455c-91b7-23fc83cdddb1','和張尹憶東籬菊','李端','唐','唐诗','tang','','[]','傳書報劉尹，何事憶陶家。',24,'全唐诗/poet.tang.15000.json','["傳書報劉尹，何事憶陶家。", "若爲籬邊菊，山中有此花。"]'),
('a0737190-4461-4ec7-b548-8b1534b87e47','幽居作','李端','唐','唐诗','tang','','[]','山舍千年樹，江亭萬里雲。',24,'全唐诗/poet.tang.15000.json','["山舍千年樹，江亭萬里雲。", "回潮迎伍相，驟雨送湘君。"]'),
('0b4365f7-5f12-44bf-aef1-b30e2762fe41','題雲際寺暕上人故院','李端','唐','唐诗','tang','','[]','白髮怱怱色，青山草草心。',24,'全唐诗/poet.tang.15000.json','["白髮怱怱色，青山草草心。", "遠公仍下世，從此別東林。"]'),
('7a9e58d6-e9a2-4b7a-87b1-25f114878049','觀鄰老栽松','李端','唐','唐诗','tang','','[]','雖過老人宅，不解老人心。',24,'全唐诗/poet.tang.15000.json','["雖過老人宅，不解老人心。", "何事殘陽裏，栽松欲待陰。"]'),
('5f9b6ea2-3e56-453a-9d39-5e9bef673fb9','贈胡居士','李端','唐','唐诗','tang','','[]','孔融過五十，海內故人稀。',24,'全唐诗/poet.tang.15000.json','["孔融過五十，海內故人稀。", "相府恩猶在，知君未拂衣。"]'),
('5ba05573-8aed-4481-8905-cabca7a82160','薦福寺送元偉','李端','唐','唐诗','tang','','[]','送客攀花後，尋僧坐竹時。',24,'全唐诗/poet.tang.15000.json','["送客攀花後，尋僧坐竹時。", "明朝莫回望，青草馬行遲。"]'),
('fc4c2a7c-919c-4f80-b76c-3e0f6623133c','哭苗垂','李端','唐','唐诗','tang','','[]','舊友無由見，孤墳草欲長。',24,'全唐诗/poet.tang.15000.json','["舊友無由見，孤墳草欲長。", "月斜鄰笛盡，車馬出山陽。"]'),
('1b3a08a6-de60-42f3-8b7b-bc949c34ad21','客行贈馮著','李端','唐','唐诗','tang','','[]','旅行雖別路，日暮各思歸。',24,'全唐诗/poet.tang.15000.json','["旅行雖別路，日暮各思歸。", "欲下今朝淚，知君亦濕衣。"]'),
('3c77e523-20ae-4f4d-a181-74127bbb9af0','蕪城','李端','唐','唐诗','tang','','[]','風吹城上樹，草沒城邊路。',24,'全唐诗/poet.tang.15000.json','["風吹城上樹，草沒城邊路。", "城裏月明時，精靈自來去。"]'),
('5a8459fb-eaeb-4ba3-8d3d-f12cbfe3f11c','贈山中老人','李端','唐','唐诗','tang','','[]','白首獨一身，青山爲四鄰。',24,'全唐诗/poet.tang.15000.json','["白首獨一身，青山爲四鄰。", "雖行故鄉陌，不見故鄉人。"]'),
('f166bcbd-1129-4a26-957a-30cd0f7d9389','拜新月','李端','唐','唐诗','tang','','["\u5199\u4eba", "\u6708\u4eae"]','開簾見新月，便即下階拜。',24,'全唐诗/poet.tang.15000.json','["開簾見新月，便即下階拜。", "細語人不聞，北風吹裙帶。"]'),
('7f3799de-78b4-49bc-b6d8-a5fa3ecacd33','聽箏','李端','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e94\u8a00\u7edd\u53e5", "\u97f3\u4e50"]','鳴箏金粟柱，素手玉房前。',24,'全唐诗/poet.tang.15000.json','["鳴箏金粟柱，素手玉房前。", "欲得周郎顧，時時誤拂弦。"]'),
('6144e081-33f1-4157-a71f-dad2502278d2','贈何兆','李端','唐','唐诗','tang','','[]','文章似揚馬，風骨又清羸。',24,'全唐诗/poet.tang.15000.json','["文章似揚馬，風骨又清羸。", "江漢君猶在，英靈信未衰。"]'),
('18e28a30-bd37-43c6-be88-a08d29b4f571','同司空文明過堅上人故院','李端','唐','唐诗','tang','','[]','我與雷居士，平生事遠公。',24,'全唐诗/poet.tang.15000.json','["我與雷居士，平生事遠公。", "無人知是舊，共到影堂中。"]'),
('889c97a7-a749-41f9-8441-2001b4b60fa9','雜詩','李端','唐','唐诗','tang','','[]','主第辭高飲，石家赴宵會。',24,'全唐诗/poet.tang.15000.json','["主第辭高飲，石家赴宵會。", "金谷走車來，玉人騎馬待。"]'),
('a7e75600-f50b-4254-a731-ea10c358b148','感興','李端','唐','唐诗','tang','','[]','香爐最高頂，中有高人住。',24,'全唐诗/poet.tang.15000.json','["香爐最高頂，中有高人住。", "日暮下山來，月明上山去。"]'),
('5d8662c6-50dd-419b-b0d6-bacb6a227026','問張山人疾','李端','唐','唐诗','tang','','[]','先生沈病意何如，蓬艾門前客轉疎。',32,'全唐诗/poet.tang.15000.json','["先生沈病意何如，蓬艾門前客轉疎。", "不見領徒過絳帳，唯聞與婢削丹書。"]'),
('64df610f-2fd8-479f-8ed5-8f87799e634d','江上送客','李端','唐','唐诗','tang','','[]','故人南去漢江陰，秋雨蕭蕭雲夢深。',32,'全唐诗/poet.tang.15000.json','["故人南去漢江陰，秋雨蕭蕭雲夢深。", "江上見人應下淚，由來遠客易傷心。"]'),
('4810005b-9113-452a-b336-caafe5709ebe','閨情','李端','唐','唐诗','tang','','[]','月落星稀天欲明，孤燈未滅夢難成。',32,'全唐诗/poet.tang.15000.json','["月落星稀天欲明，孤燈未滅夢難成。", "披衣更向門前望，不忿朝來鵲喜聲。"]'),
('bc8c1156-0d8f-4302-94c5-f63bc3a123dd','送劉侍郎','李端','唐','唐诗','tang','','[]','幾人同去謝宣城，未及酬恩隔死生。',32,'全唐诗/poet.tang.15000.json','["幾人同去謝宣城，未及酬恩隔死生。", "唯有夜猨知客恨，嶧陽溪路第三聲。"]'),
('81df0640-9a72-454b-89f9-8ed0008e9188','重送鄭宥歸蜀因寄何兆','李端','唐','唐诗','tang','','[]','黃花西上路何如，青壁連天雁亦疎。',32,'全唐诗/poet.tang.15000.json','["黃花西上路何如，青壁連天雁亦疎。", "爲報長卿休滌器，漢家思見茂陵書。"]'),
('d53959db-c139-454f-a061-f7604a37a823','宿石澗店聞婦人哭','李端','唐','唐诗','tang','','[]','山店門前一婦人，哀哀夜哭向秋雲。',32,'全唐诗/poet.tang.15000.json','["山店門前一婦人，哀哀夜哭向秋雲。", "自說夫因征戰死，朝來逢著舊將軍。"]'),
('14d2c040-c7ac-4485-b966-6de812cb7b32','與道者別','李端','唐','唐诗','tang','','[]','聞說滄溟今已淺，何當白鶴更歸來。',32,'全唐诗/poet.tang.15000.json','["聞說滄溟今已淺，何當白鶴更歸來。", "舊師唯有先生在，忍見門人掩淚回。"]'),
('954f3f46-87dd-4f9b-b656-d61dae5fb23b','長門怨','李端','唐','唐诗','tang','','[]','金壺漏盡禁門開，飛燕昭陽侍寢回。',32,'全唐诗/poet.tang.15000.json','["金壺漏盡禁門開，飛燕昭陽侍寢回。", "隨分獨眠秋殿裏，遙聞語笑自天來。"]'),
('a8be14f6-49ea-4e59-ad37-30bcf16e17a6','憶友懷野寺舊居','李端','唐','唐诗','tang','','[]','自嫌野性共人疎，憶向西林更結廬。',32,'全唐诗/poet.tang.15000.json','["自嫌野性共人疎，憶向西林更結廬。", "寄謝山陰許都講，昨來頻得遠公書。"]'),
('bee2baa5-b40f-4740-a10e-5633dc1250d8','聽夜雨寄盧綸','李端','唐','唐诗','tang','','[]','暮雨蕭條過鳳城，霏霏颯颯重還輕。',32,'全唐诗/poet.tang.15000.json','["暮雨蕭條過鳳城，霏霏颯颯重還輕。", "聞君此夜東林宿，聽得荷池幾番聲。"]'),
('4d30f7f4-44ac-4dbf-964e-723479e69e1f','昭君詞','李端','唐','唐诗','tang','','[]','李陵初送子卿回，漢月明時惆悵來。',32,'全唐诗/poet.tang.15000.json','["李陵初送子卿回，漢月明時惆悵來。", "憶著長安舊遊處，千門萬戶玉樓臺。"]'),
('ca03d740-e7bc-4cbc-9007-c59a3043d798','春晚游鶴林寺寄使府諸公','李端','唐','唐诗','tang','','[]','野寺尋春花已遲，背巖惟有兩三枝。',32,'全唐诗/poet.tang.15000.json','["野寺尋春花已遲，背巖惟有兩三枝。", "明朝攜酒猶堪醉，爲報春風且莫吹。"]'),
('d9d4c055-1dc0-4555-b180-979008c8d0f0','南充謝郡客遊澧州留贈宇文中丞','暢當','唐','唐诗','tang','','[]','僕本濩落人，辱當州郡使。',96,'全唐诗/poet.tang.15000.json','["僕本濩落人，辱當州郡使。", "量力頗及早，謝歸今即已。", "蕭蕭若凌虛，襟帶頓銷靡。", "車服率然來，涔陽作遊子。", "鬱鬱寡開顏，默默獨行李。", "忽逢平生友，一笑方在此。", "秋情寧風日，楚思浩雲水。", "爲語弋林者，冥冥鴻遠矣。"]'),
('ac2183df-331b-4594-a1dd-0498da05e189','宿報恩寺精舍','暢當','唐','唐诗','tang','','[]','鐘梵送沈景，星多露漸光。',72,'全唐诗/poet.tang.15000.json','["鐘梵送沈景，星多露漸光。", "風中蘭靡靡，月下樹蒼蒼。", "夜殿若山橫，深松如澗涼。", "羸然虎溪子，遲我一虛牀。", "杳杳空寂舍，濛濛蓮桂香。", "擁褐依西壁，紗燈靄中央。"]'),
('c0f6fbf7-0066-4d48-94bf-cb0c06c031a2','自平陽館赴郡','暢當','唐','唐诗','tang','','[]','晨興平陽館，見月沈江水。',96,'全唐诗/poet.tang.15000.json','["晨興平陽館，見月沈江水。", "溶溶山霧披，肅肅沙鷺起。", "奉恩謬符竹，伏軾省頑鄙。", "何當施教化，愧迎小郡史。", "寥落火耕俗，征途青冥裏。", "德綏及吾民，不德將鹿矣。", "擒姦非性能，多愍會衰齒。", "恭承共理詔，恆懼墜諸地。"]'),
('4f54d9c1-76d9-4cca-b20a-17b33225a457','天柱隱所重荅江州應物','暢當','唐','唐诗','tang','','[]','寂寞一悵望，秋風山景清。',72,'全唐诗/poet.tang.15000.json','["寂寞一悵望，秋風山景清。", "此中惟草色，翻意見人行。", "荒徑饒松子，深蘿絕鳥聲。", "陽崖全帶日，寬嶂偶通耕。", "拙昧難容世，貧寒別有情。", "煩君瓊玖贈，幽懶百無成。"]'),
('cae5034c-32bd-4cd7-9f3b-9ea8ac9ae813','山居酬韋蘇州見寄','暢當','唐','唐诗','tang','','[]','孤柴泄煙處，此中山叟居。',48,'全唐诗/poet.tang.15000.json','["孤柴泄煙處，此中山叟居。", "觀雲寧有事，耽酒詎知餘。", "水定鶴翻去，松歌峰儼如。", "猶煩使君問，更欲結深廬。"]'),
('c7637208-b55e-48a0-8c10-12cb7cc30e59','春日過奉誠園','暢當','唐','唐诗','tang','','[]','帝里陽和日，遊人到御園。',72,'全唐诗/poet.tang.15000.json','["帝里陽和日，遊人到御園。", "暖催新景氣，春認舊蘭蓀。", "詠德先臣沒，成蹊大樹存。", "見桐猶近井，看柳尚依門。", "獻地非更宅，遺忠永奉恩。", "又期攀桂後，來賞百花繁。"]'),
('8d8a679a-e8c7-421d-9d83-534a1394c677','軍中醉飲寄沈八劉叟','暢當','唐','唐诗','tang','','[]','酒渴愛江清，餘酣漱晚汀。',48,'全唐诗/poet.tang.15000.json','["酒渴愛江清，餘酣漱晚汀。", "軟莎欹坐穩，冷石醉眠醒。", "野膳隨行帳，華音發從伶。", "數杯君不見，都已遣沈冥。"]'),
('e02943e8-20f0-479f-b3ea-db70190ed5b3','偶宴西蜀摩訶池','暢當','唐','唐诗','tang','','[]','珍木鬱清池，風荷左右披。',48,'全唐诗/poet.tang.15000.json','["珍木鬱清池，風荷左右披。", "淺觴寧及醉，慢舸不知移。", "蔭簟流光冷，凝簪照影欹。", "胡爲獨羈者，雪涕向漣漪。"]'),
('7df2e6f1-cd80-4543-9f36-2227f421238b','奉送杜中丞赴洪州','暢當','唐','唐诗','tang','','[]','詔出鳳凰宮，新恩連帥雄。',48,'全唐诗/poet.tang.15000.json','["詔出鳳凰宮，新恩連帥雄。", "江湖經戰陣，草木待仁風。", "豪右貪威愛，紆繁德簡通。", "多慙君子顧，攀餞路塵中。"]'),
('bbe5917e-3b2f-45ac-b458-bcbf662e1aad','九日陪皇甫使君泛江宴赤岸亭','暢當','唐','唐诗','tang','','["\u957f\u6c5f"]','羈旅逢佳節，逍遙忽見招。',72,'全唐诗/poet.tang.15000.json','["羈旅逢佳節，逍遙忽見招。", "同傾菊花酒，緩櫂木蘭橈。", "平楚堪愁思，長江去寂寥。", "猿啼不離峽，灘沸鎮如潮。", "舉目關山異，傷心鄉國遙。", "徒言歡滿座，誰覺客魂消。"]'),
('c81c43d4-beab-4445-b3e9-d7992ff7b573','蒲中道中二首 一','暢當','唐','唐诗','tang','','["\u9ec4\u6cb3"]','蒼蒼中條山，厥形極奇磈。',24,'全唐诗/poet.tang.15000.json','["蒼蒼中條山，厥形極奇磈。", "我欲涉其崖，濯足黃河水。"]'),
('e7140206-0d47-44c5-a3e2-e325d62c2cc1','蒲中道中二首 二','暢當','唐','唐诗','tang','','[]','古剎棲杮林，綠陰覆蒼瓦。',24,'全唐诗/poet.tang.15000.json','["古剎棲杮林，綠陰覆蒼瓦。", "歲晏來品題，拾葉總堪寫。"]'),
('fac2dc15-b1ab-4d6d-89f0-fab7c805398e','登鸛雀樓','暢當','唐','唐诗','tang','','["\u6292\u60c5", "\u666f\u70b9"]','逈臨飛鳥上，高出世塵間。',24,'全唐诗/poet.tang.15000.json','["逈臨飛鳥上，高出世塵間。", "天勢圍平野，河流入斷山。"]'),
('dabec09f-0fd1-4a09-b0c2-c3aae3db4c82','宿潭上二首 一','暢當','唐','唐诗','tang','','[]','夜潭有仙舸，與月當水中。',24,'全唐诗/poet.tang.15000.json','["夜潭有仙舸，與月當水中。", "嘉賓愛明月，遊子驚秋風。"]'),
('ee628ffc-983f-4689-b6be-839ae94a65bf','宿潭上二首 二','暢當','唐','唐诗','tang','','[]','青蒲野陂水，白露明月天。',24,'全唐诗/poet.tang.15000.json','["青蒲野陂水，白露明月天。", "中夜秋風起，心事坐潸然。"]'),
('c32bc3e0-3733-4816-b56d-9c72a0e20119','別盧綸','暢當','唐','唐诗','tang','','[]','故交君獨在，又欲與君離。',24,'全唐诗/poet.tang.15000.json','["故交君獨在，又欲與君離。", "我有新秋淚，非關宋玉悲。"]'),
('d14174f4-ac57-479f-b377-5dc1f7a44d9d','題沈八齋','暢當','唐','唐诗','tang','','[]','江齋一入何亭亭，因寄淪漣心杳冥。',32,'全唐诗/poet.tang.15000.json','["江齋一入何亭亭，因寄淪漣心杳冥。", "綠綺琴彈白雪引，烏絲絹勒黃庭經。"]'),
('ff85eb04-4826-4889-95b7-a362b0939f64','早春','暢諸','唐','唐诗','tang','','[]','獻歲春猶淺，園林未盡開。',48,'全唐诗/poet.tang.15000.json','["獻歲春猶淺，園林未盡開。", "雪和新雨落，風帶舊寒來。", "聽鳥聞歸鴈，看花識早梅。", "生涯知幾日，更被一年催。"]'),
('f6e0972b-b2c8-4a54-b1ad-255e77cb708d','曉過南宮聞太常清樂','陸贄','唐','唐诗','tang','','[]','南宮聞古樂，拂曙聽初驚。',72,'全唐诗/poet.tang.15000.json','["南宮聞古樂，拂曙聽初驚。", "煙靄遙迷處，絲桐暗辨名。", "節隨新律改，聲帶緒風輕。", "合雅將移俗，同和自感情。", "遠音兼曉漏，餘響過春城。", "九奏明初日，寥寥天地清。"]'),
('f0a74e24-e84f-48cd-a77c-cfdc6fa9a5fd','禁中春松','陸贄','唐','唐诗','tang','','[]','陰陰清禁裏，蒼翠滿春松。',72,'全唐诗/poet.tang.15000.json','["陰陰清禁裏，蒼翠滿春松。", "雨露恩偏近，陽和色更濃。", "高枝分曉日，虛吹雜宵鐘。", "香助鑪煙遠，形疑蓋影重。", "願符千載壽，不羨五株封。", "儻得迴天眷，全勝老碧峰。"]'),
('7035e601-9fae-45b2-8556-c2645bfc2f33','賦得御園芳草','陸贄','唐','唐诗','tang','','[]','陰陰御園裏，瑤草日光長。',72,'全唐诗/poet.tang.15000.json','["陰陰御園裏，瑤草日光長。", "靃靡含煙霧，依稀帶夕陽。", "雨餘荑更密，風暖蕙初香。", "擁仗緣馳道，乘輿入建章。", "溼煙搖不散，細影亂無行。", "恆恐韶光晚，何人辨早芳。"]'),
('28503959-b22c-4839-bf8f-6afd22bd3842','句','陸贄','唐','唐诗','tang','','[]','遶堦流㶁㶁，來砌樹陰陰。',12,'全唐诗/poet.tang.15000.json','["遶堦流㶁㶁，來砌樹陰陰。"]'),
('64f8effb-f257-4693-9682-d29cb6c9159b','曉過南宮聞太常清樂','張濛','唐','唐诗','tang','','[]','玉珂經禮寺，金奏過南宮。',72,'全唐诗/poet.tang.15000.json','["玉珂經禮寺，金奏過南宮。", "雅調乘清曉，飛聲向遠空。", "慢隨飄去雪，輕逐度來風。", "迥出重城裏，傍聞九陌中。", "應將肆夏比，更與五英同。", "一聽南薫曲，因知大舜功。"]'),
('6e10f0a1-a937-48ec-b21b-d50dd5e66007','禁中春松','常沂','唐','唐诗','tang','','[]','映殿松偏好，森森列禁中。',72,'全唐诗/poet.tang.15000.json','["映殿松偏好，森森列禁中。", "攢柯霑聖澤，疎蓋引皇風。", "晚色連秦苑，春香滿漢宮。", "操將金石固，材與直臣同。", "翠影宜青瑣，蒼枝秀碧空。", "還知沐天眷，千載更蔥蘢。"]'),
('0de77f00-258c-4c9b-b8a2-6f79bd0c3c66','禁中春松','周存','唐','唐诗','tang','','[]','幾歲含貞節，青青紫禁中。',72,'全唐诗/poet.tang.15000.json','["幾歲含貞節，青青紫禁中。", "日華留偃蓋，雉尾轉春風。", "不爲繁霜改，那將衆木同。", "千條攢翠色，百尺澹晴空。", "影密金莖近，花明鳳沼通。", "安知幽澗側，獨與散樗叢。"]'),
('c0e3d89d-ec95-4b54-b358-65d5dd40e9c8','西戎獻馬','周存','唐','唐诗','tang','','[]','天馬從東道，皇威被遠戎。',72,'全唐诗/poet.tang.15000.json','["天馬從東道，皇威被遠戎。", "來參八駿列，不假貳師功。", "影別流沙路，嘶流上苑風。", "望雲時蹀足，向月每爭雄。", "稟異才難狀，標奇志豈同。", "驅馳如見許，千里一朝通。"]'),
('fd0fc773-5fe1-4fcd-bd2a-8e50417fc322','小苑春望宮池柳色','黎逢','唐','唐诗','tang','','[]','上林新柳變，小苑暮天晴。',72,'全唐诗/poet.tang.15000.json','["上林新柳變，小苑暮天晴。", "始望和煙密，遙憐拂水輕。", "色承陽氣暖，陰帶御溝清。", "不厭隨風弱，仍宜向日明。", "垂絲遍閣榭，飛絮觸簾旌。", "漸到依依處，思聞出谷鸎。"]'),
('edae3601-9f65-4bf2-8814-696f1a4c7ec8','夏首猶清和','黎逢','唐','唐诗','tang','','[]','早夏宜初景，和光起禁城。',72,'全唐诗/poet.tang.15000.json','["早夏宜初景，和光起禁城。", "祝融將御節，炎帝啓朱明。", "日送殘花晚，風過御苑清。", "郊原浮麥氣，池沼發荷英。", "樹影臨山動，禽飛入漢輕。", "幸逢堯禹化，全勝谷中情。"]'),
('d97a60f8-4b5a-4f77-a39a-00c869ff0ff3','小苑春望宮池柳色','張昔','唐','唐诗','tang','','[]','小苑春初至，皇衢日更清。',72,'全唐诗/poet.tang.15000.json','["小苑春初至，皇衢日更清。", "遙分萬條柳，迴出九重城。", "隱映龍池潤，參差鳳闕明。", "影宜宮雪曙，色帶禁煙晴。", "深淺殘陽變，高低曉吹輕。", "年光正堪折，欲寄一枝榮。"]'),
('5c7aca84-6bc9-4656-99c3-ce1515a8145e','小苑春望宮池柳色','丁位','唐','唐诗','tang','','[]','小苑春初望，宮池柳色輕。',72,'全唐诗/poet.tang.15000.json','["小苑春初望，宮池柳色輕。", "低昂含曉景，縈轉帶新晴。", "似蓋芳初合，如絲蔭漸成。", "依依連水暗，嫋嫋出牆明。", "雖以陽和發，能令旅思生。", "他時花滿路，從此接遷鶯。"]'),
('aa3870fe-2673-4710-bc94-802dcb4f42fd','小苑春望宮池柳色','元友直','唐','唐诗','tang','','[]','柳色新池遍，春光御苑晴。',72,'全唐诗/poet.tang.15000.json','["柳色新池遍，春光御苑晴。", "葉依青閣密，條向碧流傾。", "路暗陰初重，波搖影轉清。", "風從垂處度，煙就望中生。", "斷續游蜂聚，飄颻戲蝶輕。", "怡然變芳節，願及一枝榮。"]'),
('b6ce9316-8ec8-4eb8-b767-d6eb614dbd3d','小苑春望宮池柳色','楊系','唐','唐诗','tang','','[]','勝游從小苑，宮柳望春晴。',72,'全唐诗/poet.tang.15000.json','["勝游從小苑，宮柳望春晴。", "拂地青絲嫩，縈風綠帶輕。", "光含煙色遠，影透水文清。", "玉笛吟何得，金閨畫豈成。", "皇風吹欲斷，聖日映逾明。", "願駐高枝上，還同出谷鶯。"]'),
('5878fe4c-3613-461b-ab7e-1444dd2492f8','小苑春望宮池柳色','崔績','唐','唐诗','tang','','[]','帝京春氣早，御柳已先榮。',72,'全唐诗/poet.tang.15000.json','["帝京春氣早，御柳已先榮。", "嫩葉隨風散，浮光向月明。", "悠揚生別意，斷續引芳聲。", "積翠連馳道，飄花出禁城。", "柔條依水弱，遠色帶煙輕。", "南望龍池畔，斜光照晚晴。"]'),
('8c0bbd24-967c-4c50-a027-50c786d8d576','小苑春望宮池柳色','張季略','唐','唐诗','tang','','[]','韶光歸漢苑。',72,'全唐诗/poet.tang.15000.json','["韶光歸漢苑。", "柳色發春城，半見離宮出。", "纔分遠水明，青蔥當淑景。", "隱映媚新晴，積翠煙初合。", "微黃葉未生，迎春看尚嫩。", "照日見先榮，倘得辭幽谷。", "高枝寄一名。"]'),
('d595c63e-48b4-44d0-859e-e8e68f074aff','小苑春望宮池柳色','裴達','唐','唐诗','tang','','[]','勝遊經小苑，閑望上春城。',72,'全唐诗/poet.tang.15000.json','["勝遊經小苑，閑望上春城。", "御路韶光發，宮池柳色輕。", "乍濃含雨潤，微澹帶雲晴。", "羃歷殘煙斂，搖揚落照明。", "幾條垂廣殿，數樹影高旌。", "獨有風塵客，思同雨露榮。"]'),
('01199cd7-9a2a-4489-8b81-2a61043b2d01','南至日太史登臺書雲物','裴逵','唐','唐诗','tang','','[]','圓丘纔展禮，佳氣近初分。',72,'全唐诗/poet.tang.15000.json','["圓丘纔展禮，佳氣近初分。", "太史新簪筆，高臺紀彩雲。", "煙空和縹緲，曉色共氛氳。", "道泰資賢輔，年豐荷聖君。", "恭惟司國瑞，兼用察人文。", "應念懷鉛客，終朝望碧雰。"]'),
('8b5e6994-a85a-4235-b84a-1d4f24ee0aa1','小苑春望宮池柳色','沈迴','唐','唐诗','tang','','[]','今來遊上苑，春染柳條輕。',72,'全唐诗/poet.tang.15000.json','["今來遊上苑，春染柳條輕。", "濯濯方含色，依依若有情。", "分行臨曲沼，先發媚重城。", "拂水枝偏弱，搖風絲已生。", "變黃隨淑景，吐翠逐新晴。", "佇立徒延首，裴回欲寄誠。"]'),
('4d936030-f10a-41fa-878c-7d48272a5c96','長安春夜宿開元觀','楊憑','唐','唐诗','tang','','[]','霓裳下晚煙，留客杏花前。',48,'全唐诗/poet.tang.15000.json','["霓裳下晚煙，留客杏花前。", "徧問人寰事，新從洞府天。", "長松皆掃月，老鶴不知年。", "爲說蓬瀛路，雲濤幾處連。"]'),
('fef4870c-55a7-4c00-aa01-d3416ed33a46','晚泊江戍','楊憑','唐','唐诗','tang','','[]','旅櫂依遙戍，清湘急晚流。',48,'全唐诗/poet.tang.15000.json','["旅櫂依遙戍，清湘急晚流。", "若爲南浦宿，逢此北風秋。", "雲月孤鴻晚，關山幾路愁。", "年年不得意，零落對滄洲。"]'),
('1c2374ee-4b03-4303-8bed-377a9dfd290a','巴江雨夜','楊憑','唐','唐诗','tang','','[]','五嶺天無雁，三巴客問津。',48,'全唐诗/poet.tang.15000.json','["五嶺天無雁，三巴客問津。", "紛紛輕漢暮，漠漠暗江春。", "青草連湖岸，繁花憶楚人。", "芳菲無限路，幾夜月明新。"]'),
('f71cc1a4-be4f-4cb2-b7da-22d345260d50','邊塞行','楊憑','唐','唐诗','tang','','[]','九原臨得水，雙足是重城。',48,'全唐诗/poet.tang.15000.json','["九原臨得水，雙足是重城。", "獨許爲儒老，相憐從騎行。", "細叢榆塞逈，高點雁山晴。", "聖主嗤炎漢，無心自勒兵。"]'),
('f3a91124-c4de-429d-be66-a80539dcefcf','樂遊園望月','楊憑','唐','唐诗','tang','','[]','炎靈全盛地，明月半秋時。',48,'全唐诗/poet.tang.15000.json','["炎靈全盛地，明月半秋時。", "今古人同望，盈虧節暗移。", "彩凝雙月逈，輪度八川遲。", "共惜鳴珂去，金波送酒巵。"]'),
('08d0e076-ff46-4c75-b7d2-60a94290dfb6','千葉桃花','楊憑','唐','唐诗','tang','','[]','千葉桃花勝百花，孤榮春晚駐年華。',32,'全唐诗/poet.tang.15000.json','["千葉桃花勝百花，孤榮春晚駐年華。", "若教避俗秦人見，知向河源舊侶誇。"]'),
('26915352-6358-4301-a3cb-65813f8ec858','春中汎舟','楊憑','唐','唐诗','tang','','[]','仙郎歸奏過湘東，正值三湘二月中。',32,'全唐诗/poet.tang.15000.json','["仙郎歸奏過湘東，正值三湘二月中。", "惆悵滿川桃杏醉，醉看還與曲江同。"]'),
('c646227d-122c-493c-b1fb-410397eb65f7','雨中怨秋','楊憑','唐','唐诗','tang','','[]','辭家遠客愴秋風，千里寒雲與斷蓬。',32,'全唐诗/poet.tang.15000.json','["辭家遠客愴秋風，千里寒雲與斷蓬。", "日暮隔山投古寺，鐘聲何處雨濛濛。"]'),
('f00e57ab-0566-404a-aef0-1762ef4933f7','秋日獨遊曲江','楊憑','唐','唐诗','tang','','[]','信馬閑過憶所親，秋山行盡路無塵。',32,'全唐诗/poet.tang.15000.json','["信馬閑過憶所親，秋山行盡路無塵。", "主人莫惜松陰醉，還有千錢沽酒人。"]'),
('bd7b2791-2af0-4dbb-8ad0-36686e015ab9','寄別','楊憑','唐','唐诗','tang','','[]','晚煙洲霧共蒼蒼，河雁驚飛不作行。',32,'全唐诗/poet.tang.15000.json','["晚煙洲霧共蒼蒼，河雁驚飛不作行。", "廻斾轉舟行數里，歌聲猶自逐清湘。"]'),
('9cbaabf1-7aed-421d-9dec-c8a401ca89c4','邊情','楊憑','唐','唐诗','tang','','[]','新種如今屢請和，玉關邊上幸無他。',32,'全唐诗/poet.tang.15000.json','["新種如今屢請和，玉關邊上幸無他。", "欲知北海苦辛處，看取節毛餘幾多。"]'),
('16a90c1d-52ba-46e1-bb5e-0d447c6a2a72','早發湘中','楊憑','唐','唐诗','tang','','[]','按節鳴笳中貴催，紅旌白斾滿船開。',32,'全唐诗/poet.tang.15000.json','["按節鳴笳中貴催，紅旌白斾滿船開。", "迎愁湓浦登城望，西見荆門積水來。"]'),
('5728bd1b-c657-43b4-b3e6-842ae3234a26','海榴','楊憑','唐','唐诗','tang','','[]','海榴殷色透簾櫳，看盛看衰意欲同。',32,'全唐诗/poet.tang.15000.json','["海榴殷色透簾櫳，看盛看衰意欲同。", "若許三英隨五馬，便將濃豔鬬繁紅。"]'),
('16b22371-368d-4d3c-90ee-dff0c3d16670','春情','楊憑','唐','唐诗','tang','','[]','暮雨朝雲幾日歸，如絲如霧濕人衣。',32,'全唐诗/poet.tang.15000.json','["暮雨朝雲幾日歸，如絲如霧濕人衣。", "三湘二月春光早，莫逐狂風繚亂飛。"]'),
('9b8a1a9f-19e7-4b7e-aef4-3078bb3dcbd5','送客往荆州','楊憑','唐','唐诗','tang','','[]','巴丘過日又登城，雲水湘東一日平。',32,'全唐诗/poet.tang.15000.json','["巴丘過日又登城，雲水湘東一日平。", "若愛春秋繁露學，正逢元凱鎮南荆。"]'),
('0c4e7fc5-92f5-4bc5-a882-9e536a9c6dda','贈馬鍊師','楊憑','唐','唐诗','tang','','[]','心嫌碧落更何從，月帔花冠冰雪容。',32,'全唐诗/poet.tang.15000.json','["心嫌碧落更何從，月帔花冠冰雪容。", "行雨若迷歸處路，近南惟見祝融峰。"]'),
('6145d26a-df42-47a1-80dd-d6cf5bd50112','湘江泛舟','楊憑','唐','唐诗','tang','','[]','湘川洛浦三千里，地角天涯南北遙。',32,'全唐诗/poet.tang.15000.json','["湘川洛浦三千里，地角天涯南北遙。", "除却同傾百壺外，不愁誰奈兩魂銷。"]'),
('d3848220-b67b-4df1-87ee-30b90a87f507','送別','楊憑','唐','唐诗','tang','','[]','江岸梅花雪不如，看君驛馭向南徐。',32,'全唐诗/poet.tang.15000.json','["江岸梅花雪不如，看君驛馭向南徐。", "相聞不必因來雁，雲裏飛輧落素書。"]'),
('46ca0f44-e7b8-4569-a3d3-325d9724b938','贈竇牟','楊憑','唐','唐诗','tang','','[]','直用天才衆却瞋，應欺李杜久爲塵。',32,'全唐诗/poet.tang.15000.json','["直用天才衆却瞋，應欺李杜久爲塵。", "南荒不死中華老，別玉翻同西國人。"]'),
('d6ad68da-ff7c-4611-a38f-e49d2bace84d','送別','楊凝','唐','唐诗','tang','','[]','樽酒郵亭暮，雲帆驛使歸。',48,'全唐诗/poet.tang.15000.json','["樽酒郵亭暮，雲帆驛使歸。", "野鷗寒不起，川雨凍難飛。", "吳會家移遍，軒轅夢去稀。", "姓楊皆足淚，非是強沾衣。"]'),
('307e9576-89c6-44c5-8b80-0b46dd53da02','送客東歸','楊凝','唐','唐诗','tang','','[]','君向古營州，邊風戰地愁。',48,'全唐诗/poet.tang.15000.json','["君向古營州，邊風戰地愁。", "草青縵別路，柳亞拂孤樓。", "人意傷難醉，鶯啼咽不流。", "芳菲只合樂，離思返如秋。"]'),
('740ef99c-f962-402f-9147-030c2d1664f0','送客歸湖南','楊凝','唐','唐诗','tang','','[]','湖南樹色盡，了了辨潭州。',48,'全唐诗/poet.tang.15000.json','["湖南樹色盡，了了辨潭州。", "雨散今爲別，雲飛何處遊。", "情來偏似醉，淚迸不成流。", "那向蕭條路，緣湘篁竹愁。"]'),
('b0481b35-8972-4676-a749-ab9f209cdf28','送客歸淮南','楊凝','唐','唐诗','tang','','[]','畫舫照河堤，暄風百草齊。',48,'全唐诗/poet.tang.15000.json','["畫舫照河堤，暄風百草齊。", "行絲直網蝶，去燕旋遺泥。", "郡向高天近，人從別路迷。", "非關御溝上，今日各東西。"]'),
('7ce33de2-76f5-4cec-8e53-db11a25021db','春情','楊凝','唐','唐诗','tang','','[]','舊宅洛川陽，曾遊遊俠場。',48,'全唐诗/poet.tang.15000.json','["舊宅洛川陽，曾遊遊俠場。", "水添楊柳色，花絆綺羅香。", "趙瑟多愁曲，秦家足豔妝。", "江潭遠相憶，春夢不勝長。"]'),
('11c4239f-8784-43e5-87a7-3c2d2109dd22','秋夜聽擣衣','楊凝','唐','唐诗','tang','','[]','砧杵聞秋夜，裁縫寄遠方。',48,'全唐诗/poet.tang.15000.json','["砧杵聞秋夜，裁縫寄遠方。", "聲微漸濕露，響細未經霜。", "蘭牖唯遮樹，風簾不礙涼。", "雲中望何處，聽此斷人腸。"]'),
('89382d30-dbf7-4412-9c1c-fecb7e6876e5','從軍行','楊凝','唐','唐诗','tang','','[]','都尉出居延，強兵集五千。',48,'全唐诗/poet.tang.15000.json','["都尉出居延，強兵集五千。", "還將張博望，直救范祁連。", "漢卒悲簫鼓，胡姬濕采旃。", "如今意氣盡，流淚挹流泉。"]'),
('567571c0-a3a0-4e62-aa91-565636b1fd6f','和直禁省','楊凝','唐','唐诗','tang','','[]','宵直丹宮近，風傳碧樹涼。',48,'全唐诗/poet.tang.15000.json','["宵直丹宮近，風傳碧樹涼。", "漏稀銀箭滴，月度網軒光。", "鳳詔裁多暇，蘭燈夢更長。", "此時顏范貴，十步舊連行。"]'),
('43f7d5bf-6128-4c4a-97d7-db9b6de9fc15','留別','楊凝','唐','唐诗','tang','','[]','玉節隨東閣，金閨別舊僚。',24,'全唐诗/poet.tang.15000.json','["玉節隨東閣，金閨別舊僚。", "若爲花滿寺，躍馬上河橋。"]'),
('ed2e0aab-2ee3-4374-8aef-5a1817948255','送客往洞庭','楊凝','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','九江歸路遠，萬里客舟還。',24,'全唐诗/poet.tang.15000.json','["九江歸路遠，萬里客舟還。", "若過巴江水，湘東滿碧煙。"]'),
('ff101c4c-b3bd-4aef-8e7e-9de532984840','別友人','楊凝','唐','唐诗','tang','','[]','倦客驚危路，傷禽遶樹枝。',24,'全唐诗/poet.tang.15000.json','["倦客驚危路，傷禽遶樹枝。", "非逢暴公子，不敢涕流離。"]'),
('d60a1c3d-f288-4adb-a73f-baab5e6bf0a3','初渡淮北岸','楊凝','唐','唐诗','tang','','[]','別夢雖難覺，悲魂最易銷。',24,'全唐诗/poet.tang.15000.json','["別夢雖難覺，悲魂最易銷。", "慇勤淮北岸，鄉近去家遙。"]'),
('6641c4c2-33d9-4acc-bc58-41305dd34f1f','詠雨','楊凝','唐','唐诗','tang','','[]','塵浥多人路，泥歸足燕家。',24,'全唐诗/poet.tang.15000.json','["塵浥多人路，泥歸足燕家。", "可憐繚亂點，濕盡滿宮花。"]'),
('a5b107aa-c8fe-43b3-a3af-631a839b9a40','柳絮','楊凝','唐','唐诗','tang','','[]','河畔多楊柳，追遊盡狹斜。',24,'全唐诗/poet.tang.15000.json','["河畔多楊柳，追遊盡狹斜。", "春風一回送，亂入莫愁家。"]'),
('01bcddd1-4f13-4740-9e1f-d2c510188ab7','花枕','楊凝','唐','唐诗','tang','','[]','席上沈香枕，樓中蕩子妻。',24,'全唐诗/poet.tang.15000.json','["席上沈香枕，樓中蕩子妻。", "那堪一夜裏，長濕兩行啼。"]'),
('79f78a30-4013-4ecf-ac2f-93fa0b234ecb','送客往鄜州','楊凝','唐','唐诗','tang','','[]','新參將相事營平，錦帶騂弓結束輕。',64,'全唐诗/poet.tang.15000.json','["新參將相事營平，錦帶騂弓結束輕。", "曉上關城吟畫角，暗馳羗馬發支兵。", "回中地近風常急，鄜畤年多草自生。", "近喜扶陽係戎相，從來衞霍笑長纓。"]'),
('90c8c16c-b673-456c-b482-d21bad5558c1','送客往夏州','楊凝','唐','唐诗','tang','','[]','憐君此去過居延，古塞黃雲共渺然。',64,'全唐诗/poet.tang.15000.json','["憐君此去過居延，古塞黃雲共渺然。", "沙闊獨行尋馬跡，路迷遙指戍樓煙。", "夜投孤店愁吹笛，朝望行塵避控弦。", "聞有故交今從騎，何須著論更言錢。"]'),
('bd6fa3c6-5532-48c9-b78f-1357dd6e028f','春霽晚望','楊凝','唐','唐诗','tang','','[]','細雨晴深小苑東，春雲開氣逐光風。',64,'全唐诗/poet.tang.15000.json','["細雨晴深小苑東，春雲開氣逐光風。", "雄兒走馬神光上，靜女看花佛寺中。", "書劒學多心欲嬾，田園荒廢望頻空。", "南歸路極天連海，惟有相思明月同。"]'),
('f167222a-2efe-46c5-8fd7-c0d0bc6b0b7c','唐昌觀玉蘂花','楊凝','唐','唐诗','tang','','[]','瑤華瓊蘂種何年，蕭史秦嬴向紫煙。',32,'全唐诗/poet.tang.15000.json','["瑤華瓊蘂種何年，蕭史秦嬴向紫煙。", "時控綵鸞過舊邸，摘花持獻玉皇前。"]'),
('466c6b6d-4fd6-4697-8642-1c50e4b45b79','別李協','楊凝','唐','唐诗','tang','','[]','江邊日暮不勝愁，送客霑衣江上樓。',32,'全唐诗/poet.tang.15000.json','["江邊日暮不勝愁，送客霑衣江上樓。", "明月峽添明月照，蛾眉峰似兩眉愁。"]'),
('3499130a-78e3-42fb-8295-74bcd068d288','初次巴陵','楊凝','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','西江浪接洞庭波，積水遙連天上河。',32,'全唐诗/poet.tang.15000.json','["西江浪接洞庭波，積水遙連天上河。", "鄉信爲憑誰寄去，汀洲燕雁漸來多。"]'),
('82b82749-a034-4ad1-97d2-ed361b75885c','上巳','楊凝','唐','唐诗','tang','','[]','帝京元巳足繁華，細管清弦七貴家。',32,'全唐诗/poet.tang.15000.json','["帝京元巳足繁華，細管清弦七貴家。", "此日風光誰不共，紛紛皆是掖垣花。"]'),
('655946f1-eda9-469c-bc5b-da8dc465e9cf','春怨','楊凝','唐','唐诗','tang','','[]','花滿簾櫳欲度春，此時夫壻在咸秦。',32,'全唐诗/poet.tang.15000.json','["花滿簾櫳欲度春，此時夫壻在咸秦。", "綠窗孤寢難成寐，紫燕雙飛似弄人。"]'),
('a460c51f-1465-405f-b18b-6a295413054b','送客歸常州','楊凝','唐','唐诗','tang','','[]','行到河邊從此辭，寒天日遠暮帆遲。',32,'全唐诗/poet.tang.15000.json','["行到河邊從此辭，寒天日遠暮帆遲。", "可憐芳草成衰草，公子歸時過綠時。"]'),
('73c24a9a-197c-4f48-a062-9083b6566ad6','送別','楊凝','唐','唐诗','tang','','[]','春愁不盡別愁來，舊淚猶長新淚催。',32,'全唐诗/poet.tang.15000.json','["春愁不盡別愁來，舊淚猶長新淚催。", "相思倘寄相思字，君到揚州揚子迴。"]'),
('1f36603e-7e41-4fbe-ab85-1ac0c7ad6ccd','送客入蜀','楊凝','唐','唐诗','tang','','[]','劒閣迢迢夢想間，行人歸路遶梁山。',32,'全唐诗/poet.tang.15000.json','["劒閣迢迢夢想間，行人歸路遶梁山。", "明朝騎馬搖鞭去，秋雨槐花子午關。"]'),
('50438e66-8665-4453-ba9c-3446251de626','送別','楊凝','唐','唐诗','tang','','[]','仙花笑盡石門中，石室重重掩綠空。',32,'全唐诗/poet.tang.15000.json','["仙花笑盡石門中，石室重重掩綠空。", "蹔下雲峰能幾日，却迴煙駕馭春風。"]'),
('93be035d-9976-4033-a47f-5330fa8bea20','殘花','楊凝','唐','唐诗','tang','','[]','五馬踟躕在路岐，南來只爲看花枝。',32,'全唐诗/poet.tang.15000.json','["五馬踟躕在路岐，南來只爲看花枝。", "鶯銜蝶弄紅芳盡，此日深閨那得知。"]'),
('00701b63-8026-4375-bb72-1163b291e5e3','戲贈友人','楊凝','唐','唐诗','tang','','[]','湘陰直與地陰連，此日相逢憶醉年。',32,'全唐诗/poet.tang.15000.json','["湘陰直與地陰連，此日相逢憶醉年。", "美酒非如平樂貴，十升不用一千錢。"]'),
('29f41c00-2f43-47cc-99dc-b4749beef2fc','贈同遊','楊凝','唐','唐诗','tang','','[]','此囗風雨後，已覺減年華。',48,'全唐诗/poet.tang.15000.json','["此囗風雨後，已覺減年華。", "若待皆無事，應難更有花。", "管弦臨夜急，榆柳向江斜。", "且莫看歸路，同須醉酒家。"]'),
('0a7a2237-9f1c-485e-a2b7-10d862ff7349','送人出塞','楊凝','唐','唐诗','tang','','[]','北風吹雨雪，舉目已悽悽。',48,'全唐诗/poet.tang.15000.json','["北風吹雨雪，舉目已悽悽。", "戰鬼秋頻哭，征鴻夜不棲。", "沙平關路直，磧廣郡樓低。", "此去非東魯，人多事鼓鼙。"]'),
('1e3da629-3127-4806-a3d9-ffdc1162bfa3','尋僧元皎因病','楊凝','唐','唐诗','tang','','[]','此僧迷友著，因病得尋師。',48,'全唐诗/poet.tang.15000.json','["此僧迷友著，因病得尋師。", "話盡山中事，歸當月上時。", "高松連寺影，亞竹入窗枝。", "閑憶草堂路，相逢非素期。"]'),
('af5656ce-7ca5-4e01-b650-6187500120b2','夜泊渭津','楊凝','唐','唐诗','tang','','[]','飄飄東去客，一宿渭城邊。',48,'全唐诗/poet.tang.15000.json','["飄飄東去客，一宿渭城邊。", "遠處星垂岸，中流月滿船。", "涼歸夜深簟，秋入雨餘天。", "漸覺家山小，殘程尚幾年。"]'),
('4759caa1-7eea-4a67-9fa5-6cc614c69f4a','晚夏逢友人','楊凝','唐','唐诗','tang','','[]','一別同袍友，相思已十年。',48,'全唐诗/poet.tang.15000.json','["一別同袍友，相思已十年。", "長安多在客，久病忽聞蟬。", "驟雨纔沾地，陰雲不徧天。", "微涼堪話舊，移榻晚風前。"]'),
('e4e287f1-f101-4d55-8448-1f73442ef2f5','別謫者','楊凝','唐','唐诗','tang','','[]','此地聞猶惡，人言是所之。',48,'全唐诗/poet.tang.15000.json','["此地聞猶惡，人言是所之。", "一家書絕久，孤驛夢成遲。", "八月三湘道，聞猨冒雨時。", "不須祠楚相，臣節轉堪疑。"]'),
('475caaa3-edca-4365-b4d8-f7dfba41ea1c','行思','楊凝','唐','唐诗','tang','','[]','千里豈云去，欲歸如路窮。',48,'全唐诗/poet.tang.15000.json','["千里豈云去，欲歸如路窮。", "人間無暇日，馬上又秋風。", "破月銜高岳，流星拂曉空。", "此時皆在夢，行色獨怱怱。"]'),
('e43784bb-279b-4196-ba5a-1c919ee80aeb','感懷題從舅宅','楊凝','唐','唐诗','tang','','[]','郗家庭樹下，幾度醉春風。',48,'全唐诗/poet.tang.15000.json','["郗家庭樹下，幾度醉春風。", "今日花還發，當時事不同。", "流言應未息，直道竟難通。", "徒遣相思者，悲歌向暮空。"]'),
('a9ed41c1-862e-4dea-af90-f5de5a02e814','與友人會','楊凝','唐','唐诗','tang','','[]','蟬吟槐蘂落，的的是愁端。',48,'全唐诗/poet.tang.15000.json','["蟬吟槐蘂落，的的是愁端。", "病覺離家遠，貧知處事難。", "真交無所隱，深語有餘歡。", "未必聞歌吹，羈心得蹔寬。"]'),
('9de3db08-aaf6-42aa-96f5-a9af3dcb7526','下第後蒙侍郎示意指於新先輩宣恩感謝','楊凝','唐','唐诗','tang','','[]','才薄命如此，自嗟兼自疑。',48,'全唐诗/poet.tang.15000.json','["才薄命如此，自嗟兼自疑。", "遭逢好交日，黜落至公時。", "倚玉甘無路，穿楊却未期。", "更慙君侍坐，問許可言詩。"]'),
('2502eef1-d7b2-4d3d-b4b8-ada2d713b03d','奉酬韋滁州寄示','楊凌','唐','唐诗','tang','','[]','淮揚爲郡暇，坐惜流芳歇。',48,'全唐诗/poet.tang.15000.json','["淮揚爲郡暇，坐惜流芳歇。", "散懷累榭風，清暑澄潭月。", "陪燕辭三楚，戒途綿百越。", "非當遠別離，雅奏何由發。"]'),
('b10851b9-e6cb-41eb-979a-c897ccaac1df','梅里旅夕','楊凌','唐','唐诗','tang','','[]','滄洲東望路，旅櫂愴羈遊。',48,'全唐诗/poet.tang.15000.json','["滄洲東望路，旅櫂愴羈遊。", "楓浦蟬隨岸，沙汀鷗轉流。", "露天星上月，水國夜生秋。", "誰忍持相憶，南歸一葉舟。"]'),
('70ceb718-ac98-4a19-b8c7-652a3d2b6c5f','鍾陵雪夜詶友人','楊凌','唐','唐诗','tang','','[]','窮臘催年急，陽春怯和歌。',48,'全唐诗/poet.tang.15000.json','["窮臘催年急，陽春怯和歌。", "殘燈閃壁盡，夜雪透窗多。", "歸路山川險，遊人夢寐過。", "龍洲不可泊，歲晚足驚波。"]'),
('61b7672c-004e-42c9-815d-6b311e1492b6','潤州水樓','楊凌','唐','唐诗','tang','','[]','歸心不可留，雪桂一叢秋。',48,'全唐诗/poet.tang.15000.json','["歸心不可留，雪桂一叢秋。", "葉雨空江月，螢飛白露洲。", "野蟬依獨樹，水郭帶孤樓。", "遙望山川路，相思萬里遊。"]'),
('ae47f2c3-d219-43ed-8fa4-38f376e4ab7e','江上秋月','楊凌','唐','唐诗','tang','','[]','隴雁送鄉心，羈情屬歲陰。',48,'全唐诗/poet.tang.15000.json','["隴雁送鄉心，羈情屬歲陰。", "驚秋黃葉遍，愁暮碧雲深。", "月色吳江上，風聲楚木林。", "交親幾重別，歸夢併愁侵。"]'),
('b1ea1885-1c8e-4c3f-abf4-829c989b8058','閣前雙槿','楊凌','唐','唐诗','tang','','[]','羣玉開雙槿，丹榮對絳紗。',48,'全唐诗/poet.tang.15000.json','["羣玉開雙槿，丹榮對絳紗。", "含煙疑出火，隔雨怪舒霞。", "向晚爭辭蘂，迎朝鬬發花。", "非關後桃李，爲欲繼年華。"]'),
('59df755e-5961-4146-80e9-e15c9cedea8a','小苑春望宮池柳色','楊凌','唐','唐诗','tang','','[]','上苑閑游早，東風柳色輕。',72,'全唐诗/poet.tang.15000.json','["上苑閑游早，東風柳色輕。", "儲胥遙掩映，池水隔微明。", "春至條偏弱，寒餘葉未成。", "和煙變濃淡，轉日異陰晴。", "不獨芳菲好，還因雨露榮。", "行人望攀折，遠翠暮愁生。"]'),
('e7d5356c-0563-4a3a-8d01-c363ca8362b0','送客往睦州','楊凌','唐','唐诗','tang','','[]','水闊盡南天，孤舟去渺然。',24,'全唐诗/poet.tang.15000.json','["水闊盡南天，孤舟去渺然。", "驚秋路傍客，日暮數聲蟬。"]'),
('e82dfaab-abac-499f-a438-8258a87ac7ce','送客之蜀','楊凌','唐','唐诗','tang','','[]','西蜀三千里，巴南水一方。',24,'全唐诗/poet.tang.15000.json','["西蜀三千里，巴南水一方。", "曉雲天際斷，夜月峽中長。"]'),
('fc1c773f-6b56-4f23-a682-0eff52500a4d','剡溪看花','楊凌','唐','唐诗','tang','','[]','花落千廻舞，鶯聲百囀歌。',24,'全唐诗/poet.tang.15000.json','["花落千廻舞，鶯聲百囀歌。", "還同異方樂，不奈客愁多。"]'),
('bbab6661-1d07-4485-86d3-d0b6e6a9159d','江中風','楊凌','唐','唐诗','tang','','[]','白浪暗江中，南泠路不通。',24,'全唐诗/poet.tang.15000.json','["白浪暗江中，南泠路不通。", "高檣帆自滿，出浦莫呼風。"]'),
('b537a242-f109-4ced-bbba-4cea3b3db597','詠破扇','楊凌','唐','唐诗','tang','','[]','粉落空牀棄，塵生故篋留。',24,'全唐诗/poet.tang.15000.json','["粉落空牀棄，塵生故篋留。", "先來無一半，情斷不勝愁。"]'),
('c24ce06f-f490-4466-92ea-dd991a4ed4ca','賈客愁','楊凌','唐','唐诗','tang','','[]','山水路悠悠，逢灘即殢留。',24,'全唐诗/poet.tang.15000.json','["山水路悠悠，逢灘即殢留。", "西江風未便，何日到荆州。"]'),
('d98880f6-8f83-4a02-9fc7-94dca8c9fed9','即事寄人','楊凌','唐','唐诗','tang','','[]','中禁鳴鐘日欲高，北窗欹枕望頻搔。',32,'全唐诗/poet.tang.15000.json','["中禁鳴鐘日欲高，北窗欹枕望頻搔。", "相思寂寞青苔合，唯有春風啼伯勞。"]'),
('95364c77-2a32-47e0-a5f8-78f13ecdbcf1','早春雪中','楊凌','唐','唐诗','tang','','[]','新年雨雪少晴時，屢失尋梅看柳期。',32,'全唐诗/poet.tang.15000.json','["新年雨雪少晴時，屢失尋梅看柳期。", "鄉信憶隨回鴈早，江春寒帶故陰遲。"]'),
('5770b5d6-3ea9-443a-8159-14d2b05771f6','北行留別','楊凌','唐','唐诗','tang','','[]','日日山川烽火頻，山河重起舊煙塵。',32,'全唐诗/poet.tang.15000.json','["日日山川烽火頻，山河重起舊煙塵。", "一生孤負龍泉劒，羞把詩書問故人。"]'),
('32f64e23-40d7-4bd1-a43b-5a94c6d57438','秋原野望','楊凌','唐','唐诗','tang','','[]','客鴈秋來次第逢，家書頻寄兩三封。',32,'全唐诗/poet.tang.15000.json','["客鴈秋來次第逢，家書頻寄兩三封。", "夕陽天外雲歸盡，亂見青山無數峰。"]'),
('7daf85fe-c509-48fd-b923-77dc3b2bb173','春霽花萼樓南聞宮鶯','楊凌','唐','唐诗','tang','','[]','祥煙瑞氣曉來輕，柳變花開共作晴。',32,'全唐诗/poet.tang.15000.json','["祥煙瑞氣曉來輕，柳變花開共作晴。", "黃鳥遠啼鳷鵲觀，春風流出鳳皇城。"]'),
('8750bb8c-7de6-40b9-9da8-721df21f8573','明妃怨','楊凌','唐','唐诗','tang','','[]','漢國明妃去不還，馬馱絃管向陰山。',32,'全唐诗/poet.tang.15000.json','["漢國明妃去不還，馬馱絃管向陰山。", "匣中縱有菱花鏡，羞對單于照舊顏。"]'),
('c76b3d42-b78a-45aa-8bf3-642c9573ef01','句','楊凌','唐','唐诗','tang','','[]','南園桃李花落盡，春風寂寞搖空枝。',16,'全唐诗/poet.tang.15000.json','["南園桃李花落盡，春風寂寞搖空枝。"]'),
('eb5923a0-e11c-466e-94ff-1b71c60e7efa','題玉真觀公主山池院','司空曙','唐','唐诗','tang','','[]','香殿留遺影，春朝玉戶開。',72,'全唐诗/poet.tang.15000.json','["香殿留遺影，春朝玉戶開。", "羽衣重素几，珠網儼輕埃。", "石自蓬山得，泉經太液來。", "柳絲遮綠浪，花粉落青苔。", "鏡掩鸞空在，霞消鳳不迴。", "唯餘古桃樹，傳是上仙栽。"]'),
('07c96e92-8589-4e1b-9c90-44feedbaca48','送永陽崔明府','司空曙','唐','唐诗','tang','','[]','古國羣舒地，前當桐柏關。',48,'全唐诗/poet.tang.15000.json','["古國羣舒地，前當桐柏關。", "連綿江上雨，稠疊楚南山。", "沙館行帆息，楓洲候吏還。", "乘籃若有暇，精舍在林間。"]'),
('47f5d0d8-cd03-4b71-a545-eedb1ceac627','送曹三同猗遊山寺','司空曙','唐','唐诗','tang','','[]','山蹋青蕪盡，涼秋古寺深。',48,'全唐诗/poet.tang.15000.json','["山蹋青蕪盡，涼秋古寺深。", "何時得連策，此夜更聞琴。", "窮水雲同穴，過僧虎共林。", "殷勤如念我，遺爾挂冠心。"]'),
('0659c894-8128-4d41-8136-e7afac1dcc33','送崔校書赴梓幕','司空曙','唐','唐诗','tang','','[]','碧峯天柱下，鼓角鎮南軍。',48,'全唐诗/poet.tang.15000.json','["碧峯天柱下，鼓角鎮南軍。", "管記催飛檄，蓬萊輟校文。", "棧霜朝似雪，江霧晚成雲。", "想出褒中望，巴庸方路分。"]'),
('6cd63a0f-a484-4880-8a5e-d80ca885d868','送夔州班使君','司空曙','唐','唐诗','tang','','[]','魚國巴庸路，麾幢漢守過。',48,'全唐诗/poet.tang.15000.json','["魚國巴庸路，麾幢漢守過。", "曉檣爭市隘，夜鼓祭神多。", "雲白當山雨，風清滿峽波。", "夷陵舊人吏，猶誦兩岐歌。"]'),
('420fad84-9a0a-4718-a809-493e7845cd9f','送菊潭王明府','司空曙','唐','唐诗','tang','','[]','業成洙泗客，皓髮著儒衣。',48,'全唐诗/poet.tang.15000.json','["業成洙泗客，皓髮著儒衣。", "一與遊人別，仍聞帶印歸。", "林多宛地古，雲盡漢山稀。", "莫愛潯陽隱，嫌官計亦非。"]'),
('d8d8ad3c-2eed-41f8-bf50-6e980e4f4eb4','送太易上人赴東洛','司空曙','唐','唐诗','tang','','[]','遙見登山處，青蕪雪後春。',48,'全唐诗/poet.tang.15000.json','["遙見登山處，青蕪雪後春。", "雲深岳廟火，寺宿洛陽人。", "餌藥將齋折，唯詩與道親。", "凡經幾回別，麈尾不離身。"]'),
('3c9a2f78-0607-4a59-a2ee-018a2d391dd3','和王卿立秋即事','司空曙','唐','唐诗','tang','','[]','秋宜何處看，試問白雲官。',96,'全唐诗/poet.tang.15000.json','["秋宜何處看，試問白雲官。", "暗入蟬鳴樹，微侵蝶繞蘭。", "向風涼稍動，近日暑猶殘。", "九陌浮埃減，千峯爽氣攢。", "換衣防竹暮，沈果訝泉寒。", "宮響傳花杵，天清出露盤。", "高禽當側弁，遊鮪對憑欄。", "一奏招商曲，空令繼唱難。"]'),
('1b653bd7-8c7e-4265-ab0d-c9fc76da8b1d','和李員外與舍人詠玫瑰花寄徐侍郎','司空曙','唐','唐诗','tang','','[]','仙吏紫薇郎，奇花共翫芳。',96,'全唐诗/poet.tang.15000.json','["仙吏紫薇郎，奇花共翫芳。", "攢星排綠蒂，照眼發紅光。", "暗妬翻堦藥，遙連直署香。", "遊枝蜂繞易，礙刺鳥銜妨。", "露溼凝衣粉，風吹散蕊黃。", "蒙蘢珠樹合，煥爛錦屏張。", "留客勝看竹，思人比愛棠。", "如傳採蘋詠，遠思滿瀟湘。"]'),
('154b41e2-072d-4b2d-8c65-97cbed3f25f4','冬夜耿拾遺王秀才就宿因傷故人','司空曙','唐','唐诗','tang','','[]','舊時聞笛淚，今夜重沾衣。',48,'全唐诗/poet.tang.15000.json','["舊時聞笛淚，今夜重沾衣。", "方恨同人少，何堪相見稀。", "竹煙凝澗壑，林雪似芳菲。", "多謝勞車馬，應憐獨掩扉。"]'),
('ac86261f-08ed-47a0-b127-e776f59d0998','早春遊慈恩南池','司空曙','唐','唐诗','tang','','[]','山寺臨池水，春愁望遠生。',48,'全唐诗/poet.tang.15000.json','["山寺臨池水，春愁望遠生。", "蹋橋逢鶴起，尋竹值泉橫。", "新柳絲猶短，輕蘋葉未成。", "還如虎溪上，日暮伴僧行。"]'),
('71862ef7-dc20-401d-a624-f079b6a089b9','雨夜見投之作','司空曙','唐','唐诗','tang','','[]','出戶繁星盡，池塘暗不開。',48,'全唐诗/poet.tang.15000.json','["出戶繁星盡，池塘暗不開。", "動衣涼氣度，遰樹遠聲來。", "燈外初行電，城隅偶隱雷。", "因知謝文學，曉望比塵埃。"]'),
('648d56c4-71c8-4613-96bb-c1a7e960c20b','龍池寺望月寄韋使君閻別駕','司空曙','唐','唐诗','tang','','[]','清光此夜中，萬古望應同。',48,'全唐诗/poet.tang.15000.json','["清光此夜中，萬古望應同。", "當野山沈霧，低城樹有風。", "花宮紛共邃，水府皓相空。", "遙想高樓上，唯君對庾公。"]'),
('03eab4c0-f265-4545-9574-b9ebdda83b98','秋夜憶興善院寄苗發','司空曙','唐','唐诗','tang','','[]','右軍多住寺，此夜後池秋。',48,'全唐诗/poet.tang.15000.json','["右軍多住寺，此夜後池秋。", "自與山僧伴，那因洛客愁。", "卷簾霜靄靄，滿目水悠悠。", "若有詩相贈，期君憶惠休。"]'),
('bc7e7b02-fa9a-4405-8922-d2fbcba58136','病中寄鄭十六兄','司空曙','唐','唐诗','tang','','[]','倦枕欲徐行，開簾秋月明。',48,'全唐诗/poet.tang.15000.json','["倦枕欲徐行，開簾秋月明。", "手便筇杖冷，頭喜葛巾輕。", "綠草前侵水，黃花半上城。", "虛消此塵景，不見十年兄。"]'),
('04e6eb11-0b8c-4b26-ae73-2c7dc13845dc','衞明府寄枇杷葉以詩荅','司空曙','唐','唐诗','tang','','[]','傾筐呈綠葉，重疊色何鮮。',48,'全唐诗/poet.tang.15000.json','["傾筐呈綠葉，重疊色何鮮。", "詎是秋風裏，猶如曉露前。", "仙方當見重，消疾本應便。", "全勝甘蕉贈，空投謝氏篇。"]'),
('3ba99fff-5db9-4e38-9f05-6e4466a2c150','過慶寶寺','司空曙','唐','唐诗','tang','','[]','黃葉前朝寺，無僧寒殿開。',48,'全唐诗/poet.tang.15000.json','["黃葉前朝寺，無僧寒殿開。", "池晴龜出曝，松暮鶴飛迴。", "古井碑橫草，陰廊畫雜苔。", "禪宮亦銷歇，塵世轉堪哀。"]'),
('aff1a3de-cbb5-4c81-bdbb-a49b5526d5d6','奉和張大夫酬高山人','司空曙','唐','唐诗','tang','','[]','野客居鈴閣，重門將校稀。',48,'全唐诗/poet.tang.15000.json','["野客居鈴閣，重門將校稀。", "豸冠親穀弁，龜印識荷衣。", "座右寒飆爽，談餘暮角微。", "蒼生須太傅，山在豈容歸。"]'),
('5e582786-a770-48c0-b971-06e4a84788dc','送嚴使君遊山','司空曙','唐','唐诗','tang','','[]','家楚依三戶，辭州選一錢。',48,'全唐诗/poet.tang.15000.json','["家楚依三戶，辭州選一錢。", "酒杯同寄世，客櫂任銷年。", "赤燒兼山遠，青蕪與浪連。", "青春明月夜，知上鄂君船。"]'),
('47b2a70e-f226-4aef-9b58-06f835751cab','送柳震歸蜀','司空曙','唐','唐诗','tang','','[]','白日雙流靜，西看蜀國春。',48,'全唐诗/poet.tang.15000.json','["白日雙流靜，西看蜀國春。", "桐花能乳鳥，竹節競祠神。", "蹇步徒相望，先鞭不可親。", "知從江僕射，登榻更何人。"]'),
('a080ba0c-380b-4d9c-abc4-b2f3d092e627','送樂平苗明府','司空曙','唐','唐诗','tang','','[]','天際山多處，東安古邑深。',48,'全唐诗/poet.tang.15000.json','["天際山多處，東安古邑深。", "綠田通竹里，白浪隔楓林。", "詩有江僧和，門唯越客尋。", "應將放魚化，一境表吾心。"]'),
('19eabf31-3e26-479c-a0d1-1345d86cca1d','贈送鄭錢二郎中','司空曙','唐','唐诗','tang','','[]','梅含柳已動，昨日起東風。',48,'全唐诗/poet.tang.15000.json','["梅含柳已動，昨日起東風。", "惆悵心徒壯，無如鬢作翁。", "百年飄若水，萬緒盡歸空。", "何可宗禪客，遲迴岐路中。"]'),
('299c887a-8188-4e6e-ba09-b0df94161482','酬鄭十四望驛不得同宿見贈因寄張參軍','司空曙','唐','唐诗','tang','','[]','逢君喜成淚，暫似故鄉中。',48,'全唐诗/poet.tang.15000.json','["逢君喜成淚，暫似故鄉中。", "謫宦猶多懼，清宵不得終。", "月煙高有鶴，宿草淨無蟲。", "明日郄超會，應思下客同。"]'),
('082b82f8-8cf1-4c6b-9eef-384135b4b898','暮春野望寄錢起','司空曙','唐','唐诗','tang','','[]','草長花落樹，羸病強尋春。',48,'全唐诗/poet.tang.15000.json','["草長花落樹，羸病強尋春。", "無復少年意，空餘華髮新。", "青原高見水，白社靜逢人。", "寄謝南宮客，軒車不可親。"]'),
('8235ff36-99aa-4a40-a364-7a3001c2d0c4','送王使君小子孝廉登科歸省','司空曙','唐','唐诗','tang','','[]','年少通經學，登科尚佩觿。',48,'全唐诗/poet.tang.15000.json','["年少通經學，登科尚佩觿。", "張馮本名士，蔡廓是佳兒。", "鞍馬臨岐路，龍鍾對別離。", "寄書胡太守，請與故人知。"]'),
('813ba0d9-9978-4a68-b5b1-9cd1e9ee82ff','雲陽寺石竹花','司空曙','唐','唐诗','tang','','[]','一自幽山別，相逢此寺中。',48,'全唐诗/poet.tang.15000.json','["一自幽山別，相逢此寺中。", "高低俱出葉，深淺不分叢。", "野蝶難爭白，庭榴暗讓紅。", "誰憐芳最久，春露到秋風。"]'),
('bb1b0816-697c-4727-bd4a-f9392b3c4a88','送高勝重謁曹王','司空曙','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','江上青楓岸，陰陰萬里春。',48,'全唐诗/poet.tang.15000.json','["江上青楓岸，陰陰萬里春。", "朝辭郢城酒，暮見洞庭人。", "興比乘舟訪，恩懷倒屣親。", "想君登舊榭，重喜掃芳塵。"]'),
('8f23af48-ed87-40b3-bbfd-2824769aa0ae','閑園書事招暢當','司空曙','唐','唐诗','tang','','[]','聞蟬晝眠後，欹枕對蓬蒿。',48,'全唐诗/poet.tang.15000.json','["聞蟬晝眠後，欹枕對蓬蒿。", "羸病嬾尋戴，田園方詠陶。", "傍簷蟲挂靜，出樹蝶飛高。", "惆悵臨清鏡，思君見鬢毛。"]'),
('2c1a6bd0-a7fc-4485-97ce-040b34633957','過錢員外','司空曙','唐','唐诗','tang','','[]','爲郎頭已白，跡向市朝稀。',48,'全唐诗/poet.tang.15000.json','["爲郎頭已白，跡向市朝稀。", "移病居荒宅，安貧著敗衣。", "野園隨客醉，雪寺伴僧歸。", "自說東峯下，松蘿滿故扉。"]'),
('3b3cc904-7ddc-4f52-9bf1-4b222cbe804b','贈庾侍御','司空曙','唐','唐诗','tang','','[]','年少身無累，相逢憶此時。',48,'全唐诗/poet.tang.15000.json','["年少身無累，相逢憶此時。", "雪過雲寺宿，酒向竹園期。", "白髮今催老，清琴但起悲。", "唯應逐宗炳，內學願爲師。"]'),
('2cbfbe28-770f-4a19-ab6d-d97df02d83a7','贈李端','司空曙','唐','唐诗','tang','','[]','共憶南浮日，登高望若何。',48,'全唐诗/poet.tang.15000.json','["共憶南浮日，登高望若何。", "楚田湖草遠，江寺海榴多。", "載酒尋山宿，思人帶雪過。", "東西幾回別，此會各磋砣。"]'),
('6be2f191-b7c7-4861-9212-88a2eb7a5723','送流人','司空曙','唐','唐诗','tang','','[]','聞說南中事，悲君重竄身。',48,'全唐诗/poet.tang.15000.json','["聞說南中事，悲君重竄身。", "山村楓子鬼，江廟石郎神。", "童稚留荒宅，圖書託故人。", "青門好風景，爲爾一沾巾。"]'),
('e7be83d2-4e68-46e2-8fad-dbfafd0e5379','過胡居士覩王右丞遺文','司空曙','唐','唐诗','tang','','[]','舊日相知盡，深居獨一身。',48,'全唐诗/poet.tang.15000.json','["舊日相知盡，深居獨一身。", "閉門空有雪，看竹永無人。", "每許前山隱，曾憐陋巷貧。", "題詩今尚在，暫爲拂流塵。"]'),
('f66d3849-b32b-41d8-8bc0-8845cb0eb7ed','送郎使君赴郢州','司空曙','唐','唐诗','tang','','[]','使君持節去，雲水滿前程。',48,'全唐诗/poet.tang.15000.json','["使君持節去，雲水滿前程。", "楚寺多連竹，江檣遠暎城。", "登樓向月望，賽廟傍山行。", "若動思鄉詠，應貽謝步兵。"]'),
('4c745990-657a-41fe-ba2c-d9cf371ca563','賊平後送人北歸','司空曙','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u916c\u8d60", "\u611f\u4f24", "\u4e94\u8a00\u5f8b\u8bd7"]','世亂同南去，時清獨北還。',48,'全唐诗/poet.tang.15000.json','["世亂同南去，時清獨北還。", "他鄉生白髮，舊國見青山。", "曉月過殘壘，繁星宿故關。", "寒禽與衰草，處處伴愁顏。"]'),
('4ea9c5d8-c3dd-45cf-911e-e602fca2ff75','觀獵騎','司空曙','唐','唐诗','tang','','[]','纏臂繡綸巾，貂裘窄稱身。',48,'全唐诗/poet.tang.15000.json','["纏臂繡綸巾，貂裘窄稱身。", "射禽風助箭，走馬雪翻塵。", "金埒爭開道，香車爲駐輪。", "翩翩不知處，傳是霍家親。"]'),
('47948a17-85bc-4a79-815b-888a7c0a47a4','同苗員外宿薦福常師房','司空曙','唐','唐诗','tang','','[]','浮生共多故，聚宿喜君同。',48,'全唐诗/poet.tang.15000.json','["浮生共多故，聚宿喜君同。", "人息時聞磬，燈搖乍有風。", "霜堦疑水際，夜木似山中。", "一願持如意，長來事遠公。"]'),
('20b23989-2e5d-4587-b486-e8f3b2b100a0','送喬廣下第歸淮南','司空曙','唐','唐诗','tang','','[]','遙想長淮盡，荒堤楚路斜。',48,'全唐诗/poet.tang.15000.json','["遙想長淮盡，荒堤楚路斜。", "戍旌標白浪，罟網入青葭。", "啼鳥仍臨水，愁人更見花。", "東堂一枝在，爲子惜年華。"]'),
('d03165d5-faef-44bc-9e9b-9e3c16cbcb7d','風箏','司空曙','唐','唐诗','tang','','[]','高風吹玉柱，萬籟忽齊飄。',48,'全唐诗/poet.tang.15000.json','["高風吹玉柱，萬籟忽齊飄。", "颯樹遲難度，縈空細漸銷。", "松泉鹿門夜，笙鶴洛濱朝。", "坐與真僧聽，支頤向寂寥。"]'),
('febd291a-db2c-48d0-9891-249237e794be','閑居寄苗發','司空曙','唐','唐诗','tang','','[]','漸向浮生老，前期竟若何。',48,'全唐诗/poet.tang.15000.json','["漸向浮生老，前期竟若何。", "獨身居處靜，永夜坐時多。", "厭逐青林客，休吟白雪歌。", "支公有遺寺，重與謝安過。"]'),
('bc1d4a33-47ed-4e34-b7da-ae8d0347efa9','送王先生歸南山','司空曙','唐','唐诗','tang','','[]','儒中年最老，獨有濟南生。',48,'全唐诗/poet.tang.15000.json','["儒中年最老，獨有濟南生。", "愛子方傳業，無官自耦耕。", "竹通山舍遠，雲接雪田平。", "願作門人去，相隨隱姓名。"]'),
('ee741325-dc51-4625-8bb5-20d477c3efaa','寄天台秀師','司空曙','唐','唐诗','tang','','[]','天台瀑布寺，傳有白頭師。',48,'全唐诗/poet.tang.15000.json','["天台瀑布寺，傳有白頭師。", "幻跡示羸病，空門無住持。", "雪晴看鶴去，海夜與龍期。", "永願親瓶屨，呈功得問疑。"]'),
('d3435bf5-5dcb-4b55-9cf1-216b699c96d0','送夏侯審赴寧國','司空曙','唐','唐诗','tang','','[]','青圻連白浪，曉日渡南津。',48,'全唐诗/poet.tang.15000.json','["青圻連白浪，曉日渡南津。", "山疊陵陽樹，舟多建業人。", "煙霞高占寺，楓竹暗停神。", "如接玄暉集，江丞獨見親。"]'),
('3138fe30-6cf6-45b0-a441-2d5398107a9a','雲陽館與韓紳宿別','司空曙','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u53cb\u60c5", "\u4e94\u8a00\u5f8b\u8bd7", "\u60dc\u522b"]','故人江海別，幾度隔山川。',48,'全唐诗/poet.tang.15000.json','["故人江海別，幾度隔山川。", "乍見翻疑夢，相悲各問年。", "孤燈寒照雨，溼竹暗浮煙。", "更有明朝恨，離杯惜共傳。"]'),
('2be9ac64-89a2-43ac-a980-16aa2497fe02','送盧使君赴夔州','司空曙','唐','唐诗','tang','','[]','鐃管隨旌斾，高秋遠上巴。',48,'全唐诗/poet.tang.15000.json','["鐃管隨旌斾，高秋遠上巴。", "白波連霧雨，青壁斷蒹葭。", "凭几雙童靜，登樓萬井斜。", "政成知變俗，當應畫輪車。"]'),
('ed7ad319-24c2-47d1-86be-f99ec92feccc','夜聞回雁','司空曙','唐','唐诗','tang','','[]','雁響天邊過，高高望不分。',48,'全唐诗/poet.tang.15000.json','["雁響天邊過，高高望不分。", "颼飀傳細雨，嘹唳隔長雲。", "散向誰家盡，歸來幾客聞。", "還將今夜意，西海話蘇君。"]'),
('db5eca9b-a4c0-4b33-b1d3-629b78362f6c','賦得的的帆向浦','司空曙','唐','唐诗','tang','','[]','向浦參差去，隨波遠近還。',48,'全唐诗/poet.tang.15000.json','["向浦參差去，隨波遠近還。", "初移芳草裏，正在夕陽間。", "隱暎回孤驛，微明出亂山。", "向空看不盡，歸思滿江關。"]'),
('6cae6c3b-725f-42f5-95ab-a78b42582b10','秋思呈尹植裴說','司空曙','唐','唐诗','tang','','[]','靜向嬾相偶，年將衰共催。',48,'全唐诗/poet.tang.15000.json','["靜向嬾相偶，年將衰共催。", "前途懽不集，往事恨空來。", "晝景委紅葉，月華銷綠苔。", "沈思竟何有，坐結玉琴哀。"]'),
('e2740c24-d6db-4562-81ff-be9f0bfe16e0','閑園即事寄暕公','司空曙','唐','唐诗','tang','','[]','欲就東林寄一身，尚憐兒女未成人。',64,'全唐诗/poet.tang.15000.json','["欲就東林寄一身，尚憐兒女未成人。", "柴門客去殘陽在，藥圃蟲喧秋雨頻。", "近水方同梅市隱，曝衣多笑阮家貧。", "深山蘭若何時到，羨與閑雲作四鄰。"]'),
('99025f97-6135-4fb8-b5dc-0e41106cb643','題暕上人院','司空曙','唐','唐诗','tang','','[]','閉門不出自焚香，擁褐看山歲月長。',64,'全唐诗/poet.tang.15000.json','["閉門不出自焚香，擁褐看山歲月長。", "雨後綠苔生石井，秋來黃葉遍繩牀。", "身閑何處無真性，年老曾言隱故鄉。", "更說本師同學在，幾時攜手見衡陽。"]'),
('59da8f38-abd3-4af3-b549-7b9ef4aec01f','長安曉望寄程補闕','司空曙','唐','唐诗','tang','','[]','迢遰山河擁帝京，參差宮殿接雲平。',64,'全唐诗/poet.tang.15000.json','["迢遰山河擁帝京，參差宮殿接雲平。", "風吹曉漏經長樂，柳帶晴煙出禁城。", "天淨笙歌臨路發，日高車馬隔塵行。", "獨有淺才甘未達，多慙名在魯諸生。"]'),
('0d8d840d-1f94-44da-9b52-18a01cf8ed82','下第日書情寄上叔父','司空曙','唐','唐诗','tang','','[]','微才空覺滯京師，末學曾爲叔父知。',64,'全唐诗/poet.tang.15000.json','["微才空覺滯京師，末學曾爲叔父知。", "雪裏題詩偏見賞，林間飲酒獨令隨。", "遊客盡傷春色老，貧居還惜暮陰移。", "欲歸江海尋山去，願報何人得桂枝。"]'),
('550d7a0c-eb74-46c2-8bd8-7e837642be87','南原望漢宮','司空曙','唐','唐诗','tang','','[]','荒原空有漢宮名，衰草茫茫雉堞平。',64,'全唐诗/poet.tang.15000.json','["荒原空有漢宮名，衰草茫茫雉堞平。", "連雁下時秋水在，行人過盡暮煙生。", "西陵歌吹何年絕，南陌登臨此日情。", "故事悠悠不可問，寒禽野水自縱橫。"]'),
('6fb9719a-8cb6-4597-9e8a-a3d833addf5b','早夏寄元校書','司空曙','唐','唐诗','tang','','[]','獨遊野徑送芳菲，高竹林居接翠微。',64,'全唐诗/poet.tang.15000.json','["獨遊野徑送芳菲，高竹林居接翠微。", "綠岸草深蟲入徧，青藂花盡蝶來稀。", "珠荷薦果香寒簟，玉柄搖風滿夏衣。", "蓬蓽永無車馬到，更當齋夜憶玄暉。"]'),
('bdd14fd6-3be3-4f4f-acb7-4c8080ee8c83','贈衡岳隱禪師','司空曙','唐','唐诗','tang','','[]','擁褐安居南岳頭，白雲高寺見衡州。',64,'全唐诗/poet.tang.15000.json','["擁褐安居南岳頭，白雲高寺見衡州。", "石窗湖水搖寒月，楓樹猨聲報夜秋。", "講席舊逢山鳥至，梵經初向竺僧求。", "垂垂身老將傳法，因下人間逐北遊。"]'),
('225e5b02-b302-47a3-b95f-526b2acd82ac','題凌雲寺','司空曙','唐','唐诗','tang','','[]','春山古寺遶滄波，石磴盤空鳥道過。',64,'全唐诗/poet.tang.15000.json','["春山古寺遶滄波，石磴盤空鳥道過。", "百丈金身開翠壁，萬龕燈焰隔煙蘿。", "雲生客到侵衣溼，花落僧禪覆地多。", "不與方袍同結社，下歸塵世竟如何。"]'),
('e00db95a-acd8-4924-84e7-97b8e8adbb46','晦日益州北池陪宴','司空曙','唐','唐诗','tang','','[]','臨泛從公日，仙舟翠幕張。',96,'全唐诗/poet.tang.15000.json','["臨泛從公日，仙舟翠幕張。", "七橋通碧沼，雙樹接花塘。", "玉燭收寒氣，金波隱夕光。", "野聞歌管思，水靜綺蘿香。", "遊騎縈林遠，飛橈截岸長。", "郊原懷灞滻，陂溠寫江潢。", "常侍傳花詔，偏裨問羽觴。", "豈令南峴首，千載播餘芳。"]'),
('bf48fb27-3e4f-4381-901d-e3a806a81e1a','送曲山人之衡州','司空曙','唐','唐诗','tang','','["\u8861\u5c71"]','白石先生眉髮光，已分甜雪飲紅漿。',64,'全唐诗/poet.tang.15000.json','["白石先生眉髮光，已分甜雪飲紅漿。", "衣巾半染煙霞氣，語笑兼和藥草香。", "茅洞玉聲流暗水，衡山碧色暎朝陽。", "千年城郭如相問，華表峩峩有夜霜。"]'),
('a463ea97-2744-4c09-bf65-d6681e6e4136','立秋日','司空曙','唐','唐诗','tang','','[]','律變新秋至，蕭條自此初。',72,'全唐诗/poet.tang.15000.json','["律變新秋至，蕭條自此初。", "花酣蓮報謝，葉在柳呈疎。", "澹日非雲暎，清風似雨餘。", "卷簾涼暗度，迎扇暑先除。", "草靜多翻燕，波澄乍露魚。", "今朝散騎省，作賦興何如。"]'),
('52aff993-0d3e-45d1-9e5c-a6bc5cd8c966','詠古寺花','司空曙','唐','唐诗','tang','','[]','共愛芳菲此樹中，千跗萬萼裹枝紅。',32,'全唐诗/poet.tang.15000.json','["共愛芳菲此樹中，千跗萬萼裹枝紅。", "遲遲欲去猶回望，覆地無人滿寺風。"]'),
('fb725498-003a-4a42-b634-c91f9813b47b','酬張芬有赦後見贈','司空曙','唐','唐诗','tang','','[]','紫鳳朝銜五色書，陽春忽布網羅除。',64,'全唐诗/poet.tang.15000.json','["紫鳳朝銜五色書，陽春忽布網羅除。", "已將心變寒灰後，豈料光生腐草餘。", "建水風煙收客淚，杜陵花竹夢郊居。", "勞君故有詩相贈，欲報瓊瑤恨不如。"]'),
('261d8e84-5e2f-4729-abc7-9e3c6730fa80','哭苗員外呈張參軍','司空曙','唐','唐诗','tang','','[]','思君甯家宅，久接竹林期。',96,'全唐诗/poet.tang.15000.json','["思君甯家宅，久接竹林期。", "嘗值偷琴處，親聞比玉時。", "高人不易合，弱冠早相知。", "試藝臨諸友，能文即我師。", "凌寒松未老，先暮槿何衰。", "季子生前別，羊曇醉後悲。", "壽堂乖一慟，奠席阻長辭。", "因瀝殊方淚，遙成墓下詩。"]'),
('2bba5a88-ee75-4eb5-9ab9-4b6f27402147','金陵懷古','司空曙','唐','唐诗','tang','','[]','輦路江楓暗，宮庭野草春。',24,'全唐诗/poet.tang.15000.json','["輦路江楓暗，宮庭野草春。", "傷心庾開府，老作北朝臣。"]'),
('4c06e70d-d153-4fb4-bea7-1398ff964273','發渝州却寄韋判官','司空曙','唐','唐诗','tang','','[]','紅燭津亭夜見君，繁弦急管兩紛紛。',32,'全唐诗/poet.tang.15000.json','["紅燭津亭夜見君，繁弦急管兩紛紛。", "平明分手空江轉，唯有猨聲滿水雲。"]'),
('6c89eb3c-9aed-4afd-89cd-c424aaf88f86','送盧徹之太原謁馬尚書','司空曙','唐','唐诗','tang','','[]','榆落鵰飛關塞秋，黃雲畫角見幷州。',32,'全唐诗/poet.tang.15000.json','["榆落鵰飛關塞秋，黃雲畫角見幷州。", "翩翩羽騎雙旌後，上客親隨郭細侯。"]'),
('ddf96d5e-ba4c-4bbc-9630-f4cc54d871a5','峽口送友人','司空曙','唐','唐诗','tang','','["\u79bb\u522b", "\u6625\u5929"]','峽口花飛欲盡春，天涯去住淚沾巾。',32,'全唐诗/poet.tang.15000.json','["峽口花飛欲盡春，天涯去住淚沾巾。", "來時萬里同爲客，今日飜成送故人。"]'),
('12fc2689-c215-415e-bc92-1ea4ea9d2a6a','故郭婉儀挽歌','司空曙','唐','唐诗','tang','','[]','一日辭秦鏡，千秋別漢宮。',48,'全唐诗/poet.tang.15000.json','["一日辭秦鏡，千秋別漢宮。", "豈唯泉路掩，長使月輪空。", "苦色凝朝露，悲聲切暝風。", "婉儀餘舊德，仍載禮經中。"]'),
('13bb39b1-aeed-46ae-9576-315d59c1ddb5','送翰林張學士嶺南勒聖碑','司空曙','唐','唐诗','tang','','[]','漢恩天外洽，周頌日邊稱。',48,'全唐诗/poet.tang.15000.json','["漢恩天外洽，周頌日邊稱。", "文獨司空羨，書兼太尉能。", "出關逢北雁，度嶺逐南鵬。", "使者翰林客，餘春歸灞陵。"]'),
('7e77befb-75da-4226-b95d-0b44902bbb2e','送吉校書東歸','司空曙','唐','唐诗','tang','','[]','少年芸閣吏，罷直暫歸休。',48,'全唐诗/poet.tang.15000.json','["少年芸閣吏，罷直暫歸休。", "獨與親知別，行逢江海秋。", "聽猨看楚岫，隨雁到吳洲。", "處處園林好，何人待子猷。"]'),
('d48cbe05-7d5a-4d01-a798-9b64117b301b','早春遊望','司空曙','唐','唐诗','tang','','[]','東風春未足，試望秦城曲。',48,'全唐诗/poet.tang.15000.json','["東風春未足，試望秦城曲。", "青草狀寒蕪，黃花似秋菊。", "壯將歡共去，老與悲相逐。", "獨作遊社人，暮過威輦宿。"]'),
('e4fa2591-498f-46a4-8fa5-d813a13a1786','秋日趨府上張大夫','司空曙','唐','唐诗','tang','','[]','重城洞啓肅秋煙，共說羊公在鎮年。',64,'全唐诗/poet.tang.15000.json','["重城洞啓肅秋煙，共說羊公在鎮年。", "鞞鼓暗驚林葉落，旌旗遙拂雁行偏。", "石過橋下書曾受，星降人間夢已傳。", "謫吏何能沐風化，空將歌頌拜車前。"]'),
('50540ff5-7284-49dc-bcf1-73c8171e4bea','竹裏徑','司空曙','唐','唐诗','tang','','[]','幽徑行迹稀，清陰苔色古。',24,'全唐诗/poet.tang.15000.json','["幽徑行迹稀，清陰苔色古。", "蕭蕭風欲來，乍似蓬山雨。"]'),
('c14e9734-cec8-445e-8d03-88d75a42f48e','黃子陂','司空曙','唐','唐诗','tang','','[]','岸芳春色曉，水影夕陽微。',24,'全唐诗/poet.tang.15000.json','["岸芳春色曉，水影夕陽微。", "寂寂深煙裏，漁舟夜不歸。"]'),
('7b9bc8ca-355e-44fc-84f9-edb83ba18dd9','田鶴','司空曙','唐','唐诗','tang','','[]','散下渚田中，隱見菰蒲裏。',24,'全唐诗/poet.tang.15000.json','["散下渚田中，隱見菰蒲裏。", "哀鳴自相應，欲作凌風起。"]'),
('9ec10c43-5c07-40b9-a1e5-3684a31e3097','藥園','司空曙','唐','唐诗','tang','','[]','春園芳已遍，綠蔓雜紅英。',24,'全唐诗/poet.tang.15000.json','["春園芳已遍，綠蔓雜紅英。", "獨有深山客，時來辨藥名。"]'),
('bb578632-7e3b-45ba-af1e-adb0a6b4e805','石井','司空曙','唐','唐诗','tang','','[]','苔色遍春石，桐陰入寒井。',24,'全唐诗/poet.tang.15000.json','["苔色遍春石，桐陰入寒井。", "幽人獨汲時，先樂殘陽影。"]'),
('66f33bac-616c-4430-a850-efbd43761213','板橋','司空曙','唐','唐诗','tang','','[]','橫遮野水石，前帶荒村道。',24,'全唐诗/poet.tang.15000.json','["橫遮野水石，前帶荒村道。", "來往見愁人，清風柳陰好。"]'),
('e44c5577-e518-4ead-a5c3-1940c86f0c8b','石蓮花','司空曙','唐','唐诗','tang','','[]','今逢石上生，本自波中有。',24,'全唐诗/poet.tang.15000.json','["今逢石上生，本自波中有。", "紅豔秋風裏，誰憐衆芳後。"]'),
('9649f4dc-e18d-4b00-bb8c-018e0d725b03','遠寺鐘','司空曙','唐','唐诗','tang','','[]','杳杳疎鐘發，因風清復引。',24,'全唐诗/poet.tang.15000.json','["杳杳疎鐘發，因風清復引。", "中宵獨聽之，似與東林近。"]'),
('2e604fca-c9bc-4c80-a76b-102ba0c23af6','松下雪','司空曙','唐','唐诗','tang','','[]','不隨晴野盡，獨向深松積。',24,'全唐诗/poet.tang.15000.json','["不隨晴野盡，獨向深松積。", "落照入寒光，偏能伴幽寂。"]'),
('35577519-453b-4de0-a631-080f9f90eca2','新柳','司空曙','唐','唐诗','tang','','["\u67f3\u6811"]','全欺芳蕙晚，似妬寒梅疾。',24,'全唐诗/poet.tang.15000.json','["全欺芳蕙晚，似妬寒梅疾。", "撩亂發青條，春風來幾日。"]'),
('852b6ae2-62ae-486b-b236-dd51254e743a','唐昌公主院看花','司空曙','唐','唐诗','tang','','[]','遺殿空長閉，乘鸞自不回。',24,'全唐诗/poet.tang.15000.json','["遺殿空長閉，乘鸞自不回。", "至今荒草上，寥落舊花開。"]'),
('1f73ad47-4dc9-4422-83fd-04a6600e0328','別張讚','司空曙','唐','唐诗','tang','','[]','今日山晴後，殘蟬菊發時。',24,'全唐诗/poet.tang.15000.json','["今日山晴後，殘蟬菊發時。", "登樓見秋色，何處最相思。"]'),
('fe83cf62-7214-467e-ac9a-f776ab75a95b','晚思','司空曙','唐','唐诗','tang','','[]','蛩餘窗下月，草溼堦前露。',24,'全唐诗/poet.tang.15000.json','["蛩餘窗下月，草溼堦前露。", "晚景淒我衣，秋風入庭樹。"]'),
('faafba66-ea77-4659-a4f3-705e983987ef','留盧秦卿','司空曙','唐','唐诗','tang','','["\u9001\u522b"]','知有前期在，難分此夜中。',24,'全唐诗/poet.tang.15000.json','["知有前期在，難分此夜中。", "無將故人酒，不及石尤風。"]'),
('844a6888-158d-4ffd-9b8f-89fce8d79c9f','登峴亭','司空曙','唐','唐诗','tang','','[]','峴山回首望秦關，南向荆州幾日還。',32,'全唐诗/poet.tang.15000.json','["峴山回首望秦關，南向荆州幾日還。", "今日登臨唯有淚，不知風景在何山。"]'),
('f8bd6aed-f7ef-403a-9584-cef60350368d','哭麴山人','司空曙','唐','唐诗','tang','','[]','憶昔秋風起，君曾歎逐臣。',24,'全唐诗/poet.tang.15000.json','["憶昔秋風起，君曾歎逐臣。", "何言芳草日，自作九泉人。"]'),
('b1b981cd-d3a7-4739-b886-a6e4f6bf2b09','過堅上人故院與李端同賦','司空曙','唐','唐诗','tang','','[]','舊依支遁宿，曾與戴顒來。',24,'全唐诗/poet.tang.15000.json','["舊依支遁宿，曾與戴顒來。", "今日空林下，唯知見綠苔。"]'),
('aa4585b5-4390-49ad-9a27-43904499dff1','病中嫁女妓','司空曙','唐','唐诗','tang','','[]','萬事傷心在目前，一身垂淚對花筵。',32,'全唐诗/poet.tang.15000.json','["萬事傷心在目前，一身垂淚對花筵。", "黃金用盡教歌舞，留與他人樂少年。"]'),
('64d3f88f-ce69-4ea3-8646-5635a7ed9139','江村即事','司空曙','唐','唐诗','tang','','["\u4e61\u6751", "\u751f\u6d3b", "\u5199\u666f", "\u519c\u6751"]','釣罷歸來不繫船，江村月落正堪眠。',32,'全唐诗/poet.tang.15000.json','["釣罷歸來不繫船，江村月落正堪眠。", "縱然一夜風吹去，只在蘆花淺水邊。"]'),
('ecd1b88c-bfc0-46b0-a91a-802f435755b6','送鄭明府貶嶺南','司空曙','唐','唐诗','tang','','[]','青楓江色晚，楚客獨傷春。',48,'全唐诗/poet.tang.15000.json','["青楓江色晚，楚客獨傷春。", "共對一尊酒，相看萬里人。", "猜嫌成謫宦，正直不防身。", "莫畏炎方久，年年雨露新。"]'),
('2c044e03-74a7-41e1-a28e-1386228564c3','寄衞明府常見短靴褐裘又務持誦是以有末句之贈','司空曙','唐','唐诗','tang','','[]','柴桑官舍近東林，兒稚初髫即道心。',64,'全唐诗/poet.tang.15000.json','["柴桑官舍近東林，兒稚初髫即道心。", "側寄繩牀嫌凭几，斜安苔幘嬾穿簪。", "高僧靜望山僮逐，走吏喧來水鴨沈。", "翠竹黃花皆佛性，莫教塵境誤相侵。"]'),
('3e6f3ca9-f771-438d-8f5f-75ba5b802739','酬李端校書見贈','司空曙','唐','唐诗','tang','','[]','綠槐垂穗乳烏飛，忽憶山中獨未歸。',64,'全唐诗/poet.tang.15000.json','["綠槐垂穗乳烏飛，忽憶山中獨未歸。", "青鏡流年看髮變，白雲芳草與心違。", "乍逢酒客春遊慣，久別林僧夜坐稀。", "昨日聞君到城闕，莫將簪弁勝荷衣。"]'),
('f3dcc157-7b7f-43a1-b884-2aec0694612e','過盧秦卿舊居','司空曙','唐','唐诗','tang','','[]','五柳茅茨楚國賢，桔槔蔬圃水涓涓。',64,'全唐诗/poet.tang.15000.json','["五柳茅茨楚國賢，桔槔蔬圃水涓涓。", "黃花寒後難逢蝶，紅葉晴來忽有蟬。", "韓康助採君臣藥，支遁同看內外篇。", "爲問潛夫空著論，如何侍從賦甘泉。"]'),
('559dd818-124e-426b-8304-585076bece88','秋園','司空曙','唐','唐诗','tang','','[]','傷秋不是惜年華，別憶春風碧玉家。',32,'全唐诗/poet.tang.15000.json','["傷秋不是惜年華，別憶春風碧玉家。", "強向衰藂見芳意，茱萸紅實似繁花。"]'),
('6d528dd1-986f-4758-bec4-909824a7f6c8','送王使君赴太原拜節度副使','司空曙','唐','唐诗','tang','','[]','新從劉太尉，結束向幷州。',72,'全唐诗/poet.tang.15000.json','["新從劉太尉，結束向幷州。", "絡腦青絲騎，盤囊錦帶鉤。", "出關逢將校，下嶺擁戈矛。", "匣閉黃雲冷，山傳畫角秋。", "劒鋒將破虜，函道罷登樓。", "豈作書生老，當封萬戶侯。"]'),
('9390e66b-2b88-4f90-a37b-3ae3a18bb5e9','擬百勞歌','司空曙','唐','唐诗','tang','','[]','朱絲紐弦金點雜，雙蔕芙蓉共開合。',80,'全唐诗/poet.tang.15000.json','["朱絲紐弦金點雜，雙蔕芙蓉共開合。", "誰家稚女著羅裳，紅粉青眉嬌暮妝。", "木難作牀牙作席，雲母屏風光照壁。", "玉顏年幾新上頭，迴身斂笑多自羞。", "紅銷月落不復見，可惜當時誰拂面。"]'),
('e1b193e2-3062-4ac7-971b-33f310c12e93','迎神','司空曙','唐','唐诗','tang','','[]','吉日兮臨水，沐青蘭兮白芷。',75,'全唐诗/poet.tang.15000.json','["吉日兮臨水，沐青蘭兮白芷。", "假山鬼兮請東皇，託靈均兮邀帝子。", "吹參差兮正苦，舞婆娑兮未已。", "鸞旌圓蓋望欲來，山雨霏霏江浪起。", "神既降兮我獨知，目成再拜爲陳詞。"]'),
('96d11aa0-418d-4fb9-a31c-248cb6edb341','送神','司空曙','唐','唐诗','tang','','[]','神之去，迴風嫋嫋雲容與。',28,'全唐诗/poet.tang.15000.json','["神之去，迴風嫋嫋雲容與。", "桂尊瑤席不復陳，蒼山綠水暮愁人。"]'),
('b47d819e-df0d-47a8-8864-5aadeb8190f8','殘鶯百囀歌同王員外耿拾遺吉中孚李端遊慈恩各賦一物','司空曙','唐','唐诗','tang','','[]','殘鶯一何怨，百囀相尋續。',190,'全唐诗/poet.tang.15000.json','["殘鶯一何怨，百囀相尋續。", "始辨下將高，稍分長復促。", "綿蠻巧狀語，機節終如曲。", "野客賞應遲，幽僧聞詎足。", "禪齋深樹夏陰清，零落空餘三兩聲。", "金谷箏中傳不似，山陽笛裏寫難成。", "憶昨亂啼無遠近，晴宮曉色偏相引。", "送暖初隨柳色來，辭芳暗逐花枝盡。", "歌殘鶯，歌殘鶯，悠然萬感生。", "謝朓羇懷方一聽，何郎閑吟本多情。", "乃知衆鳥非儔比，暮噪晨鳴倦人耳。", "共愛奇音那可親，年年出谷待新春。", "此時斷絕爲君惜，明日玄蟬催髮白。"]'),
('048e688e-e32f-4dd7-9278-c83ab555f771','過終南柳處士','司空曙','唐','唐诗','tang','','[]','雲起山蒼蒼，林居蘿薜荒。',72,'全唐诗/poet.tang.15000.json','["雲起山蒼蒼，林居蘿薜荒。", "幽人老深境，素髮與青裳。", "雨滌莓苔綠，風搖松桂香。", "洞泉分溜淺，巖筍出藂長。", "敗屨安松砌，餘棊在石牀。", "書名一爲別，還路已堪傷。"]'),
('b62f493a-1634-4d07-a453-c2b51840ca9b','春送郭大之官','司空曙','唐','唐诗','tang','','[]','明府之官官舍春，春風辭我兩三人。',32,'全唐诗/poet.tang.15000.json','["明府之官官舍春，春風辭我兩三人。", "可憐江縣閑無事，手板支頤獨詠貧。"]'),
('4e5cc00a-1a2a-4a6a-9a98-2bea7f08255b','送鄭錫','司空曙','唐','唐诗','tang','','[]','漢陽雲樹清無極，蜀國風煙思不堪。',32,'全唐诗/poet.tang.15000.json','["漢陽雲樹清無極，蜀國風煙思不堪。", "莫怪別君偏有淚，十年曾事晉征南。"]'),
('4d524713-c72f-4d10-b632-f4cfab9abece','同張參軍喜李尚書寄新琴','司空曙','唐','唐诗','tang','','[]','新琴傳鳳凰，晴景稱高張。',72,'全唐诗/poet.tang.15000.json','["新琴傳鳳凰，晴景稱高張。", "白玉連徽淨，朱絲繫爪長。", "輕埃隨拂拭，雜籟滿鏗鏘。", "暗想山泉合，如親蘭蕙芳。", "正聲消鄭衞，古狀掩笙簧。", "遠識賢人意，清風願激揚。"]'),
('4cbf0ade-9d50-476d-84b2-c20f21697c4c','苦熱','司空曙','唐','唐诗','tang','','[]','暑氣發炎州，焦煙遠未收。',72,'全唐诗/poet.tang.15000.json','["暑氣發炎州，焦煙遠未收。", "嘯風兼熾燄，揮汗訝成流。", "鸛鵲投林盡，龜魚擁石稠。", "漱泉齊飲酎，衣葛劇兼裘。", "長簟貪欹枕，輕巾嬾挂頭。", "招商如有曲，一爲取新秋。"]'),
('2fea3769-7cab-4c8d-9a7b-5a9d654b9573','送人歸黔府','司空曙','唐','唐诗','tang','','[]','伏波簫鼓水雲中，長戟如霜大斾紅。',32,'全唐诗/poet.tang.15000.json','["伏波簫鼓水雲中，長戟如霜大斾紅。", "油幕曉開飛鳥絕，翩翩上將獨趨風。"]'),
('5f8c955d-332c-40ee-bb64-017021a187b9','雜興','司空曙','唐','唐诗','tang','','[]','月沒遼城暗出師，雙龍金角曉天悲。',32,'全唐诗/poet.tang.15000.json','["月沒遼城暗出師，雙龍金角曉天悲。", "黃塵滿目隨風散，不認將軍燕尾旗。"]'),
('002d65d7-a386-46f1-8c8f-007095ec68bd','歲暮懷崔峒耿湋','司空曙','唐','唐诗','tang','','[]','臘月江天見春色，白花青柳疑寒食。',32,'全唐诗/poet.tang.15000.json','["臘月江天見春色，白花青柳疑寒食。", "洛陽舊社各東西，楚國遊人不相識。"]'),
('a66209d3-155e-41b7-b272-8344f078847c','觀妓','司空曙','唐','唐诗','tang','','[]','翠蛾紅臉不勝情，管絕弦餘發一聲。',32,'全唐诗/poet.tang.15000.json','["翠蛾紅臉不勝情，管絕弦餘發一聲。", "銀燭搖搖塵暗下，却愁紅粉淚痕生。"]'),
('87ea72d1-8b8b-402f-b331-79f7a24dea41','過長林湖西酒家','司空曙','唐','唐诗','tang','','[]','湖草青青三兩家，門前桃杏一般花。',32,'全唐诗/poet.tang.15000.json','["湖草青青三兩家，門前桃杏一般花。", "遷人到處唯求醉，聞說漁翁有酒賒。"]'),
('83c73d1e-bc22-4ba1-8974-2c8354de41cd','過閻采病居','司空曙','唐','唐诗','tang','','[]','每逢佳節何曾坐，唯有今年不得遊。',32,'全唐诗/poet.tang.15000.json','["每逢佳節何曾坐，唯有今年不得遊。", "張邴臥來休送客，菊花楓葉向誰秋。"]'),
('d2454276-7690-4f8a-8a84-f594d3856f05','送程秀才','司空曙','唐','唐诗','tang','','[]','悠悠多路岐，相見又別離。',72,'全唐诗/poet.tang.15000.json','["悠悠多路岐，相見又別離。", "東風催節換，燄燄春陽散。", "楚草漸煙綿，江雲亦蕪漫。", "送子恨何窮，故關如夢中。", "遊人盡還北，旅雁辭南國。", "楓樹幾回青，逐臣歸不得。"]'),
('e3855367-0506-4851-a0e0-289ce9bf8f7e','長林令衞象餳絲結歌','司空曙','唐','唐诗','tang','','[]','主人琱盤盤素絲，寒女眷眷墨子悲。',124,'全唐诗/poet.tang.15000.json','["主人琱盤盤素絲，寒女眷眷墨子悲。", "乃言假使餳爲之，八珍重沓失顏色。", "手援玉筯不敢持，始狀芙蓉新出水。", "仰坼重衣傾萬蕊，又如合歡交亂枝。", "紅茸向暮花參差，吳蠶絡繭抽尚絕。", "細縷纖毫看欲滅，雪髮羞垂倭墮鬟。", "繡囊畏並茱萸結，我愛此絲巧。", "妙絕世間無，爲君作歌陳座隅。"]'),
('2a438ef5-b62e-4e29-9a48-b507796e5ba2','酬崔峒見寄','司空曙','唐','唐诗','tang','','[]','趨陪禁掖雁行隨，遷放江潭鶴髮垂。',64,'全唐诗/poet.tang.15000.json','["趨陪禁掖雁行隨，遷放江潭鶴髮垂。", "素浪遙疑太液水，青楓忽似萬年枝。", "嵩南春遍愁魂夢，壺口雲深隔路岐。", "共望漢朝多沛澤，蒼蠅早晚得先知。"]'),
('d2f4fe85-03f9-467c-a6f9-8d9a435fdbf2','聞春雷','司空曙','唐','唐诗','tang','','[]','水國春雷早，闐闐若衆車。',24,'全唐诗/poet.tang.15000.json','["水國春雷早，闐闐若衆車。", "自憐遷逐者，猶滯蟄藏餘。"]'),
('3ed0cf4f-099d-4637-b8af-0a6b30356b98','晚秋西省寄上李韓二舍人','司空曙','唐','唐诗','tang','','[]','晝漏傳清唱，天恩禁旅秋。',48,'全唐诗/poet.tang.15000.json','["晝漏傳清唱，天恩禁旅秋。", "雁親承露掌，砧隔曝衣樓。", "賜膳中人送，餘香侍女收。", "仍聞勞上直，晚步鳳池頭。"]'),
('cd9b9080-f3c9-4e70-8a5a-00f34b32569c','下武昌江行望涔陽','司空曙','唐','唐诗','tang','','[]','悠悠次楚鄉，楚口下涔陽。',48,'全唐诗/poet.tang.15000.json','["悠悠次楚鄉，楚口下涔陽。", "雪隱洲渚暗，沙高蘆荻黃。", "漁人共留滯，水鳥自喧翔。", "懷土年空盡，春風又淼茫。"]'),
('ab3404a2-34a0-4ad2-b2a6-37cf28250a89','送史申之峽州','司空曙','唐','唐诗','tang','','[]','峽口巴江外，無風浪亦翻。',48,'全唐诗/poet.tang.15000.json','["峽口巴江外，無風浪亦翻。", "蒹葭新有雁，雲雨不離猨。", "行客思鄉遠，愁人賴酒昏。", "檀郎好聯句，共滯謝家門。"]'),
('7d3d42b2-b1f2-4e2f-9e43-219fa45f2427','送王閏','司空曙','唐','唐诗','tang','','[]','相送臨寒水，蒼然望故關。',48,'全唐诗/poet.tang.15000.json','["相送臨寒水，蒼然望故關。", "江蕪連夢澤，楚雪入商山。", "話我他年舊，看君此日還。", "因將自悲淚，一灑別離間。"]'),
('879f54a8-2beb-4334-bc17-6d7e7c29be15','江園書事寄盧綸','司空曙','唐','唐诗','tang','','[]','種柳南江邊，閉門三四年。',48,'全唐诗/poet.tang.15000.json','["種柳南江邊，閉門三四年。", "豔花那勝竹，凡鳥不如蟬。", "嗜酒漸嬰渴，讀書多欲眠。", "平生故交在，白首遠相憐。"]'),
('f0d7e119-8760-4482-b19b-7f424a116c0c','送鄭況往淮南','司空曙','唐','唐诗','tang','','[]','西楚見南關，蒼蒼落日間。',48,'全唐诗/poet.tang.15000.json','["西楚見南關，蒼蒼落日間。", "雲離大雷樹，潮入秣陵山。", "登戍因高望，停橈放溜閑。", "陳公有賢榻，君去豈空還。"]'),
('fa9f873b-8b08-400c-8acb-f33b76db429f','題江陵臨沙驛樓','司空曙','唐','唐诗','tang','','[]','江天清更愁，風柳入江樓。',48,'全唐诗/poet.tang.15000.json','["江天清更愁，風柳入江樓。", "雁惜楚山晚，蟬知秦樹秋。", "淒涼多獨醉，零落半同遊。", "豈復平生意，蒼然蘭杜洲。"]'),
('90a58cb0-26fa-46ef-b1ba-e7c12bc12a06','新蟬','司空曙','唐','唐诗','tang','','[]','今朝蟬忽鳴，遷客若爲情。',48,'全唐诗/poet.tang.15000.json','["今朝蟬忽鳴，遷客若爲情。", "便覺一年老，能令萬感生。", "微風方滿樹，落日稍沈城。", "爲問同懷者，淒涼聽幾聲。"]'),
('1a159d93-1de3-4be6-81de-10338e557ec7','送張弋','司空曙','唐','唐诗','tang','','[]','擁櫂江天曠，蒼然下郢城。',48,'全唐诗/poet.tang.15000.json','["擁櫂江天曠，蒼然下郢城。", "冰霜葭菼變，雲澤鷓鴣鳴。", "酒倦臨流醉，人逢置榻迎。", "嘗聞藉東觀，不獨魯諸生。"]'),
('1ee4fce8-9ad0-4931-90e6-6a5e6846e94c','送僧無言歸山','司空曙','唐','唐诗','tang','','[]','袈裟出塵外，山徑幾盤緣。',48,'全唐诗/poet.tang.15000.json','["袈裟出塵外，山徑幾盤緣。", "人到白雲樹，鶴沈青草田。", "龕泉朝請盥，松籟夜和禪。", "自昔聞多學，逍遙注一篇。"]'),
('888f45a4-87d6-411d-854a-dd3a937c62a6','和盧校書文若早入使院書事','司空曙','唐','唐诗','tang','','[]','解帶獨裴回，秋風如水來。',48,'全唐诗/poet.tang.15000.json','["解帶獨裴回，秋風如水來。", "軒墀溼繁露，琴几拂輕埃。", "晨鳥猶在葉，夕蟲餘囗苔。", "蒼然發高興，相仰坐難陪。"]'),
('9d587424-e1fd-4046-b518-b5f6dfec0922','送史澤之長沙','司空曙','唐','唐诗','tang','','[]','謝朓懷西府，單車觸火雲。',48,'全唐诗/poet.tang.15000.json','["謝朓懷西府，單車觸火雲。", "野蕉依戍客，廟竹暎湘君。", "夢渚巴山斷，長沙楚路分。", "一杯從別後，風月不相聞。"]'),
('78a0656c-3a6e-43b0-9e67-1a894ded1688','田家','司空曙','唐','唐诗','tang','','[]','田家喜雨足，鄰老相招攜。',48,'全唐诗/poet.tang.15000.json','["田家喜雨足，鄰老相招攜。", "泉溢溝塍壞，麥高桑柘低。", "呼兒催放犢，宿客待烹雞。", "搔首蓬門下，如將軒冕齊。"]'),
('8acf36ea-95e1-4491-9718-8e0b85ee106d','送盧堪','司空曙','唐','唐诗','tang','','[]','羈貧不易去，此日始西東。',48,'全唐诗/poet.tang.15000.json','["羈貧不易去，此日始西東。", "旅舍秋霖葉，行人寒草風。", "酒醒餘恨在，野餞暫遊同。", "莫使禰生刺，空留懷袖中。"]'),
('d3dc254c-55e1-4114-93e6-44ebc2f07232','送柳震入蜀','司空曙','唐','唐诗','tang','','[]','粉堞連青氣，喧喧雜萬家。',48,'全唐诗/poet.tang.15000.json','["粉堞連青氣，喧喧雜萬家。", "夷人祠竹節，蜀鳥乳桐花。", "酒報新豐景，琴迎抵峽斜。", "多聞滯遊客，不似在天涯。"]'),
('3c65a23c-f6bb-478e-8386-50278c0f0e1a','送李嘉祐正字括圖書兼往揚州覲省','司空曙','唐','唐诗','tang','','[]','不事蘭臺貴，全多韋帶風。',48,'全唐诗/poet.tang.15000.json','["不事蘭臺貴，全多韋帶風。", "儒官比劉向，使者得陳農。", "晚燒平蕪外，朝陽疊浪東。", "歸來喜調膳，寒筍出林中。"]'),
('3ca822a6-8abd-42b0-a0cd-d38e81e22fb0','送劉侍御','司空曙','唐','唐诗','tang','','[]','獄成收夜燭，整豸出登車。',48,'全唐诗/poet.tang.15000.json','["獄成收夜燭，整豸出登車。", "黃葉辭荆楚，青山背漢初。", "早朝新羽衞，晚下步徒胥。", "應念長沙謫，思鄉不食魚。"]'),
('54e145bf-46ef-4ee6-8a40-7aaf46a35b14','送龐判官赴黔中','司空曙','唐','唐诗','tang','','[]','天遠風煙異，西南見一方。',48,'全唐诗/poet.tang.15000.json','["天遠風煙異，西南見一方。", "亂山來蜀道，諸水出辰陽。", "堆案青油暮，看棋畫角長。", "論文誰可制，記室有何郎。"]'),
('d668141d-a638-4b3d-af3a-fee7293fb90c','送人遊嶺南','司空曙','唐','唐诗','tang','','["\u5199\u4eba", "\u544a\u8beb", "\u5199\u4eba\u8bd7"]','萬里南遊客，交州見柳條。',48,'全唐诗/poet.tang.15000.json','["萬里南遊客，交州見柳條。", "逢迎人易合，時日酒能消。", "浪曉浮青雀，風溫解黑貂。", "囊金如未足，莫恨故鄉遙。"]'),
('ea112d09-8374-4aba-bdae-504d8c8d893c','送曹同椅','司空曙','唐','唐诗','tang','','[]','青春三十餘，衆藝盡無如。',48,'全唐诗/poet.tang.15000.json','["青春三十餘，衆藝盡無如。", "中散詩傳畫，將軍扇續書。", "楚田晴下雁，江日暖遊魚。", "惆悵空相送，歡遊自此疎。"]'),
('70bd18cf-3075-4752-8817-e591ace351e9','送鄂州張別駕襄陽覲省','司空曙','唐','唐诗','tang','','[]','蒼蒼峴亭路，臘月漢陽春。',48,'全唐诗/poet.tang.15000.json','["蒼蒼峴亭路，臘月漢陽春。", "帶雪半山寺，行沙隔水人。", "王祥因就宦，萊子不違親。", "正恨殊鄉別，千條楚柳新。"]'),
('8095147b-d6cc-449c-9b3b-02996f626e1f','送魏季羔遊長沙覲兄','司空曙','唐','唐诗','tang','','[]','蘆荻湘江水，蕭蕭萬里秋。',48,'全唐诗/poet.tang.15000.json','["蘆荻湘江水，蕭蕭萬里秋。", "鶴高看迥野，蟬遠入中流。", "訪友多成滯，攜家不厭遊。", "惠連仍有作，知得從兄酬。"]'),
('d52299f9-b685-4f94-bb8e-ea0d5a9e9069','雜言','司空曙','唐','唐诗','tang','','[]','伏餘西景移，風雨灑輕絺。',24,'全唐诗/poet.tang.15000.json','["伏餘西景移，風雨灑輕絺。", "燕拂青蕪地，蟬鳴紅葉枝。"]'),
('cc51c891-8c40-4c18-9d15-a8530db21be0','翫花與衞象同醉','司空曙','唐','唐诗','tang','','[]','衰鬢千莖雪，他鄉一樹花。',24,'全唐诗/poet.tang.15000.json','["衰鬢千莖雪，他鄉一樹花。", "今朝與君醉，忘却在長沙。"]'),
('a9a12ca0-3896-4787-a112-d9cbc41bac60','送王尊師歸湖州','司空曙','唐','唐诗','tang','','[]','煙蕪滿洞青山遶，幢節飄空紫鳳飛。',64,'全唐诗/poet.tang.15000.json','["煙蕪滿洞青山遶，幢節飄空紫鳳飛。", "金闕乍看迎日麗，玉簫遙聽隔花微。", "多開石髓供調膳，時御霓裳奉易衣。", "莫學遼東華表上，千年始欲一迴歸。"]'),
('bbe5c098-6fd2-4fdc-ace3-d7b049bc66c3','九日洛東亭','司空曙','唐','唐诗','tang','','[]','風息斜陽盡，遊人曲落間。',48,'全唐诗/poet.tang.15000.json','["風息斜陽盡，遊人曲落間。", "採花因覆酒，行草轉看山。", "柳散新霜下，天晴早雁還。", "傷秋非騎省，玄髮白成斑。"]'),
('402a706d-4568-471e-ac1f-e01a7f90f6cf','九日送人','司空曙','唐','唐诗','tang','','[]','送人冠獬豸，值節佩茱萸。',48,'全唐诗/poet.tang.15000.json','["送人冠獬豸，值節佩茱萸。", "均覆徵三壤，登車出五湖。", "水風淒落日，岸葉颯衰蕪。", "自恨塵中使，何因在路隅。"]'),
('287ab2db-8089-4449-bfaa-a292facd81cf','哭王注','司空曙','唐','唐诗','tang','','[]','已歎漳濱臥，何言駐隙難。',48,'全唐诗/poet.tang.15000.json','["已歎漳濱臥，何言駐隙難。", "異才傷促短，諸友哭門闌。", "古道松聲暮，荒阡草色寒。", "延陵今葬子，空使魯人觀。"]'),
('871acf59-5c9b-4ed7-b140-d0c524481dca','遇谷口道士','司空曙','唐','唐诗','tang','','[]','一見林中客，閑知州縣勞。',48,'全唐诗/poet.tang.15000.json','["一見林中客，閑知州縣勞。", "白雲秋色遠，蒼嶺夕陽高。", "自說名因石，誰逢手種桃。", "丹經儻相授，何用戀青袍。"]'),
('f0cd6afd-c89d-4fc3-b214-bcbf63042e8e','喜外弟盧綸見宿','司空曙','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u751f\u6d3b", "\u4e94\u8a00\u5f8b\u8bd7", "\u5e74\u8001"]','靜夜四無鄰，荒居舊業貧。',48,'全唐诗/poet.tang.15000.json','["靜夜四無鄰，荒居舊業貧。", "雨中黃葉樹，燈下白頭人。", "以我獨沈久，愧君相見頻。", "平生自有分，況是蔡家親。"]'),
('99b28edd-1f27-415b-993f-f7ca05f18279','深上人見訪憶李端','司空曙','唐','唐诗','tang','','[]','雁稀秋色盡，落日對寒山。',48,'全唐诗/poet.tang.15000.json','["雁稀秋色盡，落日對寒山。", "避事多稱疾，留僧獨閉關。", "心歸塵俗外，道勝有無間。", "仍憶東林友，相期久不還。"]'),
('cc1afbea-10f7-4e8d-b768-da36dfa19bab','宿青龍寺故曇上人院','司空曙','唐','唐诗','tang','','[]','年深宮院在，舊客自相逢。',48,'全唐诗/poet.tang.15000.json','["年深宮院在，舊客自相逢。", "閉戶臨寒竹，無人有夜鐘。", "降龍今已去，巢鶴竟何從。", "坐見繁星曉，淒涼識舊峯。"]'),
('d41d9356-525f-4680-93cc-724d67035925','送張鍊師還峨嵋山','司空曙','唐','唐诗','tang','','["\u5ce8\u7709\u5c71"]','太一天壇天柱西，垂蘿爲幌石爲梯。',64,'全唐诗/poet.tang.15000.json','["太一天壇天柱西，垂蘿爲幌石爲梯。", "前登靈境青霄絕，下視人間白日低。", "松籟萬聲和管磐，丹光五色雜虹蜺。", "春山一入尋無路，鳥響煙深水滿溪。"]'),
('58fe608e-8583-4be2-951a-4303ebac66f3','逢江客問南中故人因以詩寄','司空曙','唐','唐诗','tang','','[]','南客何時去，相逢問故人。',72,'全唐诗/poet.tang.15000.json','["南客何時去，相逢問故人。", "望鄉空淚落，嗜酒轉家貧。", "疎嬾辭微祿，東西任老身。", "上樓多看月，臨水共傷春。", "五柳終期隱，雙鷗自可親。", "應憐折腰吏，冉冉在風塵。"]'),
('5a5a657c-624e-44c1-8abd-4318953d1c56','送臯法師','司空曙','唐','唐诗','tang','','[]','江草知寒柳半衰，行吟怨別獨遲遲。',32,'全唐诗/poet.tang.15000.json','["江草知寒柳半衰，行吟怨別獨遲遲。", "何人講席投如意，唯有東林遠法師。"]'),
('47fed2c6-8061-49e1-9228-ae17232c6026','送鄭佶歸洛陽','司空曙','唐','唐诗','tang','','[]','蒼蒼楚色水雲間，一醉春風送爾還。',32,'全唐诗/poet.tang.15000.json','["蒼蒼楚色水雲間，一醉春風送爾還。", "何處鄉心最堪羨，汝南初見洛陽山。"]'),
('47e070ca-4722-4870-a959-ed38b3eeca3e','分流水','司空曙','唐','唐诗','tang','','[]','古時愁別淚，滴作分流水。',48,'全唐诗/poet.tang.15000.json','["古時愁別淚，滴作分流水。", "日夜東西流，分流幾千里。", "通塞兩不見，波瀾各自起。", "與君相背飛，去去心如此。"]'),
('7bcc43ce-4c7c-4339-8b24-3c3cb0e5dad3','和耿拾遺元日觀早朝','司空曙','唐','唐诗','tang','','[]','元日爭朝闕，奔流若會溟。',120,'全唐诗/poet.tang.15000.json','["元日爭朝闕，奔流若會溟。", "路塵和薄霧，騎火接低星。", "門響雙魚鑰，車喧百子鈴。", "冕旒當翠殿，幢戟滿彤庭。", "積歲方編瑞，乘春即省刑。", "大官陳禹玉，司曆獻堯蓂。", "壽酒三觴退，簫韶九奏停。", "太陽開物象，霈澤及生靈。", "南陌高山碧，東方曉氣青。", "自憐揚子賤，歸草太玄經。"]'),
('dd7eeaf4-69cf-42f4-8f43-ef2f8ec7dcbc','塞下曲','司空曙','唐','唐诗','tang','','[]','寒柳接胡桑，軍門向大荒。',48,'全唐诗/poet.tang.15000.json','["寒柳接胡桑，軍門向大荒。", "幕營隨月魄，兵氣長星芒。", "橫吹催春酒，重裘隔夜霜。", "冰開不防虜，青草滿遼陽。"]'),
('d526d975-3b1e-45d9-9424-dc49390a5f7b','關山月','司空曙','唐','唐诗','tang','','[]','蒼茫明月上，夜久光如積。',48,'全唐诗/poet.tang.15000.json','["蒼茫明月上，夜久光如積。", "野幕冷胡霜，關樓宿邊客。", "隴頭秋露暗，磧外寒沙白。", "唯有故鄉人，霑裳此聞笛。"]'),
('cb161a4b-f295-4b84-8cdf-e0c9a6ac7ccd','御製雨後出城觀覽敕朝臣已下屬和','司空曙','唐','唐诗','tang','','[]','上上開鶉野，師師出鳳城。',96,'全唐诗/poet.tang.15000.json','["上上開鶉野，師師出鳳城。", "因知聖主念，得遂老農情。", "隴麥垂秋合，郊塵得雨清。", "時新薦玄祖，歲足富蒼生。", "却馬川原靜，聞雞水土平。", "薰弦歌舜德，和鼎致堯名。", "覽物欣多稼，垂衣御大明。", "史官何所錄，稱瑞滿天京。"]'),
('8a13013e-1cb5-439f-928e-e2a2026356ca','奉和常舍人晚秋集賢院即事寄徐薛二侍郎','司空曙','唐','唐诗','tang','','[]','藹藹鳳凰宮，蘭臺玉署通。',144,'全唐诗/poet.tang.15000.json','["藹藹鳳凰宮，蘭臺玉署通。", "夜霜凝樹羽，朝日照相風。", "官附三台貴，儒開百氏宗。", "司言陳禹命，侍講發堯聰。", "香卷青編內，鉛分綠字中。", "綴籤從太史，鏘佩揖羣公。", "池接天泉碧，林交御果紅。", "寒龜登故葉，秋蝶戀疎藂。", "顏謝徵文並，鍾裴直事同。", "離羣驚海鶴，屬思怨江楓。", "地遠姑蘇外，山長越絕東。", "慙當哲匠後，下曲本難工。"]'),
('0b50750a-2f2f-48b4-b711-1c34c088006e','題鮮于秋林園','司空曙','唐','唐诗','tang','','[]','雨後園林好，幽行迥野通。',48,'全唐诗/poet.tang.15000.json','["雨後園林好，幽行迥野通。", "遠山芳草外，流水落花中。", "客醉悠悠慣，鶯啼處處同。", "夕陽自一望，日暮杜陵東。"]'),
('a8f5cfed-2300-4d3a-8112-c63dd4c433dd','登秦嶺','司空曙','唐','唐诗','tang','','[]','南登秦嶺頭，迴首始堪憂。',48,'全唐诗/poet.tang.15000.json','["南登秦嶺頭，迴首始堪憂。", "漢闕青門遠，商山藍水流。", "三湘遷客去，九陌故人遊。", "從此思鄉淚，雙垂不復收。"]'),
('362ee93e-9b20-4082-a797-bc339355f3be','獨遊寄衞長林','司空曙','唐','唐诗','tang','','[]','草綠春陽動，遲遲澤畔遊。',48,'全唐诗/poet.tang.15000.json','["草綠春陽動，遲遲澤畔遊。", "戀花同野蝶，愛水劇江鷗。", "身外唯須醉，人間盡是愁。", "那知鳴玉者，不羨賣瓜侯。"]'),
('98ab1638-8308-40ae-9ed4-ddf81aeb2e86','望水','司空曙','唐','唐诗','tang','','[]','高樓晴見水，楚色靄相和。',48,'全唐诗/poet.tang.15000.json','["高樓晴見水，楚色靄相和。", "野極空如練，天遙不辨波。", "永無人跡到，時有鳥行過。", "況是蒼茫外，殘陽照最多。"]'),
('158d2496-f9df-4212-9997-7000227153dd','望商山路','司空曙','唐','唐诗','tang','','[]','南見青山道，依然去國時。',48,'全唐诗/poet.tang.15000.json','["南見青山道，依然去國時。", "已甘長避地，誰料有還期。", "雨霽殘陽薄，人愁獨望遲。", "空殘華髮在，前事不堪思。"]'),
('35638e63-ef59-411d-a832-af24221fd0fd','題落葉','司空曙','唐','唐诗','tang','','[]','霜景催危葉，今朝半樹空。',48,'全唐诗/poet.tang.15000.json','["霜景催危葉，今朝半樹空。", "蕭條故國異，零落旅人同。", "颯岸浮寒水，依堦擁夜蟲。", "隨風偏可羨，得到洛陽宮。"]'),
('7b4fd6dd-f1dc-418d-88b1-9ee28f90a2d7','寄準上人','司空曙','唐','唐诗','tang','','[]','昨聞歸舊寺，暫別欲經年。',48,'全唐诗/poet.tang.15000.json','["昨聞歸舊寺，暫別欲經年。", "樵客應同步，鄰僧定伴禪。", "後峯秋有雪，遠澗夜鳴泉。", "偶與支公論，人間自共傳。"]'),
('e7ace9a5-8100-4da9-b819-4f45d0f80d0b','送況上人還荆州因寄衞侍御象','司空曙','唐','唐诗','tang','','[]','惠持遊蜀久，策杖欲西還。',48,'全唐诗/poet.tang.15000.json','["惠持遊蜀久，策杖欲西還。", "共別此宵月，獨歸何處山。", "對鷗沙草畔，洗足野雲間。", "知有玄暉會，齋心受八關。"]'),
('4f3920b1-4088-40d9-a888-98e8869adcf1','別盧綸','司空曙','唐','唐诗','tang','','[]','有月多共賞，無秋不共悲。',24,'全唐诗/poet.tang.15000.json','["有月多共賞，無秋不共悲。", "如何與君別，又是菊黃時。"]'),
('e072c7f0-1d16-4941-8ded-6703c9f66b44','雪二首 一','司空曙','唐','唐诗','tang','','[]','樂遊春苑望鵝毛，宮殿如星樹似毫。',32,'全唐诗/poet.tang.15000.json','["樂遊春苑望鵝毛，宮殿如星樹似毫。", "漫漫一川橫渭水，太陽初出五陵高。"]'),
('ac9ff20b-28e5-41f5-b1ef-596dab0894cf','雪二首 二','司空曙','唐','唐诗','tang','','[]','王屋南崖見洛城，石龕松寺上方平。',32,'全唐诗/poet.tang.15000.json','["王屋南崖見洛城，石龕松寺上方平。", "半山槲葉當窗下，一夜曾聞雪打聲。"]'),
('01c7e7af-0460-4a15-adfe-a0b9b60a6d4e','酬衞長林歲日見呈','司空曙','唐','唐诗','tang','','[]','地暖雪花摧，天春斗柄迴。',48,'全唐诗/poet.tang.15000.json','["地暖雪花摧，天春斗柄迴。", "朱泥一丸藥，柏葉萬年杯。", "旅雁辭人去，繁霜滿鏡來。", "今朝彩盤上，神燕不須雷。"]'),
('90ebf7a8-e3e4-4f50-8f66-fe0f412398c2','杜鵑行','司空曙','唐','唐诗','tang','','[]','古時杜宇稱望帝，魂作杜鵑何微細。',168,'全唐诗/poet.tang.15000.json','["古時杜宇稱望帝，魂作杜鵑何微細。", "跳枝竄葉樹木中，搶翔瞥捩雌隨雄。", "毛衣慘黑自顦顇，衆鳥安肯相尊崇。", "隳形不敢栖華屋，短翮唯願巢深叢。", "穿皮啄朽觜欲禿，苦飢始得食一蟲。", "誰言養雛不自哺，此語亦足爲愚蒙。", "聲音咽噦若有謂，號啼略與嬰兒同。", "口乾垂血轉迫促，似欲上訴於蒼穹。", "蜀人聞之皆起立，至今相效傳遺風。", "乃知變化不可窮，豈知昔日居深宮，嬪妃左右如花紅。"]'),
('1246e3b2-e4cc-4cea-b01d-6b1e3bae4d6b','寄胡居士','司空曙','唐','唐诗','tang','','[]','日暖風微南陌頭，青田紅樹起春愁。',64,'全唐诗/poet.tang.15000.json','["日暖風微南陌頭，青田紅樹起春愁。", "伯勞相逐行人別，岐路空歸野水流。", "徧地尋僧同看雪，誰期載酒共登樓。", "爲言惆悵嵩陽寺，明月高松應獨遊。"]'),
('dafd746b-c98e-4cb3-973d-952bbb683383','寒塘','司空曙','唐','唐诗','tang','','[]','曉髮梳臨水，寒塘坐見秋。',24,'全唐诗/poet.tang.15000.json','["曉髮梳臨水，寒塘坐見秋。", "鄉心正無限，一雁度南樓。"]'),
('d8474ce5-372b-49a0-bdf2-0fe91fdd5c73','爲李魏公賦謝汧公','司空曙','唐','唐诗','tang','','[]','白雪高吟際，青霄遠望中。',24,'全唐诗/poet.tang.15000.json','["白雪高吟際，青霄遠望中。", "誰言路遐曠，宮徵暗相通。"]'),
('0b0170c8-424f-4f0a-aaa3-b984ddffbfd4','梁城老人怨','司空曙','唐','唐诗','tang','','[]','朝爲耕鐘人，暮作刀槍鬼。',24,'全唐诗/poet.tang.15000.json','["朝爲耕鐘人，暮作刀槍鬼。", "相看父子血，共染城壕水。"]'),
('46e49082-f006-4157-b5e7-3c821cac0e42','揚州選蒙相公賞判雪後呈上','崔峒','唐','唐诗','tang','','[]','自得山公許，休畊海上田。',48,'全唐诗/poet.tang.15000.json','["自得山公許，休畊海上田。", "慙看長史傳，欲棄釣魚船。", "窮巷殷憂日，蕪城雨雪天。", "此時瞻相府，心事比旌懸。"]'),
('039c2a5b-73bc-47b4-a6dd-68cb46a8dc59','客舍書情寄趙中丞','崔峒','唐','唐诗','tang','','[]','東楚復西秦，浮雲類此身。',50,'全唐诗/poet.tang.15000.json','["東楚復西秦，浮雲類此身。", "關山勞策蹇，僮僕慣投人。", "孤客來千里，全家託四鄰。", "生涯難自料，中夜問[情親]。"]'),
('6b12c992-250e-4231-9b19-8fada6c0f668','客舍有懷因呈諸在事','崔峒','唐','唐诗','tang','','[]','讀書常苦節，待詔豈辭貧。',48,'全唐诗/poet.tang.15000.json','["讀書常苦節，待詔豈辭貧。", "暮雪猶驅馬，晡飡又寄人。", "愁來占吉夢，老去惜良辰。", "延首平津閣，家山日已春。"]'),
('b9049867-1c05-4ba5-b3cc-ac55fe3ea20e','書懷寄楊郭李王判官','崔峒','唐','唐诗','tang','','[]','慣作雲林客，因成懶漫人。',48,'全唐诗/poet.tang.15000.json','["慣作雲林客，因成懶漫人。", "吏欺從政拙，妻笑理家貧。", "李郭應時望，王楊入幕頻。", "從容丞相閣，知憶故園春。"]'),
('04ff6d31-d3fb-4343-aedd-7a53a106b470','奉和給事寓直','崔峒','唐','唐诗','tang','','[]','桂枝家共折，雞樹代相傳。',48,'全唐诗/poet.tang.15000.json','["桂枝家共折，雞樹代相傳。", "忝向鸞臺下，仍看鴈影連。", "夜閑方步月，漏盡欲朝天。", "知去丹墀近，明王許薦賢。"]'),
('cfa6b0e2-6fe0-4840-bb51-b27d4d8c1afb','初入集賢院贈李獻仁','崔峒','唐','唐诗','tang','','[]','燕代官初罷，江湖路便分。',48,'全唐诗/poet.tang.15000.json','["燕代官初罷，江湖路便分。", "九遷從命薄，四十幸人聞。", "跡愧趨丹禁，身曾繫白雲。", "何由返滄海，昨日謁明君。"]'),
('e8c0b596-d5d0-4073-9f9f-ecef8025dac2','酬李補闕雨中寄贈','崔峒','唐','唐诗','tang','','[]','十年隨馬宿，幾度受人恩。',48,'全唐诗/poet.tang.15000.json','["十年隨馬宿，幾度受人恩。", "白髮還鄉井，微官有子孫。", "竹窗寒雨滴，苦砌夜蟲喧。", "獨媿東垣友，新詩慰旅魂。"]'),
('1b9258ce-f8d6-417d-8bb1-aac8b4b0b653','初除拾遺酬丘二十二見寄','崔峒','唐','唐诗','tang','','[]','江海久垂綸，朝衣忽掛身。',48,'全唐诗/poet.tang.15000.json','["江海久垂綸，朝衣忽掛身。", "丹墀初謁帝，白髮免羞人。", "才愧文章士，名當諫諍臣。", "空餘薦賢分，不敢負交親。"]'),
('3abc38e4-f4ce-4a03-8cff-368a950c86e6','劉展下判官相招以詩答之','崔峒','唐','唐诗','tang','','[]','國有非常寵，家承異姓勳。',48,'全唐诗/poet.tang.15000.json','["國有非常寵，家承異姓勳。", "背恩慙皎日，不義若浮雲。", "但使忠貞在，甘從玉石焚。", "竄身如有地，夢寐見明君。"]'),
('651ebe46-5927-4e46-8cec-68edf7f09fa8','送侯山人赴會稽','崔峒','唐','唐诗','tang','','[]','仙客辭蘿月，東來就一官。',48,'全唐诗/poet.tang.15000.json','["仙客辭蘿月，東來就一官。", "且歸滄海住，猶向白雲看。", "猨呌江天暮，蟲聲野浦寒。", "時遊鏡湖裏，爲我把魚竿。"]'),
('5388c512-5dad-4b5d-87a2-146786df0636','宿禪智寺上方演大師院','崔峒','唐','唐诗','tang','','[]','石林高幾許，金剎在中峰。',48,'全唐诗/poet.tang.15000.json','["石林高幾許，金剎在中峰。", "白日空山梵，清霜後夜鐘。", "竹窗迴翠壁，苔徑入寒松。", "幸接無生法，疑心怯所從。"]'),
('8da62a2e-2782-4b7a-80c7-45042284ffc2','題空山人石室','崔峒','唐','唐诗','tang','','[]','早晚悟無生，頭陀不到城。',48,'全唐诗/poet.tang.15000.json','["早晚悟無生，頭陀不到城。", "雲山知夏臘，猨鳥見修行。", "地僻無溪路，人尋逐水聲。", "年年深谷裏，誰識遠公名。"]'),
('c418f6a0-9c6d-4a70-a409-c37c02297314','登蔣山開善寺','崔峒','唐','唐诗','tang','','[]','山殿秋雲裏，香煙出翠微。',48,'全唐诗/poet.tang.15000.json','["山殿秋雲裏，香煙出翠微。", "客尋朝磬至，僧背夕陽歸。", "下界千門見，前朝萬事非。", "看心兼送目，葭菼暮依依。"]'),
('33328b3c-5773-4538-b70e-8b58e019a2cf','題崇福寺禪院','崔峒','唐','唐诗','tang','','[]','僧家竟何事，掃地與焚香。',48,'全唐诗/poet.tang.15000.json','["僧家竟何事，掃地與焚香。", "清磬度山翠，閑雲來竹房。", "身心塵外遠，歲月坐中長。", "向晚禪堂掩，無人空夕陽。"]'),
('b5d27367-62b7-4b9a-b66c-bbaff3d2ea33','秋晚送丹徒許明府赴上國因寄江南故人','崔峒','唐','唐诗','tang','','[]','秋暮之彭澤，籬花遠近逢。',48,'全唐诗/poet.tang.15000.json','["秋暮之彭澤，籬花遠近逢。", "君書前日至，別後此時重。", "寒夜江邊月，晴天海上峰。", "還知南地客，招引住新豐。"]'),
('b721a577-dbff-480d-8b3a-76be13b31f02','送薛仲方歸揚州','崔峒','唐','唐诗','tang','','[]','佳句應無敵，貞心不有猜。',48,'全唐诗/poet.tang.15000.json','["佳句應無敵，貞心不有猜。", "慙爲丈人行，怯見後生才。", "泛舸貪斜月，浮橈值早梅。", "綠楊新過雨，芳草待君來。"]'),
('e3026b4a-e2e5-47f8-8497-ae73399bda6b','送韋員外還京','崔峒','唐','唐诗','tang','','[]','十年離亂後，此去若爲情。',48,'全唐诗/poet.tang.15000.json','["十年離亂後，此去若爲情。", "春晚香山綠，人稀豫水清。", "野陂看獨樹，關路逐殘鶯。", "前殿朝明主，應憐白髮生。"]'),
('d73d10a5-8b43-46b7-8106-de6ed2153d66','潤州送友人','崔峒','唐','唐诗','tang','','[]','見君還此地，灑淚向江邊。',48,'全唐诗/poet.tang.15000.json','["見君還此地，灑淚向江邊。", "國士勞相問，家書無處傳。", "荒城胡馬跡，塞木戍人煙。", "一路堪愁思，孤舟何渺然。"]'),
('27ae9cbd-2344-4e12-8ce8-24adabd11486','送張芬東歸','崔峒','唐','唐诗','tang','','[]','喧喧五衢上，鞍馬自驅馳。',48,'全唐诗/poet.tang.15000.json','["喧喧五衢上，鞍馬自驅馳。", "落日臨阡陌，貧交欲別離。", "早知時事異，堪與世人隨。", "握手將何贈，君心我獨知。"]'),
('58703b0a-258d-4de7-bb1e-c6587cb8bfea','送蘇脩遊上饒','崔峒','唐','唐诗','tang','','[]','愛爾無羈束，雲山恣意過。',48,'全唐诗/poet.tang.15000.json','["愛爾無羈束，雲山恣意過。", "一身隨遠岫，孤棹任輕波。", "世事關情少，漁家寄宿多。", "蘆花淺淡處，江月奈人何。"]'),
('838ed701-495c-4c25-940a-ff012b60414a','送陸明府之盱眙','崔峒','唐','唐诗','tang','','[]','陶令之官去，窮愁慘別魂。',48,'全唐诗/poet.tang.15000.json','["陶令之官去，窮愁慘別魂。", "白煙橫海戍，紅葉下淮村。", "澹浪搖山郭，平蕪到縣門。", "政成堪吏隱，免負府公恩。"]'),
('931833f0-e0e1-4904-a4b3-2183940856c7','江南迴逢趙曜因送任十一赴交城主簿','崔峒','唐','唐诗','tang','','[]','江上長相憶，因高北望看。',48,'全唐诗/poet.tang.15000.json','["江上長相憶，因高北望看。", "不知攜老幼，何處度艱難。", "屈指同人盡，傷心故里殘。", "遙憐驅匹馬，白首到微官。"]'),
('377fd9dd-3ab4-4bb4-8eaa-6a5334b38d14','送薛良史往越州謁從叔','崔峒','唐','唐诗','tang','','[]','辭家年已久，與子分偏深。',48,'全唐诗/poet.tang.15000.json','["辭家年已久，與子分偏深。", "易得相思淚，難爲欲別心。", "孤雲隨浦口，幾日到山陰。", "遙想蘭亭下，清風滿竹林。"]'),
('db8be32b-7191-4e61-a10f-1d3a20f533e9','送丘二十二之蘇州','崔峒','唐','唐诗','tang','','[]','積水與寒煙，嘉禾路幾千。',48,'全唐诗/poet.tang.15000.json','["積水與寒煙，嘉禾路幾千。", "孤猨啼海島，羣雁起湖田。", "曾見長洲苑，嘗聞大雅篇。", "却將封事去，知爾愛閑眠。"]'),
('8ea76149-dd97-4cd4-9564-7595c9df1506','登潤州芙蓉樓','崔峒','唐','唐诗','tang','','[]','上古人何在，東流水不歸。',48,'全唐诗/poet.tang.15000.json','["上古人何在，東流水不歸。", "往來潮有信，朝暮事成非。", "煙樹臨沙靜，雲帆入海稀。", "郡樓多逸興，良牧謝玄暉。"]'),
('b8cb002c-be55-4c7b-8725-3983ebec476f','江上書懷','崔峒','唐','唐诗','tang','','[]','骨肉天涯別，江山日落時。',48,'全唐诗/poet.tang.15000.json','["骨肉天涯別，江山日落時。", "淚流襟上血，髮變鏡中絲。", "胡越書難到，存亡夢豈知。", "登高回首罷，形影自相隨。"]'),
('f6d2af85-ad87-42c8-97b9-5f6e32b4950d','春日憶姚氏外甥','崔峒','唐','唐诗','tang','','[]','離亂人相失，春秋鴈自飛。',48,'全唐诗/poet.tang.15000.json','["離亂人相失，春秋鴈自飛。", "祗緣行路遠，未必寄書稀。", "二月花無數，頻年意有違。", "落暉看過後，獨坐淚沾衣。"]'),
('cc1b6105-9342-4aa3-9872-516886fd2e5a','送真上人還蘭若','崔峒','唐','唐诗','tang','','[]','得道雲林久，年深暫一歸。',48,'全唐诗/poet.tang.15000.json','["得道雲林久，年深暫一歸。", "出山逢世亂，乞食覺人稀。", "半偈初傳法，中峰又掩扉。", "愛憎應不染，塵俗自依依。"]'),
('4f0f738a-0f5a-4646-8f7e-21f4a86c763d','潤州送師弟自江夏往台州','崔峒','唐','唐诗','tang','','[]','遠客乘流去，孤帆向夜開。',48,'全唐诗/poet.tang.15000.json','["遠客乘流去，孤帆向夜開。", "春風江上使，前日漢陽來。", "別路猶千里，離心重一杯。", "剡溪木未落，羨爾過天台。"]'),
('93ea6203-85b0-4aff-a8c1-6b017c83f05c','送李道士歸山','崔峒','唐','唐诗','tang','','[]','秋城臨古路，城上望君還。',48,'全唐诗/poet.tang.15000.json','["秋城臨古路，城上望君還。", "曠野入寒草，獨行隨遠山。", "授人鴻寶內，將犬白雲間。", "早晚燒丹罷，遙知冰雪寒。"]'),
('c55add81-d6ba-4c4d-bc3d-346914766a12','宿江西竇主簿廳','崔峒','唐','唐诗','tang','','[]','廣庭方緩步，星漢話中移。',48,'全唐诗/poet.tang.15000.json','["廣庭方緩步，星漢話中移。", "月滿關山道，烏啼霜樹枝。", "時艱難會合，年長重親知。", "前事成金石，悽然淚欲垂。"]'),
('580aa9a1-188d-4ba7-abae-7cdf6e2ac289','喜逢妻弟鄭損因送入京','崔峒','唐','唐诗','tang','','[]','亂後自江城，相逢喜復驚。',48,'全唐诗/poet.tang.15000.json','["亂後自江城，相逢喜復驚。", "爲經多載別，欲問小時名。", "對酒悲前事，論文畏後生。", "遙知盈卷軸，紙貴在江城。"]'),
('3f25f510-e1a5-4803-89a9-d16c13d6013e','詠門下畫小松上元王杜三相公','崔峒','唐','唐诗','tang','','[]','昔聞生澗底，今見起毫端。',48,'全唐诗/poet.tang.15000.json','["昔聞生澗底，今見起毫端。", "衆草此時沒，何人知歲寒。", "豈能裨棟宇，且貴出門闌。", "只在丹青意，凌雲也不難。"]'),
('b7dd27c6-0626-42da-a842-380334fadf9a','寄上禮部李侍郎','崔峒','唐','唐诗','tang','','[]','吳楚相逢處，江湖共泛時。',72,'全唐诗/poet.tang.15000.json','["吳楚相逢處，江湖共泛時。", "任風舟去遠，待月酒行遲。", "白髮常同歡，青雲本要期。", "貴來君却少，秋至老偏悲。", "玉佩明朝盛，蒼苔陋巷滋。", "追尋恨無路，唯有夢相思。"]'),
('02c4f932-2c5d-49a4-b9bb-962315ef1ac2','書情寄上蘇州韋使君兼呈吳縣李明府','崔峒','唐','唐诗','tang','','["\u6292\u60c5", "\u6101\u7eea"]','數年湖上謝浮名，竹杖紗巾遂性情。',64,'全唐诗/poet.tang.15000.json','["數年湖上謝浮名，竹杖紗巾遂性情。", "雲外有時逢寺宿，日西無事傍江行。", "陶潛縣裏看花發，庾亮樓中對月明。", "誰念獻書來萬里，君王深在九重城。"]'),
('63038f1b-c864-496c-813c-11c021deb618','題桐廬李明府官舍','崔峒','唐','唐诗','tang','','[]','訟堂寂寂對煙霞，五柳門前聚曉鵶。',64,'全唐诗/poet.tang.15000.json','["訟堂寂寂對煙霞，五柳門前聚曉鵶。", "流水聲中視公事，寒山影裏見人家。", "觀風競美新爲政，計日還知舊觸邪。", "可惜陶潛無限酒，不逢籬菊正開花。"]'),
('b311196f-b1ae-4df5-8ee5-7e1af438478a','贈竇十九','崔峒','唐','唐诗','tang','','[]','靈臺暮宿意多違，木落花開羨客歸。',64,'全唐诗/poet.tang.15000.json','["靈臺暮宿意多違，木落花開羨客歸。", "江海幾時傳錦字，風塵不覺化緇衣。", "山陽會裏同人少，灞曲農時故老稀。", "幸得漢皇容直諫，憐君未遇覺人非。"]'),
('752f0d5f-d851-437c-8be9-8d6ace092e57','虔州見鄭表新詩因以寄贈','崔峒','唐','唐诗','tang','','[]','梅花嶺裏見新詩，感激情深過楚詞。',64,'全唐诗/poet.tang.15000.json','["梅花嶺裏見新詩，感激情深過楚詞。", "平子四愁今莫比，休文八詠自同時。", "萍鄉露冕真堪惜，鳳沼鳴珂已訝遲。", "才子風流定難見，湖南春草但相思。"]'),
('dabb5b5f-fe33-4632-93ce-e32f638296b1','贈元秘書','崔峒','唐','唐诗','tang','','[]','舊書稍稍出風塵，孤客逢秋感此身。',64,'全唐诗/poet.tang.15000.json','["舊書稍稍出風塵，孤客逢秋感此身。", "秦地謬爲門下客，淮陰徒笑市中人。", "也聞阮籍尋常醉，見說陳平不久貧。", "幸有故人茅屋在，更將心事問情親。"]'),
('a7066599-38bd-4570-b61a-ac733327440f','送韋八少府判官歸東京','崔峒','唐','唐诗','tang','','[]','玄成世業紫真官，文似相如貌勝潘。',64,'全唐诗/poet.tang.15000.json','["玄成世業紫真官，文似相如貌勝潘。", "鴻鴈南飛人獨去，雲山一別歲將闌。", "清淮水急桑林晚，古驛霜多柿葉寒。", "瓊樹相思何日見，銀鉤數字莫爲難。"]'),
('dec5ea9f-2718-41d2-8159-634c502b0764','送馮八將軍奏事畢歸滑臺幕府','崔峒','唐','唐诗','tang','','["\u9ec4\u6cb3"]','王門別後到滄洲，帝里相逢俱白頭。',64,'全唐诗/poet.tang.15000.json','["王門別後到滄洲，帝里相逢俱白頭。", "自歡馬卿常帶疾，還嗟李廣不封侯。", "棠梨宮裏瞻龍衮，細柳營中著虎裘。", "想到滑臺桑葉落，黃河東注杏園秋。"]'),
('65bfae3b-2f83-4256-b0e3-a52e6855b6d6','送王侍御佐婺州','崔峒','唐','唐诗','tang','','[]','聞君作尉向江潭，吳越風煙到自諳。',64,'全唐诗/poet.tang.15000.json','["聞君作尉向江潭，吳越風煙到自諳。", "客路尋常經竹徑，人家大底傍山嵐。", "緣溪花木偏宜遠，避地衣冠盡向南。", "惟有夜猨啼海樹，思鄉望北意難堪。"]'),
('1945ec6b-ad53-4e03-8cd8-24f84d51add5','越中送王使君赴江華','崔峒','唐','唐诗','tang','','[]','皂蓋春風自越溪，獨尋芳樹桂陽西。',64,'全唐诗/poet.tang.15000.json','["皂蓋春風自越溪，獨尋芳樹桂陽西。", "遠水浮雲隨馬去，空山弱篠向雲低。", "遙知異政荆門北，舊許新詩康樂齊。", "萬里相思在何處，九疑殘雪白猿啼。"]'),
('5bdcf9e3-cb35-46e5-ab96-ad215e02f331','送皇甫冉往白田','崔峒','唐','唐诗','tang','','[]','江邊盡日雉鳴飛，君向白田何日歸。',64,'全唐诗/poet.tang.15000.json','["江邊盡日雉鳴飛，君向白田何日歸。", "楚地蒹葭連海逈，隋朝楊柳映堤稀。", "津樓故市無行客，山館空庭閉落暉。", "試問疲人與征戰，使君雙淚定沾衣。"]'),
('445a7886-88f4-443b-9eca-5959e8d7d5de','題蘭若','崔峒','唐','唐诗','tang','','[]','絕頂茅庵老此生，寒雲孤木獨經行。',32,'全唐诗/poet.tang.15000.json','["絕頂茅庵老此生，寒雲孤木獨經行。", "世人那得知幽逕，遙向青峰禮磬聲。"]'),
('620a3bee-0216-4573-a96d-7bd67bcc1c21','送賀蘭廣赴選','崔峒','唐','唐诗','tang','','[]','而今用武爾攻文，流輩干時獨臥雲。',32,'全唐诗/poet.tang.15000.json','["而今用武爾攻文，流輩干時獨臥雲。", "白髮青袍趨會府，定應衡鏡却慙君。"]'),
('fd4458fa-8053-4817-a7e1-9d9b5fddd2fe','清江曲內一絕','崔峒','唐','唐诗','tang','','["\u957f\u6c5f"]','八月長江去浪平，片帆一道帶風輕。',32,'全唐诗/poet.tang.15000.json','["八月長江去浪平，片帆一道帶風輕。", "極目不分天水色，南山南是岳陽城。"]'),
('31c7702e-8d2a-4a2f-a7cc-2e07c7498f05','武康郭外望許緯先生山居','崔峒','唐','唐诗','tang','','[]','湖上千峰帶落暉，白雲開處見柴扉。',32,'全唐诗/poet.tang.15000.json','["湖上千峰帶落暉，白雲開處見柴扉。", "松門一逕仍生草，應是仙人向郭稀。"]'),
('b96b4bed-3730-4d2f-819a-b5a472a1107c','送司空曙之蘇州','苗發','唐','唐诗','tang','','[]','盤門吳舊地，蟬盡草秋時。',48,'全唐诗/poet.tang.15000.json','["盤門吳舊地，蟬盡草秋時。", "歸國人皆久，移家君獨遲。", "廣陵經水宿，建鄴有僧期。", "若到西霞寺，應看江總碑。"]'),
('d5a61d84-8246-462a-beae-fea8dbc3c0df','送孫德諭罷官往黔州','苗發','唐','唐诗','tang','','[]','中歲分符典石城，兩朝趨陛謁承明。',64,'全唐诗/poet.tang.15000.json','["中歲分符典石城，兩朝趨陛謁承明。", "闕下昨承歸老疏，天南今切去鄉情。", "親知握手三秋別，几杖扶身萬里行。", "伯道暮年無嗣子，欲將家事託門生。"]'),
('794b90fc-bcbe-41ac-945a-912255c2189a','送歸中丞使新羅冊立弔祭','吉中孚','唐','唐诗','tang','','[]','官稱漢獨坐，身是魯諸生。',72,'全唐诗/poet.tang.15000.json','["官稱漢獨坐，身是魯諸生。", "絕域通王制，窮天向水程。", "島中分萬象，日處轉雙旌。", "氣積魚龍窟，濤翻水浪聲。", "路長經歲去，海盡向山行。", "復道殊方禮，人瞻漢使榮。"]'),
('4cff990b-3924-447a-bebd-71e49aa9fd89','詠被中繡鞵','夏侯審','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u548f\u7269", "\u8273\u60c5"]','雲裏蟾鉤落鳳窩，玉郎沈醉也摩挲。',32,'全唐诗/poet.tang.15000.json','["雲裏蟾鉤落鳳窩，玉郎沈醉也摩挲。", "陳王當日風流減，只向波間見襪羅。"]'),
('6f972a01-6d28-4693-aa79-68840f6fc049','行路難','王烈','唐','唐诗','tang','','[]','行客滿長路，路長良足哀。',60,'全唐诗/poet.tang.15000.json','["行客滿長路，路長良足哀。", "白日持角弓，射人而取財。", "千金誰家子，紛紛死黃埃。", "見者不敢言，言者不得回。", "家人各望歸，豈知長不來。"]'),
('887ebd54-4d78-41de-8082-a636a184fc0a','雪','王烈','唐','唐诗','tang','','[]','雪飛當夢蝶，風度幾驚人。',48,'全唐诗/poet.tang.15000.json','["雪飛當夢蝶，風度幾驚人。", "半夜一窗曉，平明千樹春。", "花園應失路，白屋忽爲鄰。", "散入仙廚裏，還如雲母塵。"]'),
('3cf00a29-37e1-48fc-8277-fc915eda0495','酬崔峝','王烈','唐','唐诗','tang','','[]','狥世甘長往，逢時忝一官。',48,'全唐诗/poet.tang.15000.json','["狥世甘長往，逢時忝一官。", "欲朝青瑣去，羞向白雲看。", "榮寵無心易，艱危抗節難。", "思君寫懷抱，非敢和幽蘭。"]'),
('23a06f51-e1f9-44af-9fdd-35e3c6ed92ca','塞上曲二首 一','王烈','唐','唐诗','tang','','[]','紅顏歲歲老金微，砂磧年年臥鐵衣。',32,'全唐诗/poet.tang.15000.json','["紅顏歲歲老金微，砂磧年年臥鐵衣。", "白草城中春不入，黃花戍上鴈長飛。"]'),
('9d2e9575-91b2-4e8c-9b4b-eaaf27df10dd','塞上曲二首 二','王烈','唐','唐诗','tang','','[]','孤城夕對戍樓閑，迴合青冥萬仞山。',32,'全唐诗/poet.tang.15000.json','["孤城夕對戍樓閑，迴合青冥萬仞山。", "明鏡不須生白髮，風沙自解老紅顏。"]'),
('1a10b41f-45f7-42fe-9728-30d1e9418660','傷李端','衞象','唐','唐诗','tang','','[]','才子浮生促，泉臺此路賒。',48,'全唐诗/poet.tang.15000.json','["才子浮生促，泉臺此路賒。", "官卑揚執戟，年少賈長沙。", "人去門栖鵩，災成酒誤虵。", "唯餘封禪草，留在茂陵家。"]'),
('d4dbe585-74e3-44ed-a767-4692b9e9c39c','古詞','衞象','唐','唐诗','tang','','[]','鵲血琱弓濕未乾，鸊鵜新淬劒光寒。',32,'全唐诗/poet.tang.15000.json','["鵲血琱弓濕未乾，鸊鵜新淬劒光寒。", "遼東老將鬢成雪，猶向旄頭夜夜看。"]'),
('a6c01e2e-acb8-46ec-8e77-ceacd788b9f7','晴江秋望','崔季卿','唐','唐诗','tang','','["\u957f\u6c5f", "\u6d1e\u5ead\u6e56", "\u79cb\u5929", "\u8d5e\u7f8e"]','八月長江萬里晴，千帆一道帶風輕。',32,'全唐诗/poet.tang.15000.json','["八月長江萬里晴，千帆一道帶風輕。", "盡日不分天水色，洞庭南是岳陽城。"]'),
('d22f1a49-5ef6-4df6-b365-f9ba2fe2442c','贈兄','何兆','唐','唐诗','tang','','[]','洛陽紙價因兄貴，蜀地紅牋爲弟貧。',32,'全唐诗/poet.tang.15000.json','["洛陽紙價因兄貴，蜀地紅牋爲弟貧。", "南北東西九千里，除兄與弟更無人。"]'),
('db497d72-aefd-4639-88d1-dc93999b1de4','玉蘂花','何兆','唐','唐诗','tang','','[]','羽車潛下玉龜山，塵世何緣覩蕣顏。',32,'全唐诗/poet.tang.15000.json','["羽車潛下玉龜山，塵世何緣覩蕣顏。", "惟有多情天上雪，好風吹上綠雲鬟。"]'),
('a8cb3dc3-f809-4681-907c-49afb54f3015','句','何兆','唐','唐诗','tang','','[]','芙蓉十二池心漏，薝蔔三千灌頂香。',16,'全唐诗/poet.tang.15000.json','["芙蓉十二池心漏，薝蔔三千灌頂香。"]'),
('d2c6ea87-8f59-4fdf-aa86-232255783cb9','嚴陵灘下寄常建','奚賈','唐','唐诗','tang','','[]','日入溪水靜，尋真此亦難。',72,'全唐诗/poet.tang.15000.json','["日入溪水靜，尋真此亦難。", "乃知滄洲人，道成仍釣竿。", "漾檝乘微月，振衣生早寒。", "紛吾成獨往，自速耽考槃。", "已息漢陰誚，且同濠上觀。", "曠然心無涯，誰問容膝安。"]'),
('ac8e5604-8985-4de3-bc4a-2904364dcfe9','謁李尊師','奚賈','唐','唐诗','tang','','[]','萬物返常性，惟道貴自然。',48,'全唐诗/poet.tang.15000.json','["萬物返常性，惟道貴自然。", "先生容其微，隱几爲列仙。", "鍊魄閉瓊戶，養毛飛洞天。", "將知逍遙久，得道無歲年。"]'),
('edc6142f-c234-48ed-8e65-4c9bef714834','尋許山人亭子','奚賈','唐','唐诗','tang','','[]','桃源若遠近，漁子櫂輕舟。',48,'全唐诗/poet.tang.15000.json','["桃源若遠近，漁子櫂輕舟。", "川路行難盡，人家到漸幽。", "山禽拂席起，溪水入庭流。", "君是何年隱，如今成白頭。"]'),
('20bb2033-bc83-4b7c-be92-bb3066b03aa7','句','奚賈','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','眠澗花自落，步林鳥不飛。',36,'全唐诗/poet.tang.15000.json','["眠澗花自落，步林鳥不飛。", "谿谷何蕭條，日入人獨行。", "落日下平楚，孤煙生洞庭。"]'),
('0ba0acd3-935e-4e2a-bd8c-d9d62532758f','富陽南樓望浙江風起','張南史','唐','唐诗','tang','','[]','南樓渚風起，樹杪見滄波。',48,'全唐诗/poet.tang.15000.json','["南樓渚風起，樹杪見滄波。", "稍覺征帆上，蕭蕭暮雨多。", "沙洲殊未極，雲水更相和。", "欲問任公子，垂綸意若何。"]'),
('921c64b8-bb7b-48dc-9f1f-799076ee6349','奉酬李舍人秋日寓直見寄','張南史','唐','唐诗','tang','','[]','秋日金華直，遙知玉佩清。',48,'全唐诗/poet.tang.15000.json','["秋日金華直，遙知玉佩清。", "九重門更肅，五色詔初成。", "槐落宮中影，鴻高苑外聲。", "飜從魏闕下，江海寄幽情。"]'),
('6fa1dc58-6378-4da2-9b04-640aa565ab05','同韓侍郎秋朝使院','張南史','唐','唐诗','tang','','[]','重門啓曙關，一葉報秋還。',48,'全唐诗/poet.tang.15000.json','["重門啓曙關，一葉報秋還。", "露井桐柯濕，風庭鶴翅閒。", "忘情簪白筆，假夢入青山。", "惆悵祗應此，難裁語默間。"]'),
('d5f86b06-3568-4bf7-95ac-7ca3e383b074','送朱大遊塞','張南史','唐','唐诗','tang','','[]','歲暮一爲別，江湖聊自寬。',48,'全唐诗/poet.tang.15000.json','["歲暮一爲別，江湖聊自寬。", "且無人事處，誰謂客行難。", "郢曲憐公子，吳州憶伯鸞。", "蒼蒼遠山際，松柏獨宜寒。"]'),
('fe45ab35-fb40-4650-bc87-ccd12776c478','送鄭錄事赴太原','張南史','唐','唐诗','tang','','[]','歎息不相見，紅顏今白頭。',48,'全唐诗/poet.tang.15000.json','["歎息不相見，紅顏今白頭。", "重爲西候別，方起北風愁。", "六月胡天冷，雙城汾水流。", "盧諶即故吏，還復向幷州。"]'),
('f5608e2a-b7e9-4cc4-8b23-cf45036f80d3','送余贊善使還赴薛尚書幕','張南史','唐','唐诗','tang','','[]','音書不可論，河塞雪紛紛。',48,'全唐诗/poet.tang.15000.json','["音書不可論，河塞雪紛紛。", "雁足期蘇武，狐裘見薛君。", "城池通紫陌，鞍馬入黃雲。", "遠棹漳渠水，平流幾處分。"]'),
('a5311d52-89f9-4ab0-a879-234456f23778','送李侍御入茅山採藥','張南史','唐','唐诗','tang','','[]','苦縣家風在，茅山道錄傳。',48,'全唐诗/poet.tang.15000.json','["苦縣家風在，茅山道錄傳。", "聊聽驄馬使，却就紫陽仙。", "江海生岐路，雲霞入洞天。", "莫令千歲鶴，飛到草堂前。"]'),
('ad17b1f6-13c6-4030-9709-a880fae6b672','寄中書李舍人','張南史','唐','唐诗','tang','','[]','昨宵淒斷處，對月與臨風。',48,'全唐诗/poet.tang.15000.json','["昨宵淒斷處，對月與臨風。", "鶴病三江上，蘭衰百草中。", "題詩隨謝客，飲酒寄黃翁。", "早歲心相待，還因貴賤同。"]'),
('9391ef33-933e-452d-8fc3-5c6ccfe8eb12','和崔中丞中秋月','張南史','唐','唐诗','tang','','[]','秋夜月偏明，西樓獨有情。',48,'全唐诗/poet.tang.15000.json','["秋夜月偏明，西樓獨有情。", "千家看露濕，萬里覺天清。", "映水金波動，銜山桂樹生。", "不知飛鵲意，何用此時驚。"]'),
('723959fc-7c26-46a6-be23-6532a951edf9','西陵懷靈一上人兼寄朱放','張南史','唐','唐诗','tang','','[]','淮海風濤起，江關憂思長。',48,'全唐诗/poet.tang.15000.json','["淮海風濤起，江關憂思長。", "同悲鵲遶樹，獨坐雁隨陽。", "山晚雲藏雪，汀寒月照霜。", "由來濯纓處，漁父愛滄浪。"]'),
('cb63a531-5e8b-4da9-b04b-5351b3bad171','寄靜虛上人雲門','張南史','唐','唐诗','tang','','[]','寒日白雲裏，法侶自提攜。',48,'全唐诗/poet.tang.15000.json','["寒日白雲裏，法侶自提攜。", "竹徑通城下，松門隔水西。", "方同沃洲去，不自武陵迷。", "髣髴心疑處，高峯是會稽。"]'),
('721bea36-8cbd-4787-974d-23b4760c8b6b','送司空十四北遊宋州','張南史','唐','唐诗','tang','','[]','九拒危城下，蕭條送爾歸。',48,'全唐诗/poet.tang.15000.json','["九拒危城下，蕭條送爾歸。", "寒風吹畫角，暮雪犯征衣。", "道里猶成間，親朋重與違。", "白雲愁欲斷，看入大梁飛。"]'),
('b9328299-6903-4418-93f1-e4172e7e3320','殷卿宅夜宴','張南史','唐','唐诗','tang','','[]','日暗城烏宿，天寒櫪馬嘶。',48,'全唐诗/poet.tang.15000.json','["日暗城烏宿，天寒櫪馬嘶。", "詞人留上客，妓女出中閨。", "積雪連燈照，迴廊映竹迷。", "太常今夜宴，誰不醉如泥。"]'),
('c2d39297-ba40-40e6-94b9-b09cdffebaae','宣城雪後還望郡中寄孟侍御','張南史','唐','唐诗','tang','','[]','臘後年華變，關西驛騎遙。',48,'全唐诗/poet.tang.15000.json','["臘後年華變，關西驛騎遙。", "塞鴻連暮雪，江柳動寒條。", "山水還鄣郡，圖書入漢朝。", "高樓非別處，故使百憂銷。"]'),
('1b7e6f4d-499f-4489-a106-c60a0532087a','獨孤常州北亭','張南史','唐','唐诗','tang','','[]','北洫敞高明，憑軒見野情。',72,'全唐诗/poet.tang.15000.json','["北洫敞高明，憑軒見野情。", "朝回五馬跡，更勝百花名。", "海樹凝煙遠，湖田見鶴清。", "雲光侵素壁，水影蕩閒楹。", "俗賴褰帷謁，人歡倒屣迎。", "始能崇結構，獨有謝宣城。"]'),
('7038ee94-a84c-4d53-80a9-90430ce36af1','早春書事奉寄中書李舍人','張南史','唐','唐诗','tang','','["\u957f\u6c5f"]','儒服山東士，衡門洛下居。',288,'全唐诗/poet.tang.15000.json','["儒服山東士，衡門洛下居。", "風塵遊上路，簡冊委空廬。", "戎馬生郊日，賢人避地初。", "竄身初浩蕩，投跡豈躊躇。", "翠羽憐窮鳥，瓊枝顧散樗。", "還令親道術，倒欲混樵漁。", "敝緼袍多補，飛蓬鬢少梳。", "誦詩陪賈誼，酌酒伴應璩。", "鶴膝兵家備，鳧茨儉歲儲。", "泊舟依野水，開逕接園蔬。", "暫閱新山澤，長懷故里閭。", "思賢乘朗月，覽古到荒墟。", "在竹慙充箭，爲蘭幸免鋤。", "那堪聞相府，更遣詣公車。", "蹇足終難進，嚬眉竟未舒。", "事從因病止，生寄負恩餘。", "不見神仙久，無由鄙恡祛。", "帝庭張禮樂，天閣繡簪裾。", "日色浮青瑣，香煙近玉除。", "神清王子敬，氣逐馬相如。", "銅漏時常靜，金門步轉徐。", "唯看五字表，不記八行書。", "宿昔投知己，周旋謝起予。", "祇應高位隔，詎是故情疎。"]'),
('99e9e559-6f81-4757-9b14-827d6d4aa2de','陸勝宅秋暮雨中探韻同作','張南史','唐','唐诗','tang','','[]','同人永日自相將，深竹閒園偶辟疆。',64,'全唐诗/poet.tang.15000.json','["同人永日自相將，深竹閒園偶辟疆。", "已被秋風教憶鱠，更聞寒雨勸飛觴。", "歸心莫問三江水，旅服徒沾九日霜。", "醉裏欲尋騎馬路，蕭條幾處有垂楊。"]'),
('e01bfd47-271a-4897-85aa-0b6c469e19f9','春日道中寄孟侍御','張南史','唐','唐诗','tang','','[]','春來游子傍歸路，時有白雲遮獨行。',64,'全唐诗/poet.tang.15000.json','["春來游子傍歸路，時有白雲遮獨行。", "水流亂赴石潭響，花開不知山樹名。", "誰家魚網求鮮食，幾處人煙事火耕。", "昨日已嘗村酒熟，一杯思與孟嘉傾。"]'),
('91ba74c4-82ef-4760-a723-9916b32800bc','江北春望贈皇甫補闕','張南史','唐','唐诗','tang','','[]','閒園柳綠井桃紅，野徑荒墟左右通。',64,'全唐诗/poet.tang.15000.json','["閒園柳綠井桃紅，野徑荒墟左右通。", "清逈獨連江水北，芳菲更似洛城東。", "時看雨歇人歸岫，每覺潮來樹起風。", "聞道金門堪避世，何須身與海鷗同。"]'),
('986ee647-9f82-44bf-908e-9d31e70e29bc','酬張二倉曹楊子閒居見寄兼呈韓郎中左補闕皇甫冉','張南史','唐','唐诗','tang','','[]','孤雲獨鶴自悠悠，別後經年尚泊舟。',64,'全唐诗/poet.tang.15000.json','["孤雲獨鶴自悠悠，別後經年尚泊舟。", "漁父致詞相借問，仙郎能賦許依投。", "折芳遠計三春草，乘興閒看萬里流。", "莫怪杜門頻乞假，不堪扶病拜龍樓。"]'),
('f3900a71-2d1e-4099-81d9-2f4e099b0940','秋夜聞鴈寄南十五兼呈空和尚','張南史','唐','唐诗','tang','','[]','晚節聞君道趣深，結茅栽樹近東林。',64,'全唐诗/poet.tang.15000.json','["晚節聞君道趣深，結茅栽樹近東林。", "禪師幾度曾摩頂，高士何年更發心。", "北渚三更聞過鴈，西城萬木動寒砧。", "不見支公與玄度，相思擁膝坐長吟。"]'),
('712df10d-a110-4c39-8d92-d93874a499fc','雪','張南史','唐','唐诗','tang','','[]','雪，雪。',70,'全唐诗/poet.tang.15000.json','["雪，雪。", "花片，玉屑。", "結陰風，凝暮節。", "高嶺虛晶，平原廣潔。", "初從雲外飄，還向空中噎。", "千門萬戶皆靜，獸炭皮裘自熱。", "此時雙舞洛陽人，誰悟郢中歌斷絕。"]'),
('45e3e037-699c-41df-a14f-9c2835334fcc','月','張南史','唐','唐诗','tang','','[]','月，月。',70,'全唐诗/poet.tang.15000.json','["月，月。", "暫盈，還缺。", "上虛空，生溟渤。", "散彩無際，移輪不歇。", "桂殿入西秦，菱歌映南越。", "正看雲霧秋卷，莫待關山曉沒。", "天涯地角不可尋，清光永夜何超忽。"]'),
('b3754072-4bb7-47ba-9ea4-5a5d4d8e4949','泉','張南史','唐','唐诗','tang','','[]','泉，泉。',70,'全唐诗/poet.tang.15000.json','["泉，泉。", "色淨，苔鮮。", "石上激，雲中懸。", "津流竹樹，脉亂山川。", "扣玉千聲應，含風百道連。", "太液倂歸池上，雲陽舊出宮邊。", "北陵井深鑿不到，我欲添淚作潺湲。"]'),
('88ec78ff-b1f5-4176-aa01-60bd10186362','竹','張南史','唐','唐诗','tang','','[]','竹，竹。',70,'全唐诗/poet.tang.15000.json','["竹，竹。", "披山，連谷。", "出東南，殊草木。", "葉細枝動，霜停露宿。", "成林處處雲，抽笋年年玉。", "天風乍起爭韻，池水相涵更綠。", "却尋庾信小園中，閒對數竿心自足。"]'),
('3584c703-97e7-45ca-92df-a8decb1b31b5','花','張南史','唐','唐诗','tang','','[]','花，花。',70,'全唐诗/poet.tang.15000.json','["花，花。", "深淺，芬葩。", "凝爲雪，錯爲霞。", "鶯和蝶到，苑占宮遮。", "已迷金谷路，頻駐玉人車。", "芳草欲陵芳樹，東家半落西家。", "願得春風相伴去，一攀一折向天涯。"]'),
('cd638a99-949f-4db8-9655-ba974f9d0de1','草','張南史','唐','唐诗','tang','','[]','草，草。',70,'全唐诗/poet.tang.15000.json','["草，草。", "折宜，看好。", "滿地生，催人老。", "金殿玉砌，荒城古道。", "青青千里遙，悵悵三春早。", "每逢南北離別，乍逐東西傾倒。", "一身本是山中人，聊與王孫慰懷抱。"]'),
('55ff7275-ebbb-4a1f-ba4e-30a9f4937113','送人','王建','唐','唐诗','tang','','["\u9ec4\u6cb3"]','白日向西沒，黃河復東流。',144,'全唐诗/poet.tang.15000.json','["白日向西沒，黃河復東流。", "人生足著地，寧免四方遊。", "我行無返顧，祝子勿回頭。", "當須向前去，何用起離憂。", "但恐無廣路，平地作山丘。", "令我車與馬，欲疾反停留。", "蜀客多積貨，邊人易封侯。", "男兒戀家鄉，歡樂爲仇讐。", "丁寧相勸勉，苦口幸無尤。", "對面無相成，不如豺虎儔。", "彼遠不寄書，此寒莫寄裘。", "與君俱絕跡，兩念無因由。"]'),
('cc77a4a0-3e5c-456f-8bf2-739e4ec6e477','主人故亭','王建','唐','唐诗','tang','','[]','主人昔專城，城南起高亭。',168,'全唐诗/poet.tang.15000.json','["主人昔專城，城南起高亭。", "貴與賓客遊，工者夜不寧。", "酒食宴圃人，栽接望早成。", "經年使家僮，遠道求異英。", "郡中暫閑暇，遶樹引諸生。", "開泉浴山禽，爲愛山中聲。", "世間事難保，一日各徂征。", "死生不相及，花落實方榮。", "我來至此中，守吏非本名。", "重君昔爲主，相與下馬行。", "舊島日日摧，池水不復清。", "豈無後人賞，所貴手自營。", "澆酒向所思，風起如有靈。", "此去不重來，重來傷我形。"]'),
('4f447572-d25c-4898-a1c0-0f2f1a8194e8','古從軍','王建','唐','唐诗','tang','','[]','漢家逐單于，日沒處河曲。',96,'全唐诗/poet.tang.15000.json','["漢家逐單于，日沒處河曲。", "浮雲道旁起，行子車下宿。", "槍城圍鼓角，氈帳依山谷。", "馬上懸壺漿，刀頭分頰肉。", "來時高堂上，父母親結束。", "回面不見家，風吹破衣服。", "金瘡在肢節，相與拔箭鏃。", "聞道西涼州，家家婦女哭。"]'),
('f60d0421-7813-4060-9dbe-fb59533a778b','邯鄲主人','王建','唐','唐诗','tang','','[]','遠客無主人，夜投邯鄲市。',96,'全唐诗/poet.tang.15000.json','["遠客無主人，夜投邯鄲市。", "飛蛾繞殘燭，半夜人醉起。", "壚邊酒家女，遺我緗綺被。", "合成雙鳳花，宛轉不相離。", "縱令顏色改，勿遣合歡異。", "一念始爲難，萬金誰足貴。", "門前長安道，去者如流水。", "晨風羣鳥翔，裴回別離此。"]'),
('1876a213-663e-4780-ae52-068af79122c3','泛水曲','王建','唐','唐诗','tang','','[]','載酒入煙浦，方舟泛綠波。',72,'全唐诗/poet.tang.15000.json','["載酒入煙浦，方舟泛綠波。", "子酌我復飲，子飲我還歌。", "蓮深微路通，峰曲幽氣多。", "閱芳無留瞬，弄桂不停柯。", "水上秋日鮮，西山碧峩峩。", "茲歡良可貴，誰復更來過。"]'),
('b41259ac-cee7-406a-9ee7-089d0ea337e2','江南雜體二首 一','王建','唐','唐诗','tang','','[]','江上風翛翛，竹間湘水流。',36,'全唐诗/poet.tang.15000.json','["江上風翛翛，竹間湘水流。", "日夜桂花落，行人去悠悠。", "復見離別處，蟲聲陰雨秋。"]'),
('519df5eb-79c7-4f25-87bc-e51522aaa186','江南雜體二首 二','王建','唐','唐诗','tang','','[]','處處江草綠，行人發瀟湘。',36,'全唐诗/poet.tang.15000.json','["處處江草綠，行人發瀟湘。", "瀟湘回雁多，日夜思故鄉。", "春夢不知數，空山蘭蕙芳。"]'),
('36c4627f-ef62-4ee3-8652-4d6399bd5512','遠征歸','王建','唐','唐诗','tang','','[]','萬里發遼陽，處處問家鄉。',48,'全唐诗/poet.tang.15000.json','["萬里發遼陽，處處問家鄉。", "回車不淹轍，雨雪滿衣裳。", "行見日月疾，坐思道路長。", "但令不征戍，暗鏡生重光。"]'),
('fed7bba3-9372-4ffb-bce2-5733cb757be5','思遠人','王建','唐','唐诗','tang','','[]','妾思常懸懸，君行復綿綿。',48,'全唐诗/poet.tang.15000.json','["妾思常懸懸，君行復綿綿。", "征途向何處，碧海與青天。", "歲久自有念，誰令長在邊。", "少年若不歸，蘭室如黃泉。"]'),
('6d6c9fbb-dd8b-4272-9419-b821f5099672','傷近者不見','王建','唐','唐诗','tang','','[]','離人隔中庭，幸不爲遠征。',48,'全唐诗/poet.tang.15000.json','["離人隔中庭，幸不爲遠征。", "雕梁下有壁，聞語亦聞行。", "天涯尚寄信，此處不傳情。", "君能並照水，形影自分明。"]'),
('a9efd292-5e45-487a-b4ad-fec81366b5c3','元日早朝','王建','唐','唐诗','tang','','[]','大國禮樂備，萬邦朝元正。',192,'全唐诗/poet.tang.15000.json','["大國禮樂備，萬邦朝元正。", "東方色未動，冠劒門已盈。", "帝居在蓬萊，肅肅鐘漏清。", "將軍領羽林，持戟巡宮城。", "翠華皆宿陳，雪仗羅天兵。", "庭燎遠煌煌，旗上日月明。", "聖人龍火衣，寢殿開旋扃。", "龍樓橫紫煙，宮女天中行。", "六蕃倍位次，衣服各異形。", "舉頭看玉牌，不識宮殿名。", "左右雉扇開，蹈舞分滿庭。", "朝服帶金玉，珊珊相觸聲。", "泰階備雅樂，九奏鸞鳳鳴。", "裴回慶雲中，竽磬寒錚錚。", "三公再獻壽，上帝錫永貞。", "天明告四方，羣后保太平。"]'),
('fd65fb3f-d418-4cd7-8658-444d19f1327b','聞故人自征戍回','王建','唐','唐诗','tang','','[]','昔聞著征戍，三年一還鄉。',132,'全唐诗/poet.tang.15000.json','["昔聞著征戍，三年一還鄉。", "今來不換兵，須死在戰場。", "念子無氣力，徒學事戎行。", "少年得生還，有同墮穹蒼。", "自去報爾家，再行上高堂。", "爾弟修廢櫪，爾母縫新裳。", "恍恍恐不真，猶未苦承望。", "每日空出城，畏渴攜壺漿。", "安得縮地經，忽使在我傍。", "亦知遠行勞，人悴馬玄黃。", "慎莫多停留，苦我居者腸。"]'),
('922842c3-c2c1-4c9f-9bc3-83a0580b01d1','七泉寺上方','王建','唐','唐诗','tang','','[]','長年好名山，本性今得從。',120,'全唐诗/poet.tang.15000.json','["長年好名山，本性今得從。", "回看塵蹟遙，稍見糜鹿蹤。", "老僧雲中居，石門青重重。", "陰泉養成龜，古壁飛却龍。", "掃石禮新經，懸幡上高峰。", "日夕猿鳥合，覓食聽山鐘。", "將火尋遠泉，煮茶傍寒松。", "晚隨收藥人，便宿南澗中。", "晨起衝露行，濕花枝茸茸。", "歸依向禪師，願作香火翁。"]'),
('44108987-73c2-4661-a258-cab7d617838b','從元太守夏讌西樓','王建','唐','唐诗','tang','','[]','六月晨亦熱，卑居多煩昏。',96,'全唐诗/poet.tang.15000.json','["六月晨亦熱，卑居多煩昏。", "五馬遊西城，几杖隨朱輪。", "西樓臨方塘，嘉木當華軒。", "鳧鷖滿中流，有酒復盈尊。", "山東地無山，平視大海垠。", "高風涼氣來，灝景沈清源。", "青衿儼坐傍，禮容益敦敦。", "願爲顏氏徒，歌詠夫子門。"]'),
('09d9d2b1-e2a0-499c-a673-bd9f9333a435','酬栢侍御聞與韋處士同遊靈臺寺見寄','王建','唐','唐诗','tang','','[]','西域傳中說，靈臺屬雍州。',240,'全唐诗/poet.tang.15000.json','["西域傳中說，靈臺屬雍州。", "有泉皆聖蹟，有石皆佛頭。", "所出薝蔔香，外國俗來求。", "毒蛇護其下，樵者不可偷。", "古碑在雲巔，備載置寺由。", "魏家移下來，後人始增修。", "近與韋處士，愛此山之幽。", "各自具所須，竹籠盛茶甌。", "牽馬過危棧，襞衣涉奔流。", "草開平路盡，林下大石稠。", "過郭轉經峰，忽見東西樓。", "瀑布當寺門，逬落衣裳秋。", "石苔鋪紫花，溪葉裁碧油。", "松根載殿高，飄颻仙山浮。", "縣中賢大夫，一月前此遊。", "賽神賀得雨，豈暇多停留。", "二十韻新詩，遠寄尋山儔。", "清冷玉澗泣，冷切石磬愁。", "君名高難閑，余身愚終休。", "相將長無因，從今生離憂。"]'),
('612f385f-0ae2-411c-a894-e24280d4dbfb','荆南贈別李肇著作轉韻詩','王建','唐','唐诗','tang','','[]','輝天復耀地，再爲歌詠始。',288,'全唐诗/poet.tang.15000.json','["輝天復耀地，再爲歌詠始。", "素傳學道徒，清門有君子。", "文澗瀉潺潺，德峰來壘壘。", "兩京二十年，投食公卿間。", "封章既不下，故舊多慙顏。", "賣馬市耕牛，却歸湘浦山。", "麥收蠶上簇，衣食應豐足。", "碧澗伴僧禪，秋山對雨宿。", "且歡身體適，幸免纓組束。", "上宰鎮荆州，敬重同歲遊。", "歡逢通世友，簡授畫戎籌。", "遲遲就公食，愴愴別野裘。", "主人開宴席，禮數無形迹。", "醉笑或顛吟，發談皆損益。", "臨甃理芳鮮，升堂引賓客。", "早歲慕嘉名，遠思今始平。", "孔門忝同轍，潘館幸諸甥。", "自知再婚娶，豈望爲親情。", "欣欣還切切，又二千里別。", "楚筆防寄書，蜀茶憂遠熱。", "關山足重疊，會合何時節。", "莫歎各從軍，且愁岐路分。", "美人停玉指，離瑟不中聞。", "爭向巴山夜，猿聲滿碧雲。"]'),
('4ea2fc96-eaad-49f9-8c58-72dee6735599','早發金堤驛','王建','唐','唐诗','tang','','[]','蟲聲四野合，月色滿城白。',96,'全唐诗/poet.tang.15000.json','["蟲聲四野合，月色滿城白。", "家家閉戶眠，行人發孤驛。", "離家尚苦熱，衣服唯輕綌。", "時節忽復遷，秋風徹經脈。", "人睡落塹轍，馬驚入蘆荻。", "慰遠時問程，驚昏忽搖策。", "從軍豈云樂，憂患常縈積。", "唯願在貧家，團圓過朝夕。"]'),
('6782377e-0381-425a-a12e-e8b8ae91c95e','和裴相公道中贈別張相公','王建','唐','唐诗','tang','','[]','雲間雙鳳鳴，一去一歸城。',48,'全唐诗/poet.tang.15000.json','["雲間雙鳳鳴，一去一歸城。", "鞍馬朝天色，封章戀闕情。", "日臨宮樹高，煙蓋沙草平。", "會當戎事息，聯影遶池行。"]'),
('66f3955f-e971-44b8-9d9e-ae10c784bf40','和錢舍人水植詩','王建','唐','唐诗','tang','','[]','盆裏盛野泉，晚鮮幽更好。',48,'全唐诗/poet.tang.15000.json','["盆裏盛野泉，晚鮮幽更好。", "初活草根浮，重生荷葉小。", "多時水馬出，盡日蜻蜓遶。", "朝早獨來看，冷星沈碧曉。"]'),
('8e75f834-9e40-4e26-8167-a63f3979d3d5','題壽安南館','王建','唐','唐诗','tang','','[]','明蒙竹間亭，天暖幽桂碧。',48,'全唐诗/poet.tang.15000.json','["明蒙竹間亭，天暖幽桂碧。", "雲生四面山，水接當階石。", "濕樹浴鳥痕，破苔臥鹿蹟。", "不緣塵駕觸，堪作商皓宅。"]'),
('db092216-2813-4abb-8802-fa92516db6f2','送張籍歸江東','王建','唐','唐诗','tang','','[]','清泉澣塵緇，靈藥釋昏狂。',204,'全唐诗/poet.tang.15000.json','["清泉澣塵緇，靈藥釋昏狂。", "君詩發大雅，正氣回我腸。", "復令五彩姿，潔白歸天常。", "昔歲同講道，青襟在師傍。", "出處兩相因，如彼衣與裳。", "行行成此歸，離我適咸陽。", "失意未還家，馬蹄盡四方。", "訪余詠新文，不倦道路長。", "僮僕懷昔念，亦如還故鄉。", "相親惜晝夜，寢息不異牀。", "猶將在遠道，忽忽起思量。", "黃金未爲罍，無以挹酒漿。", "所念俱貧賤，安得相發揚。", "回車遠歸省，舊宅江南廂。", "歸鄉非得意，但貴情義彰。", "五月天氣熱，波濤毒於湯。", "慎勿多飲酒，藥膳願自強。"]'),
('ab7653e1-0fe1-4051-bc3e-e6b08d29ae19','勵學','王建','唐','唐诗','tang','','[]','買地不肥實，其繁繫耕鑿。',96,'全唐诗/poet.tang.15000.json','["買地不肥實，其繁繫耕鑿。", "良田少鋤理，蘭焦香亦薄。", "勿以聽者迷，故使宮徵錯。", "誰言三歲童，還能分善惡。", "孜孜日求益，猶恐業未博。", "況我性頑蒙，復不勤修學。", "有如朝暮食，暫虧憂隕穫。", "若使無六經，賢愚何所託。"]'),
('d8aa0031-9b68-4a19-b6d0-6695b1021c0b','山中寄及第故人','王建','唐','唐诗','tang','','[]','長長南山松，短短北磵楊。',168,'全唐诗/poet.tang.15000.json','["長長南山松，短短北磵楊。", "俱承日月照，幸免斤斧傷。", "去年與子別，誠言暫還鄉。", "如何棄我去，天路忽騰驤。", "誰謂有雙目，識貌不識腸。", "豈知心內乖，著我薜蘿裳。", "尋君向前事，不歎今異翔。", "往往空室中，寤寐說珪璋。", "十年居此溪，松桂日蒼蒼。", "自從無佳人，山中不輝光。", "盡棄所留藥，亦焚舊草堂。", "還君誓已書，歸我學仙方。", "既爲參與辰，各願不相望。", "始終名利途，慎勿罹咎殃。"]'),
('cdc098ae-1b92-4a86-8a7e-469c5231d735','求友','王建','唐','唐诗','tang','','[]','鑒形須明鏡，療疾須良醫。',168,'全唐诗/poet.tang.15000.json','["鑒形須明鏡，療疾須良醫。", "若無傍人見，形疾安自知。", "世路薄言行，學成棄其師。", "每懷一飯恩，不重勸勉詞。", "斅學既不誠，朋友道日虧。", "遂作名利交，四海爭奔馳。", "常慕正直人，生死不相離。", "苟能成我身，甘與僮僕隨。", "我言彼當信，彼道我無疑。", "針藥及病源，以石投深池。", "終朝舉善道，敬愛當行之。", "縱令誤所見，亦貴本相規。", "不求立名聲，所貴去瑕玼。", "各願貽子孫，永爲後世資。"]'),
('4811480c-aba6-48b9-bc0d-241c51f17c8a','寄李益少監兼送張實遊幽州','王建','唐','唐诗','tang','','[]','大雅廢已久，人倫失其常。',192,'全唐诗/poet.tang.15000.json','["大雅廢已久，人倫失其常。", "天若不生君，誰復爲文綱。", "迷者得道路，溺者遇舟航。", "國風人已變，山澤增輝光。", "星辰有其位，豈合離帝傍。", "賢人既遐征，鳳鳥安來翔。", "少小慕高名，所念隔山岡。", "集卷新紙封，每讀常焚香。", "古來難自達，取鑑在賢良。", "未爲知音故，徒恨名不彰。", "諒無金石堅，性命豈能長。", "常恐一世中，不上君子堂。", "偉哉清河子，少年志堅強。", "篋中有素文，千里求發揚。", "自願音韻乖，無因合宮商。", "幸君達精誠，爲我求回章。"]'),
('0b11e727-9af6-4a6c-b4c1-daa5547e0ad0','寄崔列中丞','王建','唐','唐诗','tang','','[]','火山無冷地，濁流無清源。',156,'全唐诗/poet.tang.15000.json','["火山無冷地，濁流無清源。", "人生在艱世，何處避讒言。", "諸侯鎮九州，天子開四門。", "尚有忠義士，不得申其冤。", "嘉木移遠植，爲我當行軒。", "君子居要途，易失主人恩。", "我愛古人道，師君直且溫。", "貪泉誓不飲，邪路誓不奔。", "如何非岡坂，故使車輪翻。", "妓妾隨他人，家事幸獲存。", "當時門前客，默默空冤煩。", "從今遇明代，善惡亦須論。", "莫以曾見疑，直道遂不敦。"]'),
('6c4151f4-a21d-431c-a30b-220a65f5fecd','喩時','王建','唐','唐诗','tang','','[]','去者如弊帷，來者如新衣。',84,'全唐诗/poet.tang.15000.json','["去者如弊帷，來者如新衣。", "鮮華非久長，色落還棄遺。", "詎知行者夭，豈悟壯者衰。", "區區未死間，回面相是非。", "好聞苦不樂，好視忽生疵。", "乃明萬物情，皆逐人心移。", "古今盡如此，達士將何爲。"]'),
('33ab50e2-eea7-4403-afb3-34719c8495ed','贈王侍御','王建','唐','唐诗','tang','','[]','愚者昧邪正，貴將平道行。',168,'全唐诗/poet.tang.15000.json','["愚者昧邪正，貴將平道行。", "君子抱仁義，不懼天地傾。", "三受主人辟，方出咸陽城。", "遲疑匪自崇，將顯求賢名。", "自來掌軍書，無不盡臣誠。", "何必操白刃，始致海內平。", "恭事四海人，甚於敬公卿。", "有惡如己辱，聞善如已榮。", "或人居飢寒，進退陳中情。", "徹晏聽苦辛，坐臥身不寧。", "以心應所求，盡家猶爲輕。", "衣食有親疎，但恐踰禮經。", "我今願求益，詎敢爲友生。", "幸君揚素風，永作來者程。"]'),
('6f2cc792-642c-4d3a-8113-c9f46ea1fd7f','宋氏五女','王建','唐','唐诗','tang','','[]','五女誓終養，貞孝內自持。',120,'全唐诗/poet.tang.15000.json','["五女誓終養，貞孝內自持。", "兔絲自縈紆，不上青松枝。", "晨昏在親傍，閑則讀書詩。", "自得聖人心，不因儒者知。", "少年絕音華，貴絕父母詞。", "素釵垂兩髦，短窄古時衣。", "行成聞四方，徵詔環珮隨。", "同時入皇宮，聯影步玉墀。", "鄉中尚其風，重爲修茅茨。", "聖朝有良史，將此爲女師。"]'),
('c72f6a51-1cf2-4924-b193-bbe6bbb411ca','送于丹移家洺州','王建','唐','唐诗','tang','','[]','憶昔門館前，君當童子年。',216,'全唐诗/poet.tang.15000.json','["憶昔門館前，君當童子年。", "今來見成長，俱過遠所傳。", "詩禮不外學，兄弟相攻研。", "如彼販海翁，豈種溪中田。", "四方尚爾文，獨我敬爾賢。", "但愛金玉聲，不貴金玉堅。", "孤遺一室中，寢食不相捐。", "飽如腸胃同，疾若膚體連。", "耕者求沃土，漚者求深源。", "彼邦君子居，一日可徂遷。", "念此居處近，各爲衣食牽。", "從今不見面，猶勝異山川。", "既乖歡會期，鬱鬱兩難宣。", "素琴苦無徽，安得宮商全。", "他皆緩別日，我願促行軒。", "送人莫長歌，長歌離恨延。", "羸馬不知去，過門常盤旋。", "會當爲爾鄰，有地容一泉。"]'),
('c0f1e9a8-8f81-4001-9a1d-3fbe51e29e89','留別舍弟','王建','唐','唐诗','tang','','[]','孤賤相長育，未曾爲遠遊。',144,'全唐诗/poet.tang.15000.json','["孤賤相長育，未曾爲遠遊。", "誰不重歡愛，晨昏闕珍羞。", "出門念衣車，草木當窮秋。", "非疾有憂歎，實爲人子尤。", "世情本難合，對面隔山丘。", "況復干戈地，儒夫何所投。", "與爾俱長成，尚爲溝壑憂。", "豈非輕歲月，少小不勤修。", "從今解思量，勉力謀善猷。", "但得成爾身，衣食寧我求。", "固合受此訓，墮慢爲身羞。", "歲暮當歸來，慎莫懷遠遊。"]'),
('380d7f3c-cd6c-47ce-9ccb-a8a90906376f','壞屋','王建','唐','唐诗','tang','','[]','官家有壞屋，居者願離得。',96,'全唐诗/poet.tang.15000.json','["官家有壞屋，居者願離得。", "苟或幸其遷，回循任傾側。", "若當君子住，一日還修餙。", "必使換榱楹，先須木端直。", "永令雀與鼠，無處求棲息。", "堅固傳後人，從今勉勞力。", "以茲喩臣下，亦可成邦國。", "雖曰愚者詞，將來幸無惑。"]'),
('dccf57d8-9597-43fe-a8ea-034e4ae4776e','送薛蔓應舉','王建','唐','唐诗','tang','','[]','四海重貢獻，珠賮稱至珍。',168,'全唐诗/poet.tang.15000.json','["四海重貢獻，珠賮稱至珍。", "聖朝開禮闈，所貴集嘉賓。", "若生在世間，此路出常倫。", "一士登甲科，九族光彩新。", "憧憧車馬徒，爭路長安塵。", "萬目視高天，昇者得苦辛。", "況子當少年，丈人在咸秦。", "出門見宮闕，獻賦侍朱輪。", "有賢大國豐，無子一家貧。", "男兒富邦家，豈爲榮其身。", "煌煌文明代，俱幸生此辰。", "自顧非國風，難以合聖人。", "子去東堂上，我歸南澗濱。", "願君勤作書，與我山中鄰。"]'),
('9661054e-93f0-4f1b-bec0-0c83814e189d','將歸故山留別杜侍御','王建','唐','唐诗','tang','','[]','有川不得涉，有路不得行。',96,'全唐诗/poet.tang.15000.json','["有川不得涉，有路不得行。", "沈沈百憂中，一日如一生。", "錯來干諸侯，石田廢春耕。", "虎戟衞重門，何因達中誠。", "日月俱照輝，山川異陰晴。", "如何百里間，開目不見明。", "我今歸故山，誓與草木幷。", "願君去丘坂，長使道路平。"]'),
('fb751212-3263-4f61-ae0c-1c2397ac6578','送韋處士老舅','王建','唐','唐诗','tang','','[]','憶昨癡小年，不知有經籍。',168,'全唐诗/poet.tang.15000.json','["憶昨癡小年，不知有經籍。", "常隨童子遊，多向外家劇。", "偷花入鄰里，弄筆書牆壁。", "照水學梳頭，應門未穿幘。", "人前賞文性，棃果蒙不惜。", "賦字詠新泉，探題得幽石。", "自從出關輔，三十年作客。", "風雨一飄颻，親情多阻隔。", "如何二千里，塵土驅蹇瘠。", "良久陳苦辛，從頭歎衰白。", "既來今又去，暫笑還成戚。", "落日動征車，春風卷離席。", "雲臺觀西路，華岳祠前柏。", "會得過帝鄉，重尋舊行蹟。"]'),
('546e3a8a-d3a5-4930-8098-8754e020ca35','送同學故人','王建','唐','唐诗','tang','','[]','各爲四方人，此地同事師。',72,'全唐诗/poet.tang.15000.json','["各爲四方人，此地同事師。", "業成有先後，不得長相隨。", "出林多道路，緣岡復遶陂。", "念君辛苦行，令我形體疲。", "黃葉墮車前，四散當此時。", "亭上夜蕭索，山風水離離。"]'),
('dc82c7ca-e900-4c69-b6a9-9c14cd89aadf','幽州送申稷評事歸平盧','王建','唐','唐诗','tang','','[]','行子繞天北，山高塞復深。',72,'全唐诗/poet.tang.15000.json','["行子繞天北，山高塞復深。", "升堂展客禮，臨水濯纓襟。", "驅馳戎地馬，聚散林間禽。", "一杯瀉東流，各願無異心。", "薊亭雖苦寒，春夕勿重衾。", "從軍任白頭，莫賣故山岑。"]'),
('a90251b7-5025-4345-9e39-6e3b7f42230c','溫門山','王建','唐','唐诗','tang','','[]','早入溫門山，羣峰亂如戟。',120,'全唐诗/poet.tang.15000.json','["早入溫門山，羣峰亂如戟。", "崩崖欲相觸，呀豁斷行跡。", "脫屐尋淺流，定足畏欹石。", "路盡十里溪，地多千歲栢。", "洞門晝陰黑，深處惟石壁。", "似見丹砂光，亦聞鍾乳滴。", "靈池出山底，沸水沖地脈。", "暖氣成濕煙，濛濛窗中白。", "隨僧入古寺，便是雲外客。", "月出天氣涼，夜鐘山寂寂。"]'),
('1d84e98a-9ad7-4e40-b772-4da9680ad763','代故人新姬侍疾','王建','唐','唐诗','tang','','[]','雙轂不回轍，子疾已在傍。',48,'全唐诗/poet.tang.15000.json','["雙轂不回轍，子疾已在傍。", "侍坐長搖扇，迎醫漸下牀。", "新施箱中幔，未洗來時妝。", "奉君纏綿意，幸願莫相忘。"]'),
('74b26b8b-be15-482f-a6b0-0135133c917f','採桑','王建','唐','唐诗','tang','','[]','鳥鳴桑葉間，綠條復柔柔。',48,'全唐诗/poet.tang.15000.json','["鳥鳴桑葉間，綠條復柔柔。", "攀看去手近，放下長長鉤。", "黃花蓋野田，白馬少年遊。", "所念豈回顧，良人在高樓。"]'),
('f9ab989a-79e5-45b2-8eda-0cf6e74818dc','曉思','王建','唐','唐诗','tang','','[]','曉氣生綠水，春條露霏霏。',48,'全唐诗/poet.tang.15000.json','["曉氣生綠水，春條露霏霏。", "林間棲鳥散，遠念征人起。", "幽花宿含彩，早蝶寒弄翅。", "君行非晨風，詎能從門至。"]'),
('eb0080b1-c476-47dc-a946-c5b8d668ec27','早起','王建','唐','唐诗','tang','','[]','回燈正衣裳，出戶星未稀。',48,'全唐诗/poet.tang.15000.json','["回燈正衣裳，出戶星未稀。", "堂前候姑起，環珮生晨輝。", "暗池光羃䍥，密樹花葳蕤。", "九城鐘漏絕，遙聽直郎歸。"]'),
('684387fe-9020-4b93-97e8-37a7cda07cf3','酬張十八病中寄詩','王建','唐','唐诗','tang','','[]','本性慵遠行，綿綿病自生。',48,'全唐诗/poet.tang.15000.json','["本性慵遠行，綿綿病自生。", "見君綢繆思，慰我寂寞情。", "風幌夜不掩，秋燈照雨明。", "彼愁此又憶，一夕兩盈盈。"]'),
('c9159fcd-f025-43f3-b009-1ead5ede5268','涼州行','王建','唐','唐诗','tang','','[]','涼州四邊沙皓皓，漢家無人開舊道。',128,'全唐诗/poet.tang.15000.json','["涼州四邊沙皓皓，漢家無人開舊道。", "邊頭州縣盡胡兵，將軍別築防秋城。", "萬里人家皆已沒，年年旌節發西京。", "多來中國收婦女，一半生男爲漢語。", "蕃人舊日不耕犂，相學如今種禾黍。", "驅羊亦著錦爲衣，爲惜氈裘防鬬時。", "養蠶繅繭成匹帛，那堪繞帳作旌旗。", "城頭山雞鳴角角，洛陽家家學胡樂。"]'),
('124207a8-53d1-49be-aacd-ddcd530fab38','寒食行','王建','唐','唐诗','tang','','[]','寒食家家出古城，老人看屋少年行。',96,'全唐诗/poet.tang.15000.json','["寒食家家出古城，老人看屋少年行。", "丘壠年年無舊道，車徒散行入衰草。", "牧兒驅牛下塚頭，畏有家人來灑掃。", "遠人無墳水頭祭，還引婦姑望鄉拜。", "三日無火燒紙錢，紙錢那得到黃泉。", "但看壠上無新土，此中白骨應無主。"]'),
('31438fab-f58e-4e89-93c1-9a01aface955','促剌詞','王建','唐','唐诗','tang','','[]','促剌復促剌，水中無魚山無石。',94,'全唐诗/poet.tang.15000.json','["促剌復促剌，水中無魚山無石。", "少年雖嫁不得歸，頭白猶著父母衣。", "田邊舊宅非所有，我身不及逐雞飛。", "出門若有歸死處，猛虎當衢向前去。", "百年不遺踏君門，在家誰喚爲新婦。", "豈不見他鄰舍娘，嫁來常在舅姑傍。"]'),
('6aa3602c-eb42-4fc5-8839-215fd094ce16','壠頭水','王建','唐','唐诗','tang','','[]','壠水何年壠頭別，不在山中亦嗚咽。',96,'全唐诗/poet.tang.15000.json','["壠水何年壠頭別，不在山中亦嗚咽。", "征人塞耳馬不行，未到壠頭聞水聲。", "謂是西流入蒲海，還聞北去繞龍城。", "壠東壠西多屈曲，野麋飲水長簇簇。", "胡兵夜回水旁住，憶著來時磨劒處。", "向前無井復無泉，放馬回看壠頭樹。"]'),
('988939d3-4c01-4bbf-928d-0c542920c3d5','北邙行','王建','唐','唐诗','tang','','[]','北邙山頭少閑士，盡是洛陽人舊墓。',144,'全唐诗/poet.tang.15000.json','["北邙山頭少閑士，盡是洛陽人舊墓。", "舊墓人家歸葬多，堆著黃金無買處。", "天涯悠悠葬日促，岡坂崎嶇不停轂。", "高張素幕繞銘旌，夜唱挽歌山下宿。", "洛陽城北復城東，魂車祖馬長相逢。", "車轍廣若長安路，蒿草少於松柏樹。", "澗底盤陀石漸稀，盡向墳向作羊虎。", "誰家石碑文字滅，後人重取書年月。", "朝朝車馬送葬回，還起大宅與高臺。"]'),
('3bbfafbe-cb90-4552-8ddf-b3789804f5d2','溫泉宮行','王建','唐','唐诗','tang','','[]','十月一日天子來，青繩御路無塵埃。',128,'全唐诗/poet.tang.15000.json','["十月一日天子來，青繩御路無塵埃。", "宮前內裏湯各別，每箇白玉芙蓉開。", "朝元閣向山上起，城繞青山龍暖水。", "夜開金殿看星河，宮女知更月明裏。", "武皇得仙王母去，山雞晝鳴宮中樹。", "溫泉決決出宮流，宮使年年修玉樓。", "禁兵去盡無射獵，日西麋鹿登城頭。", "棃園弟子偷曲譜，頭白人間教歌舞。"]'),
('acb9fa7a-7147-40eb-8613-68de9dba2e19','春詞','王建','唐','唐诗','tang','','[]','紅煙滿戶日照梁，天絲軟弱蟲飛揚。',48,'全唐诗/poet.tang.15000.json','["紅煙滿戶日照梁，天絲軟弱蟲飛揚。", "菱花霍霍繞帷光，美人對鏡著衣裳。", "庭中並種相思樹，夜夜還棲雙鳳凰。"]'),
('b9857add-a99a-4c64-af63-2b22c8263508','遼東行','王建','唐','唐诗','tang','','["\u6218\u4e89", "\u51ac\u5929", "\u4e50\u5e9c", "\u8fd1\u4ee3\u66f2\u8f9e"]','遼東萬里遼水曲，古戍無城復無屋。',80,'全唐诗/poet.tang.15000.json','["遼東萬里遼水曲，古戍無城復無屋。", "黃雲蓋地雪作山，不惜黃金買衣服。", "戰回各自收弓箭，正西回面家鄉遠。", "年年郡縣送征人，將與遼東作丘坂。", "寧爲草木鄉中生，有身不向遼東行。"]'),
('d7806360-7bc2-41cb-b8bf-f889b1c9362e','塞上梅','王建','唐','唐诗','tang','','[]','天山路傍一株梅，年年花發黃雲下。',64,'全唐诗/poet.tang.15000.json','["天山路傍一株梅，年年花發黃雲下。", "昭君已歿漢使回，前後征人惟繫馬。", "日夜風吹滿隴頭，還隨隴水東西流。", "此花若近長安路，九衢年少無攀處。"]'),
('396a0cc2-38dc-45c7-be8a-615efb330b57','戴勝詞','王建','唐','唐诗','tang','','[]','戴勝誰與爾爲名，木中作窠牆上鳴。',64,'全唐诗/poet.tang.15000.json','["戴勝誰與爾爲名，木中作窠牆上鳴。", "聲聲催我急種轂，人家向田不歸宿。", "紫冠采采褐羽斑，銜得蜻蜓飛過屋。", "可憐白鷺滿綠池，不如戴勝知天時。"]'),
('db5e7031-fe00-4693-a3e0-ed08debf7dec','鞦韆詞','王建','唐','唐诗','tang','','[]','長長絲繩紫復碧，嫋嫋橫枝高百尺。',112,'全唐诗/poet.tang.15000.json','["長長絲繩紫復碧，嫋嫋橫枝高百尺。", "少年兒女重鞦韆，盤巾結帶分兩邊。", "身輕裙薄易生力，雙手向空如鳥翼。", "下來立定重繫衣，復畏斜風高不得。", "傍人送上那足貴，終賭鳴璫鬬自起。", "回回若與高樹齊，頭上寶釵從墮地。", "眼前爭勝難爲休，足踏平地看始愁。"]'),
('a30aff99-3d64-40a0-8585-4a1cb8f73780','開池得古釵','王建','唐','唐诗','tang','','[]','美人開池北堂下，拾得寶釵金未化。',80,'全唐诗/poet.tang.15000.json','["美人開池北堂下，拾得寶釵金未化。", "鳳凰半在雙股齊，鈿花落處生黃泥。", "當時墮地覓不得，暗想窗中還夜啼。", "可知將來對夫壻，鏡前學梳古時髻。", "莫言至死亦不遺，還似前人初得時。"]'),
('676c6fd4-203d-47e3-8aea-00e2a34d96ea','賽神曲','王建','唐','唐诗','tang','','[]','男抱琵琶女作舞，主人再拜聽神語。',96,'全唐诗/poet.tang.15000.json','["男抱琵琶女作舞，主人再拜聽神語。", "新婦上酒勿辭勤，使爾舅姑無所苦。", "椒漿湛湛桂座新，一雙長箭繫紅巾。", "但願牛羊滿家宅，十月報賽南山神。", "青天無風水復碧，龍馬上鞍牛服軛。", "紛紛醉舞踏衣裳，把酒路旁勸行客。"]'),
('39c1283a-f88c-4375-9f4c-70e3159ef04e','田家留客','王建','唐','唐诗','tang','','[]','人家少能留我屋，客有新漿馬有粟。',96,'全唐诗/poet.tang.15000.json','["人家少能留我屋，客有新漿馬有粟。", "遠行僮僕應苦飢，新婦廚中炊欲熟。", "不嫌田家破門戶，蠶房新泥無風土。", "行人但飲莫畏貧，明府上來何苦辛。", "丁寧回語屋中妻，有客勿令兒夜啼。", "雙塚直西有縣路，我教丁男送君去。"]'),
('af6128a3-ddea-4701-a489-e0f367f7200e','精衞詞','王建','唐','唐诗','tang','','[]','精衞誰教爾填海，海邊石子青磊磊。',80,'全唐诗/poet.tang.15000.json','["精衞誰教爾填海，海邊石子青磊磊。", "但得海水作枯池，海中魚龍何所爲。", "口穿豈爲空銜石，山中草木無全枝。", "朝在樹頭暮海裏，飛多羽折時墮水。", "高山未盡海未平，願我身死子還生。"]'),
('39142992-539e-419e-8546-182666f9ede6','老婦歎鏡','王建','唐','唐诗','tang','','[]','嫁時明鏡老猶在，黃金鏤畫雙鳳背。',64,'全唐诗/poet.tang.15000.json','["嫁時明鏡老猶在，黃金鏤畫雙鳳背。", "憶昔咸陽初買來，燈前自繡芙蓉帶。", "十年不開一片鐵，長向暗中梳白髮。", "今日後牀重照看，生死終當此長別。"]'),
('4af6a6ef-c011-48c1-9485-b5b6ec581fe6','望夫石','王建','唐','唐诗','tang','','[]','望夫處，江悠悠，化爲石，不回頭。',32,'全唐诗/poet.tang.15000.json','["望夫處，江悠悠，化爲石，不回頭。", "上頭日日風復雨，行人歸來石應語。"]'),
('dc55325f-3c89-4e22-ae8d-042170027926','別鶴曲','王建','唐','唐诗','tang','','[]','主人一去池水絕，池鶴散飛不相別。',64,'全唐诗/poet.tang.15000.json','["主人一去池水絕，池鶴散飛不相別。", "青天漫漫碧水重，知向何山風雪中。", "萬里雖然音影在，兩心終是死生同。", "池邊巢破松樹死，樹頭年年烏生子。"]'),
('a4b50477-282b-4699-886f-35c25410a3e0','烏棲曲','王建','唐','唐诗','tang','','[]','章華宮人夜上樓，君王望月西山頭。',32,'全唐诗/poet.tang.15000.json','["章華宮人夜上樓，君王望月西山頭。", "夜深宮殿門不鎖，白露滿山山葉墮。"]'),
('0a1d2b85-1c8e-4d56-8b68-083c95ec1cf3','雉將雛','王建','唐','唐诗','tang','','[]','雉咿喔，雛出㲉，毛斑斑，觜啄啄。',64,'全唐诗/poet.tang.15000.json','["雉咿喔，雛出㲉，毛斑斑，觜啄啄。", "學飛未得一尺高，還逐母行旋母脚。", "麥壟淺淺難蔽身，遠去戀雛低怕人。", "時時土中鼓兩翅，引雛拾蟲不相離。"]'),
('d2c97c4b-aff9-42a6-841b-cbc358d85ddf','白紵歌二首 一','王建','唐','唐诗','tang','','[]','天河漫漫北斗璨，宮中烏啼知夜半。',72,'全唐诗/poet.tang.15000.json','["天河漫漫北斗璨，宮中烏啼知夜半。", "新縫白紵舞衣成，來遲邀得吳王迎。", "低鬟轉面掩雙袖，玉釵浮動秋風生。", "酒多夜長夜未曉，月明燈光兩相照，後庭歌聲更窈窕。"]'),
('32e0c97c-34f5-4030-bd0a-a410f5643784','白紵歌二首 二','王建','唐','唐诗','tang','','[]','館娃宮中春日暮，荔枝木瓜花滿樹。',88,'全唐诗/poet.tang.15000.json','["館娃宮中春日暮，荔枝木瓜花滿樹。", "城頭烏棲休擊鼓，青蛾彈瑟白紵舞。", "夜天曈曈不見星，宮中火照西江明。", "美人醉起無次第，墮釵遺珮滿中庭。", "此時但願可君意，回晝爲宵亦不寐，年年奉君君莫棄。"]'),
('1eff153c-0993-4236-8430-289b1d13c8a0','短歌行','王建','唐','唐诗','tang','','["\u60dc\u65f6", "\u6bcd\u4eb2"]','人初生，日初出，上山遲，下山疾。',72,'全唐诗/poet.tang.15000.json','["人初生，日初出，上山遲，下山疾。", "百年三萬六千朝，夜裏分將強半日。", "有歌有舞須早爲，昨日健於今日時。", "人家見生男女好，不知男女催人老。", "短歌行，無樂聲。"]'),
('a2d88511-cac0-434e-a102-792458bc3af5','飲馬長城窟','王建','唐','唐诗','tang','','[]','長城窟，長城窟邊多馬骨。',92,'全唐诗/poet.tang.15000.json','["長城窟，長城窟邊多馬骨。", "古來此地無井泉，賴得秦家築城卒。", "征人飲馬愁不回，長城變作望鄉堆。", "蹄蹤未乾人去近，續後馬來泥污盡。", "枕弓睡著待水生，不見陰山在前陣。", "馬蹄足脫裝馬頭，健兒戰死誰封侯。"]'),
('98d7c675-3763-425d-827d-cd3d96d5ee38','烏夜啼','王建','唐','唐诗','tang','','[]','庭樹烏，爾何不向別處棲？',84,'全唐诗/poet.tang.15000.json','["庭樹烏，爾何不向別處棲？", "夜夜夜半當戶啼。", "家人把燭出洞戶，驚棲失羣飛落樹。", "一飛直欲飛上天，回回不離舊棲處。", "未明重繞主人屋，欲下空中黑相觸。", "風飄雨濕亦不移，君家樹頭多好枝。"]'),
('ec370770-8350-41f2-81ff-c79d7dc452fe','簇蠶辭','王建','唐','唐诗','tang','','[]','蠶欲老，箔頭作繭絲皓皓。',108,'全唐诗/poet.tang.15000.json','["蠶欲老，箔頭作繭絲皓皓。", "場寬地高風日多，不向中庭曬蒿草。", "神蠶急作莫悠揚，年來爲爾祭神桑。", "但得青天不下雨，上無蒼蠅下無鼠。", "新婦拜簇願繭稠，女灑桃漿男打鼓。", "三日開箔雪團團，先將新繭送縣官。", "已聞鄉里催織作，去與誰人身上著。"]'),
('1ea88702-91b1-4d3c-870b-14f3d4114781','渡遼水','王建','唐','唐诗','tang','','["\u6218\u4e89", "\u8fd1\u4ee3\u66f2\u8f9e", "\u4e50\u5e9c"]','渡遼水，此去咸陽五千里。',60,'全唐诗/poet.tang.15000.json','["渡遼水，此去咸陽五千里。", "來時父母知隔生，重著衣裳如送死。", "亦有白骨歸咸陽，營家各與題本鄉。", "身在應無回渡日，駐馬相看遼水傍。"]'),
('e6390608-433d-470e-912a-1f6dad0134fe','空城雀','王建','唐','唐诗','tang','','[]','空城雀，何不飛來人家住？',100,'全唐诗/poet.tang.15000.json','["空城雀，何不飛來人家住？", "空城無人種禾黍，土間生子草間長。", "滿地蓬蒿幸無主，近村雖有高樹枝。", "雨中無食長苦飢，八月小兒挾弓箭。", "家家畏向田頭飛，但能不出空城裏。", "秋時百草皆有子，報言黃口莫啾啾，長爾得成無橫死。"]'),
('72798678-f47c-43dc-bf79-43e41e388365','水運行','王建','唐','唐诗','tang','','[]','西江運船立紅幟，萬棹千帆繞江水。',128,'全唐诗/poet.tang.15000.json','["西江運船立紅幟，萬棹千帆繞江水。", "去年六月無稻苗，已說水鄉人餓死。", "縣官部船日算程，暴風惡雨亦不停。", "在生有樂當有苦，三年作官一年行。", "壞舟畏鼠復畏漏，恐向太倉折升斗。", "辛勤耕種非毒藥，看著不入農夫口。", "用盡百金不爲貴，但得一金即爲利。", "遠徵海稻供邊食，豈如多種邊頭地。"]'),
('301bcd5f-5135-4a43-a2d2-314423cf4b74','當窗織','王建','唐','唐诗','tang','','[]','歎息復歎息，園中有棗行人食。',94,'全唐诗/poet.tang.15000.json','["歎息復歎息，園中有棗行人食。", "貧家女爲富家織，翁母隔牆不得力。", "水寒手澁絲脆斷，續來續去心腸爛。", "草蟲促促機下啼，兩日催成一匹半。", "輸官上頂有零落，姑未得衣身不著。", "當窗却羨青樓倡，十指不動衣盈箱。"]'),
('1ea9829e-b553-4509-b2d3-68b31fd347b2','失釵怨','王建','唐','唐诗','tang','','[]','貧女銅釵惜於玉，失却來尋一日哭。',80,'全唐诗/poet.tang.15000.json','["貧女銅釵惜於玉，失却來尋一日哭。", "嫁時女伴與作妝，頭戴此釵如鳳凰。", "雙杯行酒六親喜，我家新婦宜拜堂。", "鏡中乍無失髻樣，初起猶疑在牀上。", "高樓翠鈿飄舞塵，明日從頭一遍新。"]'),
('4b18fd37-f900-44bc-86a6-84243776001f','春燕詞','王建','唐','唐诗','tang','','[]','新燕新燕何不定，東家綠池西家井。',96,'全唐诗/poet.tang.15000.json','["新燕新燕何不定，東家綠池西家井。", "飛鳴當戶影悠揚，一遶簷頭一遶梁。", "黃姑說向新婦女，去年墮子汙衣箱。", "已能辭山復過海，幸我堂前故巢在。", "求食慎勿愛高飛，空中飢鳶爲爾害。", "辛勤作窠在畫梁，願得年年主人富。"]'),
('9e4bef3c-d99d-41e4-899c-c0110ff6e378','主人故池','王建','唐','唐诗','tang','','[]','高池高閣上連起，荷葉團團蓋秋水。',32,'全唐诗/poet.tang.15000.json','["高池高閣上連起，荷葉團團蓋秋水。", "主人已遠涼風生，舊客不來芙蓉死。"]'),
('3fe183ad-90cb-4691-8e9f-4e71a133ee40','古宮怨','王建','唐','唐诗','tang','','[]','乳烏啞啞飛復啼，城頭晨夕宮中棲。',32,'全唐诗/poet.tang.15000.json','["乳烏啞啞飛復啼，城頭晨夕宮中棲。", "吳王別殿繞江水，後宮不開美人死。"]'),
('58568655-f115-4c02-bf0f-35eca3742bf4','關山月','王建','唐','唐诗','tang','','[]','關山月，營開道白前軍發。',44,'全唐诗/poet.tang.15000.json','["關山月，營開道白前軍發。", "凍輪當磧光悠悠，照見三堆兩堆骨。", "邊風割面天欲明，金沙嶺西看看沒。"]'),
('a48bafe1-dc29-4500-b83b-78937237372f','贈離曲','王建','唐','唐诗','tang','','[]','合歡葉墮梧桐秋，鴛鴦背飛水分流。',96,'全唐诗/poet.tang.15000.json','["合歡葉墮梧桐秋，鴛鴦背飛水分流。", "少年使我忽相棄，雌號雄鳴夜悠悠。", "夜長月沒蟲切切，冷風入房燈焰滅。", "若知中路各西東，彼此不忘同心結。", "收取頭邊蛟龍枕，留著箱中雙雉裳。", "我今焚却舊房物，免使他人登爾牀。"]'),
('1bc0a972-789b-493a-83f9-d597d1eee3b3','宛轉詞','王建','唐','唐诗','tang','','[]','宛宛轉轉勝上紗，紅紅綠綠苑中花。',32,'全唐诗/poet.tang.15000.json','["宛宛轉轉勝上紗，紅紅綠綠苑中花。", "紛紛泊泊夜飛鵶，寂寂寞寞離人家。"]'),
('94e1f141-b25f-4c12-8084-534b4210bd49','水夫謠','王建','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11"]','苦哉生長當驛邊，官家使我牽驛船。',128,'全唐诗/poet.tang.15000.json','["苦哉生長當驛邊，官家使我牽驛船。", "辛苦日多樂日少，水宿沙行如海鳥。", "逆風上水萬斛重，前驛迢迢後淼淼。", "半夜緣堤雪和雨，受他驅遣還復去。", "衣寒衣濕披短蓑，臆穿足裂忍痛何。", "到明辛苦無處說，齊聲騰踏牽船出。", "一間茆屋何所值，父母之鄉去不得。", "我願此水作平田，長使水夫不怨天。"]'),
('649329b5-17f4-4af1-8476-6e428b814cdf','田家行','王建','唐','唐诗','tang','','["\u751f\u6d3b", "\u4e50\u5e9c", "\u65b0\u4e50\u5e9c\u8f9e", "\u519c\u6c11"]','男聲欣欣女顏悅，人家不怨言語別。',96,'全唐诗/poet.tang.15000.json','["男聲欣欣女顏悅，人家不怨言語別。", "五月雖熱麥風清，簷頭索索繰車鳴。", "野蠶作繭人不取，葉間撲撲秋蛾生。", "麥收上場絹在軸，的知輸得官家足。", "不望入口復上身，且免向城賣黃犢。", "回家衣食無厚薄，不見縣門身即樂。"]'),
('acd2442a-816c-4a5b-a0dc-94e0ba485033','去婦','王建','唐','唐诗','tang','','[]','新婦去年腁手足，衣不暇縫蠶廢簇。',64,'全唐诗/poet.tang.15000.json','["新婦去年腁手足，衣不暇縫蠶廢簇。", "白頭使我憂家事，還如夜裏燒殘燭。", "當初爲取傍人語，豈道如今自辛苦。", "在時縱嫌織絹遲，有絲不上鄰家機。"]'),
('67a7c727-1f4b-4950-82a9-80841147949e','神樹詞','王建','唐','唐诗','tang','','[]','我家家西老棠樹，須晴即晴雨即雨。',64,'全唐诗/poet.tang.15000.json','["我家家西老棠樹，須晴即晴雨即雨。", "四時八節上杯盤，願神莫離神處所。", "男不着丁女在舍，官事上下無言語。", "老身長健樹婆娑，萬歲千年作神主。"]'),
('20a724d2-1075-4645-8bbd-7385f675a2dc','祝鵲','王建','唐','唐诗','tang','','[]','神鵲神鵲好言語，行人早回多利賂。',32,'全唐诗/poet.tang.15000.json','["神鵲神鵲好言語，行人早回多利賂。", "我今庭中栽好樹，與汝作巢當報汝。"]'),
('13d28611-fc3c-4b50-af12-d155d9ab5895','古謠','王建','唐','唐诗','tang','','[]','一東一西壠頭水，一聚一散天邊霞。',32,'全唐诗/poet.tang.15000.json','["一東一西壠頭水，一聚一散天邊霞。", "一來一去道上客，一顛一倒池中麻。"]'),
('26a84f32-1349-4ff1-8b61-91d2af5cd47c','公無渡河','王建','唐','唐诗','tang','','[]','渡頭惡天兩岸遠，波濤塞川如疊坂。',90,'全唐诗/poet.tang.15000.json','["渡頭惡天兩岸遠，波濤塞川如疊坂。", "幸無白刃驅向前，何用將身自棄捐。", "蛟龍嚙骨魚食血，黃泥直下無青天。", "男兒縱輕婦人語，惜君性命還須取。", "婦人無力挽斷衣，舟沈身死悔難追。", "公無渡河，公須自爲。"]'),
('aae75655-ec65-44a3-a8b5-71de5dafa5ef','海人謠','王建','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11", "\u751f\u6d3b", "\u4e50\u5e9c", "\u519c\u6c11"]','海人無家海裏住，採珠役象爲歲賦。',32,'全唐诗/poet.tang.15000.json','["海人無家海裏住，採珠役象爲歲賦。", "惡波橫天山塞路，未央宮中常滿庫。"]'),
('2cee87ca-ba60-468f-8569-9e5a69147dee','行見月','王建','唐','唐诗','tang','','[]','月初生，居人見月一月行。',92,'全唐诗/poet.tang.15000.json','["月初生，居人見月一月行。", "行行一年十二月，強半馬上看盈缺。", "百年歡樂能幾何，在家見少行見多。", "不緣衣食相驅遣，此身誰願長奔波。", "篋中有帛倉有粟，豈向天涯走碌碌。", "家人見月望我歸，正是道上思家時。"]'),
('6d8dba87-8e48-42cb-9943-653cd609afe3','七夕曲','王建','唐','唐诗','tang','','["\u4e03\u5915\u60c5\u4eba\u8282", "\u4e03\u5915\u8282", "\u6000\u5ff5"]','河邊獨自看星宿，夜織天絲難接續。',104,'全唐诗/poet.tang.15000.json','["河邊獨自看星宿，夜織天絲難接續。", "拋梭振鑷動明璫，爲有秋期眠不足。", "遙愁今夜河水隔，龍駕車轅鵲填石。", "流蘇翠帳星渚間，環珮無聲燈寂寂。", "兩情纏綿忽如故，復畏秋風生曉路。", "幸回郎意且斯須，一年中別今始初，明星未出少停車。"]'),
('fe6f88c0-13a5-4742-b8c4-6c3b4c8ef8ed','兩頭纖纖','王建','唐','唐诗','tang','','[]','兩頭纖纖青玉玦，半白半黑頭上髮。',32,'全唐诗/poet.tang.15000.json','["兩頭纖纖青玉玦，半白半黑頭上髮。", "偪偪仆仆春冰裂，磊磊落落桃花結。"]'),
('feb3e164-e431-4451-89da-49f5829aeeb7','獨漉歌','王建','唐','唐诗','tang','','["\u9ec4\u6cb3"]','獨獨漉漉，鼠食貓肉。',26,'全唐诗/poet.tang.15000.json','["獨獨漉漉，鼠食貓肉。", "烏日中，鶴露宿，黃河水直人心曲。"]'),
('d47993cd-94d9-468e-93e9-0c3c237e2d8c','寄遠曲','王建','唐','唐诗','tang','','[]','美人別來無處所，巫山月明湘江雨。',48,'全唐诗/poet.tang.15000.json','["美人別來無處所，巫山月明湘江雨。", "千回相見不分明，井底看星夢中語。", "兩心相對尚難知，何況萬里不相疑。"]'),
('ddec6ff9-8dd4-4e9e-8789-009f896a7703','傷韋令孔雀詞','王建','唐','唐诗','tang','','[]','可憐孔雀初得時，美人爲爾別開池。',96,'全唐诗/poet.tang.15000.json','["可憐孔雀初得時，美人爲爾別開池。", "池邊鳳凰作伴侶，羌聲鸚鵡無言語。", "雕籠玉架嫌不棲，夜夜思歸向南舞。", "如今憔悴人見惡，萬里更求新孔雀。", "熱眠雨水飢拾蟲，翠尾盤泥金彩落。", "多時人養不解飛，海山風黑何處歸。"]'),
('69e45825-c9d6-464b-aa58-098c19774d6c','傷鄰家鸚鵡詞','王建','唐','唐诗','tang','','[]','東家小女不惜錢，買得鸚鵡獨自憐。',96,'全唐诗/poet.tang.15000.json','["東家小女不惜錢，買得鸚鵡獨自憐。", "自從死却家中女，無人更共鸚鵡語。", "十日不飲一滴漿，淚漬綠毛頭似鼠。", "舌關啞咽畜哀怨，開籠放飛離人眼。", "短聲亦絕翠臆翻，新墓崔嵬舊巢遠。", "此禽有志女有靈，定爲連理相並生。"]'),
('db2e0bcc-0147-45e2-ad79-3e571534a6b9','春來曲','王建','唐','唐诗','tang','','[]','春欲來，每日望春門早開。',108,'全唐诗/poet.tang.15000.json','["春欲來，每日望春門早開。", "黃衫白馬帶塵土，逢著探春人却回。", "御堤內園曉過急，九衢大宅家家入。", "青帝少女染桃花，露妝初出紅猶濕。", "光風暾暾蝶宛宛，遶樹氣匝枝柯軟。", "可憐寒食街中郎，早起著得單衣裳。", "少年即見春好處，似我白頭無好樹。"]'),
('6fe2a594-673e-4ab3-a897-c11997fedeb7','春去曲','王建','唐','唐诗','tang','','[]','春已去，花亦不知春去處。',60,'全唐诗/poet.tang.15000.json','["春已去，花亦不知春去處。", "緣岡繞澗却歸來，百回看著無花樹。", "就中一夜東風惡，收紅拾紫無遺落。", "老夫不比少年兒，不中數與春別離。"]'),
('08932057-7ef8-459d-8868-5b8b4e9bad85','東征行','王建','唐','唐诗','tang','','[]','桐栢水西賊星落，梟雛夜飛林木惡。',144,'全唐诗/poet.tang.15000.json','["桐栢水西賊星落，梟雛夜飛林木惡。", "相國刻日波濤清，當朝自請東南征。", "舍人爲賓侍郎副，曉覺蓬萊欠珮聲。", "玉階舞蹈謝旌節，生死向前山可穴。", "同時賜馬幷賜衣，御樓看帶弓刀發。", "馬前猛士三百人，金書左右紅旗新。", "司庖常膳皆得對，好事將軍封爾身。", "男兒生殺在手裏，營門老將皆憂死。", "曈曈白日當南山，不立功名終不還。"]'),
('9bf453d9-38b0-44e5-85b9-f556c7785271','荆門行','王建','唐','唐诗','tang','','[]','江邊行人暮悠悠，山頭殊未見荆州。',272,'全唐诗/poet.tang.15000.json','["江邊行人暮悠悠，山頭殊未見荆州。", "峴亭西南路多曲，櫟林深深石鏃鏃。", "看炊紅米煮白魚，夜向雞鳴店家宿。", "南中三月蚊蚋生，黃昏不聞人語聲。", "生紗帷疎薄如霧，隔衣噆膚耳邊鳴。", "欲明不待燈火起，喚得官船過蠻水。", "女兒停客茆屋新，開門掃地桐花裏。", "犬聲撲撲寒溪煙，人家燒竹種山田。", "巴雲欲雨薰石熱，麋鹿度江蟲出穴。", "大蛇過處一山腥，野牛驚跳雙角折。", "斜分漢水橫千山，山青水綠荆門關。", "向前問箇長沙路，舊是屈原沈溺處。", "誰家丹旐已南來，逢著流人從此去。", "月明山鳥多不棲，下枝飛上高枝啼。", "主人念遠心不懌，羅衫臥對章臺夕。", "紅燭交橫各自歸，酒醒還是他鄉客。", "壯年留滯尚思家，況復白頭在天涯。"]'),
('4d3b99f2-568b-4c3c-a7a1-ec13ca148381','鏡聽詞','王建','唐','唐诗','tang','','[]','重重摩挲嫁時鏡，夫壻遠行憑鏡聽。',128,'全唐诗/poet.tang.15000.json','["重重摩挲嫁時鏡，夫壻遠行憑鏡聽。", "回身不遣別人知，人意丁寧鏡神聖。", "懷中收拾雙錦帶，恐畏街頭見驚怪。", "嗟嗟際際下堂階，獨自竈前來跪拜。", "出門願不聞悲哀，郎在任郎回未回。", "月明地上人過盡，好語多同皆道來。", "卷帷上牀喜不定，與郎裁衣失翻正。", "可中三日得相見，重繡錦囊磨鏡面。"]'),
('7617e041-5807-442d-ae0f-591eea74c71d','行宮詞','王建','唐','唐诗','tang','','[]','上陽宮到蓬萊殿，行宮巖巖遙相見。',128,'全唐诗/poet.tang.15000.json','["上陽宮到蓬萊殿，行宮巖巖遙相見。", "向前天子行幸多，馬蹄車轍山川遍。", "當時州縣每年修，皆留內人看玉案。", "禁兵奪得明堂後，長閉桃源與綺繡。", "開元歌舞古草頭，梁州樂人世嫌舊。", "官家乏人作宮戶，不泥宮牆斫宮樹。", "兩邊仗屋半崩摧，夜火入林燒殿柱。", "休封中岳六十年，行宮不見人眼穿。"]'),
('83ebd852-25b4-44fa-a74e-76aba64b063f','羽林行','王建','唐','唐诗','tang','','["\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u5199\u4eba", "\u8bbd\u523a"]','長安惡少出名字，樓下劫商樓上醉。',80,'全唐诗/poet.tang.15000.json','["長安惡少出名字，樓下劫商樓上醉。", "天明下直明光宮，散入五陵松柏中。", "百回殺人身合死，赦書尚有收城功。", "九衢一日消息定，鄉吏籍中重改姓。", "出來依舊屬羽林，立在殿前射飛禽。"]'),
('3cbb6fb5-44cf-463b-bff1-33203d774c71','射虎行','王建','唐','唐诗','tang','','[]','自去射虎得虎歸，官差射虎得虎遲。',80,'全唐诗/poet.tang.15000.json','["自去射虎得虎歸，官差射虎得虎遲。", "獨行以死當虎命，兩人因疑終不定。", "朝朝暮暮空手回，山下綠苗成道徑。", "遠立不敢污箭鏃，聞死還來分虎肉。", "惜留猛虎着深山，射殺恐畏終身閑。"]'),
('49002be8-8bd7-4914-be68-291a13de9735','遠將歸','王建','唐','唐诗','tang','','[]','遠將歸，勝未別離時。',50,'全唐诗/poet.tang.15000.json','["遠將歸，勝未別離時。", "在家相見熱，新歸歡不足。", "去願車輪遲，回思馬蹄速。", "但令在舍相對貧，不向天涯金遶身。"]'),
('1014dab5-7db0-482c-9f61-efcd3f2a7295','尋橦歌','王建','唐','唐诗','tang','','[]','人間百戲皆可學，尋橦不比諸餘樂。',192,'全唐诗/poet.tang.15000.json','["人間百戲皆可學，尋橦不比諸餘樂。", "重梳短髻下金鈿，紅帽青巾各一邊。", "身輕足捷勝男子，繞竿四面爭先緣。", "習多依附攲竿滑，上下蹁躚皆著襪。", "翻身垂頸欲落地，却住把腰初似歇。", "大竿百夫擎不起，褭褭半在青雲裏。", "纖腰女兒不動容，戴行直舞一曲終。", "回頭但覺人眼見，矜難恐畏天無風。", "險中更險何曾失，山鼠懸頭猿挂膝。", "小垂一手當舞盤，斜慘雙蛾看落日。", "斯須改變曲解新，貴欲歡他平地人。", "散時滿面生顏色，行步依前無氣力。"]');
